INSERT INTO DailySummary VALUES('cmrkbrlue0001rwk9crg33a3h','cmrby3y0000001znnofoo0a53','2026-07-14','Asia/Seoul',unistr('## [일일 업무 보고] 추노 _ 2026.07.14 (작성자: 이슈보드 자동 생성)\u000a\u000a### 1. 금일 업무 총평\u000a\u000a* 온보딩(약관 동의·닉네임 설정) 이슈 2건과 방 생성 이슈를 완료 처리했고, 방(경주 세션) 관리·방 목록/입장을 착수해 Room 도메인 개발이 본격화됐다. 정산(Settlement) 도메인과 결과 정산 로직 이슈를 신규 등록하며 경주 후반 흐름까지 범위를 확장했다.\u000a* **핵심 지표**: 완료 3 · 진행 2 · 신규 2 · 전체 이슈 진척률 7/37 (19%)\u000a\u000a### 2. 주요 업무 추진 현황\u000a\u000a| 분류 | 업무 내용 및 수행 결과 | 진척도 |\u000a| :--- | :--- | :---: |\u000a| onboarding | [Onboarding] 약관 동의 화면 및 필수 검증 — 필수/선택 약관 동의 UI와 진입 차단 검증 구현, 완료 처리 | 100% |\u000a| onboarding | [Onboarding] 닉네임·프로필 설정 — 온보딩 닉네임 설정으로 User 프로필 완성, 완료 처리 | 100% |\u000a| room | [Room] 방 생성 — POST /rooms 및 Room.create() 불변식 검증(거리·시간·정원·미래 시작시각·호스트당 1개) 구현, 완료조건 4/4 충족 완료 | 100% |\u000a| room | [Room] 방(경주 세션) 관리 — 방 생성/조회/입장·대기실·자동 마감 범위의 상위 이슈 착수. 완료조건 0/2 — 남은: Room 상태 흐름(recruiting→ready→live→finished) 준수, 하위 이슈 반영 | 0% |\u000a| room | [Room] 방 목록 · 입장 — 참여 가능한 방 목록·입장 처리 착수. 완료조건 0/3 — 남은: 모집 중 방만 입장, 정원 초과 차단·잔여시간 표시, 입장 시 Participant 생성 | 0% |\u000a| room, mobile | [Room] 방 목록 필터 거리·시간 상한 정책 확정 및 반영 — 홈 필터 상한 하드코딩(12km·120분)으로 정책 초과 방이 숨는 문제 정리, 정책 확정 대기 이슈 신규 등록 | 0% |\u000a| auth | [Auth] OAuth 제공자 연동 (카카오·구글·애플) — 우선순위 보통→높음 상향. 완료조건 0/3(미착수) | 0% |\u000a| 이슈 | [Race] 결과 정산 로직 — 경주 결과 정산 이슈 신규 등록 | 0% |\u000a| 기획 | 추노 서비스 기획 v2 수정 | - |\u000a| 도메인 | Settlement(정산) 도메인 신규 정의 | - |\u000a| 도메인 | Room 도메인 수정(경주 세션 생명주기 정비) | - |\u000a| 와이어프레임 | 경주 상세 · 베팅 화면 신규 | - |\u000a| 디자인 | 디자인 시스템 스냅샷 v1.1 확정 | - |\u000a\u000a### 3. 차일 주요 예정 업무\u000a\u000a| 분류 | 예정 업무 내용 | 우선순위 |\u000a| :--- | :--- | :---: |\u000a| room | [Room] 방 목록 · 입장 — 모집 중 방 입장 제한·정원 초과 차단·Participant 생성 이어서 진행 | 높음 |\u000a| room | [Room] 방(경주 세션) 관리 — Room 상태 흐름 준수 및 하위 기능 연동 이어서 진행 | 보통 |\u000a\u000a### 4. 이슈 및 위험 요인\u000a\u000a특이사항 없음\u000a\u000a### 5. 점검 필요\u000a\u000a* [[Onboarding] 약관 동의 화면 및 필수 검증](http://localhost:5173/issues?project=cmrby3y0000001znnofoo0a53&issue=cmrc5yx9u000l1zkpsxusze3a) — done인데 완료조건 0/3\u000a* [[Onboarding] 닉네임·프로필 설정](http://localhost:5173/issues?project=cmrby3y0000001znnofoo0a53&issue=cmrc5z095000n1zkp5l0q57qr) — done인데 완료조건 0/2'),NULL,'ready',NULL,21,'manual',1784013820502,1784017610004);
INSERT INTO DailySummary VALUES('cmrkdor7g0003rw3prd3tfi0l','cmrby3y0000001znnofoo0a53','2026-07-13','Asia/Seoul',unistr('## [일일 업무 보고] 추노 _ 2026.07.13 (작성자: 이슈보드 자동 생성)\u000a\u000a### 1. 금일 업무 총평\u000a\u000a* 경주 세션의 진입점인 "방 생성" 이슈를 완료 조건 4개 전부 충족해 마감했고, 로그인 세션·토큰 관리 이슈에 착수했으나 완료 조건은 아직 반영되지 않았다. 실시간 순위 계산 이슈를 신규 등록하고 서비스 기획 v1을 수정했다.\u000a* **핵심 지표**: 완료 1 · 진행 1 · 신규 1 · 전체 이슈 진척률 7/37 (19%)\u000a\u000a### 2. 주요 업무 추진 현황\u000a\u000a| 분류 | 업무 내용 및 수행 결과 | 진척도 |\u000a| :--- | :--- | :---: |\u000a| room | [Room] 방 생성 — `POST /rooms`로 로그인 사용자를 방장(hostUserId)으로 방을 생성하고 `status=recruiting`으로 초기화. 입력값 검증(거리>0·시간>0·정원≥2), 시작 시각 미래 제약, 호스트당 진행중 방 1개 제한까지 완료 조건 4/4 충족 | 100% |\u000a| auth | [Auth] 로그인 세션·토큰 관리 및 신규/기존 분기 — 착수(in_progress). 완료조건 0/3 — 남은: 토큰 발급·갱신·만료 및 자동 로그인, User.status 기반 진입 분기(onboarding/active), suspended·exited 라우팅 | 0% |\u000a| 이슈 | [Race] 실시간 순위 계산 — 신규 등록 | 0% |\u000a| 기획 | 추노 서비스 기획 v1 수정 | - |\u000a\u000a### 3. 차일 주요 예정 업무\u000a\u000a| 분류 | 예정 업무 내용 | 우선순위 |\u000a| :--- | :--- | :---: |\u000a| auth | [Auth] 로그인 세션·토큰 관리 및 신규/기존 분기 — 완료조건 3건(토큰 처리·진입 분기·상태별 라우팅) 이어서 진행 | 높음 |\u000a\u000a### 4. 이슈 및 위험 요인\u000a\u000a특이사항 없음\u000a\u000a### 5. 점검 필요\u000a\u000a* **[Auth] 로그인 세션·토큰 관리 및 신규/기존 분기**: 활동 로그에는 오늘 in_progress→done으로 기록됐으나 실제 항목은 in_progress·완료조건 0/3 상태다. 상태 변경 로그와 실제 진행도가 불일치하므로 확정 상태 확인 필요.\u000a\u000a---\u000a\u000a참고: 위 보고서는 제공하신 명세 하나로 앱 내부 경로(서버 → claude CLI)와 외부 경로(`/ib-daily`)를 함께 구동하는 **출력 포맷 계약**을 그대로 적용해 생성한 결과입니다. 데이터에 근거가 없는 PR 번호·일정·대응 계획은 규칙대로 생략했고, 활동 로그와 실제 항목 상태의 불일치는 5절에 점검 항목으로 올렸습니다. 포맷을 바꾸려면 이 명세 파일만 수정하시면 됩니다.'),NULL,'ready',NULL,4,'manual',1784017046716,1784017046716);
INSERT INTO DailySummary VALUES('cmrmsg46e002lrwz899n9uykz','cmrby3y0000001znnofoo0a53','2026-07-15','Asia/Seoul',unistr('## [일일 업무 보고] 추노 _ 2026.07.15 (작성자: 이슈보드 자동 생성)\u000a\u000a### 1. 금일 업무 총평\u000a\u000a* 방(Room) 도메인의 핵심 기능 5건을 착수 당일 완료했다 — 대기실 방장 관리(조건 수정·강퇴), 방 이탈(나가기), 방 조건 거리·시간 상·하한 검증, 방 목록 필터 상한 정책 반영, 방 목록 ''참여중'' 표시·입장 분기. 방 조건 검증 작업에서는 기존 `changeSetting`의 0-통과 버그도 함께 수정했다.\u000a* **핵심 지표**: 완료 5 · 진행 0 · 신규 3 · 전체 이슈 진척률 15/67 (22%)\u000a\u000a### 2. 주요 업무 추진 현황\u000a\u000a| 분류 | 업무 내용 및 수행 결과 | 진척도 |\u000a| :--- | :--- | :---: |\u000a| room | [Room] 대기실·방장 관리 — 완주 기준 페이스(제한시간÷목표거리) 표시, 모집 중 방장의 조건 수정·강퇴 구현. 강퇴는 상태 전이 대신 참가자 row 삭제(orphan delete)로 확정, `KICKED` enum 제거(마이그레이션) | 100% |\u000a| room, mobile | [Room] 방 목록 필터 거리·시간 상한 정책 확정(거리 100km·시간 1,440분) 및 홈 필터 상한 반영 — 상한 초과 방이 목록에서 조용히 사라지던 동작 제거 | 100% |\u000a| room, backend, mobile | [Room] 방 조건 거리·시간 상·하한 검증 — core-api 생성·수정 모두에서 거리 100~100,000m·시간 5~1,440분 밖 값 거부, 기존 0-통과 버그 수정, DTO·모바일 클라 검증·km 소수 1자리 일관화 | 100% |\u000a| mobile | [Room] 방 목록 ''참여중'' 표시 및 입장 분기(isJoined) — 참여중 배지 표시, 참여한 방은 ''참가'' 대신 ''입장''(join 미호출)으로 대기실 진입, 미참여 recruiting만 기존 join 유지 | 100% |\u000a| backend, mobile | [Room] 방 이탈(나가기) — `POST /rooms/:id/exit`로 참가자 row 삭제, 방장 exit 시 방 취소(cancelled) 처리, 모바일은 비방장에게만 ''방 나가기'' 노출·이탈 후 목록 갱신 | 100% |\u000a| 기획 | 1차 MVP 기획서 갱신 | - |\u000a| 도메인 | Room·Participant 정의 갱신 (거리 0.1~100km·시간 5~1,440분 범위, 강퇴=참가자 row 삭제 반영) | - |\u000a| 와이어프레임 | 대기실(v9)·방 생성(v4) 갱신 | - |\u000a\u000a### 3. 차일 주요 예정 업무\u000a\u000a예정 업무 없음\u000a\u000a### 4. 이슈 및 위험 요인\u000a\u000a특이사항 없음\u000a\u000a### 5. 점검 필요\u000a\u000a점검 필요 항목 없음'),NULL,'ready',NULL,38,'manual',1784162770213,1784163980829);
INSERT INTO DailySummary VALUES('cmrmswbl7003jrwz8jhfp1bes','cmrby3y0000001znnofoo0a53','2026-07-16','Asia/Seoul',unistr('## [일일 업무 보고] 추노 _ 2026.07.16 (작성자: 이슈보드 자동 생성)\u000a\u000a### 1. 금일 업무 총평\u000a\u000a* 백오피스 1차 착수일로, 기획서 초안을 정리하고 관리자 도메인(Admin)·화면 와이어프레임 9종·백오피스 이슈 7건을 신규 등록해 개발 착수 기반을 마련했다. 코드 구현 착수 전 설계·정의 단계다.\u000a* **핵심 지표**: 완료 0 · 진행 0 · 신규 7 · 전체 이슈 진척률 15/49 (31%)\u000a\u000a### 2. 주요 업무 추진 현황\u000a\u000a| 분류 | 업무 내용 및 수행 결과 | 진척도 |\u000a| :--- | :--- | :---: |\u000a| 기획 | "백오피스 1차 기획서" 신규 작성·수정 (draft) — 개요/목적, 단일 역할(Admin) 유스케이스, MVP 핵심 기능 정의 | - |\u000a| 도메인 | "Admin" 신규 정의 (draft) — User와 분리된 관리자 계정 테이블, 이메일/비밀번호 인증·활성 상태 관리 (id·email·passwordHash·name·status·createdOn) | - |\u000a| 와이어프레임 | 백오피스 화면 9종 신규(html): 관리자 로그인·대시보드·사용자 목록·사용자 상세·방 목록·방 상세·약관 관리·경주 결과 조회·관리자 계정 관리 | - |\u000a| backoffice, auth | "[백오피스] 관리자 인증" 신규 (todo) — Admin 인증 API(`/admins/auth/*`)·가드·로그인 화면. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 운영 대시보드" 신규 (todo) — 핵심 운영 지표 집계 API·KPI 대시보드. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 사용자 관리" 신규 (todo) — 사용자 조회/검색/상세·상태 변경(active/suspended) API·화면. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 방(경주) 관리" 신규 (todo) — 방 모니터링·강제 취소 API·목록/상세 화면. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 약관 관리" 신규 (todo) — 약관 버전 등록·활성화(이전 active→archived) API·화면. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 경주 이력 · 결과 조회" 신규 (todo) — 종료 경주 결과(등수·거리·시간·페이스) 조회 API·화면. 완료조건 0/2 | 0% |\u000a| backoffice | "[백오피스] 관리자 계정 관리" 신규 (todo) — 관리자 추가·비활성/활성 API·화면. 완료조건 0/2 | 0% |\u000a\u000a### 3. 차일 주요 예정 업무\u000a\u000a| 분류 | 예정 업무 내용 | 우선순위 |\u000a| :--- | :--- | :---: |\u000a| backoffice, auth | "[백오피스] 관리자 인증" — Admin 인증 API·가드·로그인 화면 구현 착수 | 높음 |\u000a| backoffice | "[백오피스] 운영 대시보드" — 지표 집계 API·대시보드 화면 | 높음 |\u000a| backoffice | "[백오피스] 사용자 관리" — 사용자 조회·상태 변경 API·화면 | 높음 |\u000a| backoffice | "[백오피스] 방(경주) 관리" — 방 모니터링·강제 취소 API·화면 | 높음 |\u000a| backoffice | "[백오피스] 약관 관리" — 약관 버전 등록·활성화 API·화면 | 높음 |\u000a| backoffice | "[백오피스] 관리자 계정 관리" — 관리자 추가·비활성/