INSERT INTO DailySummary VALUES('cmrn06nem0001rw5suyg1ntpk','cmrby3y0000001znnofoo0a53','2026-07-10','Asia/Seoul',unistr('## [일일 업무 보고] 추노 _ 2026.07.10 (작성자: 이슈보드 자동 생성)\u000a\u000a### 1. 금일 업무 총평\u000a\u000a* 초기 설계 단계로, 핵심 도메인(User·Bet) 정의와 로그인·회원가입 와이어프레임, 온보딩 이슈 등록이 함께 진행되었고 디자인 시스템의 컬러 팔레트가 확정되었다.\u000a* **핵심 지표**: 완료 0 · 진행 0 · 신규 1 · 전체 이슈 진척률 16/67 (24%)\u000a\u000a### 2. 주요 업무 추진 현황\u000a\u000a| 분류 | 업무 내용 및 수행 결과 | 진척도 |\u000a| :--- | :--- | :---: |\u000a| 도메인 | "User(사용자)" 엔티티 신규 정의 | - |\u000a| 도메인 | "Bet(베팅)" 엔티티 신규 정의 | - |\u000a| 와이어프레임 | "로그인 · 회원가입" 화면 신규 작성 | - |\u000a| 이슈 | "[Onboarding] 튜토리얼 화면" 신규 등록 | 0% |\u000a| 디자인 | "디자인 시스템" 컬러 팔레트 확정 (brand main #FF6A3D 등 토큰 스냅샷, 상태 draft) | - |\u000a\u000a### 3. 차일 주요 예정 업무\u000a\u000a예정 업무 없음\u000a\u000a### 4. 이슈 및 위험 요인\u000a\u000a특이사항 없음\u000a\u000a### 5. 점검 필요\u000a\u000a점검 필요 항목 없음'),NULL,'ready',NULL,5,'manual',1784175765502,1784175765502);
INSERT INTO Issue VALUES('cmrc5xz6b000b1zkpqyae6533','cmrby3y0000001znnofoo0a53','[Auth] 소셜 로그인',unistr('카카오/구글/애플 소셜 로그인으로 가입·로그인한다. (자체 이메일 가입 없음)\u000a\u000a## 범위\u000a- 카카오 / 구글 / 애플 OAuth 연동\u000a- 신규/기존 사용자 판별 (User.provider + providerUserId)\u000a- 로그인 세션/토큰 관리, 자동 로그인\u000a\u000a## 완료 조건\u000a- [ ] 세 제공자로 각각 로그인 성공 → 인증 완료\u000a- [ ] 최초 사용자는 온보딩으로, 기존 사용자는 홈으로 분기\u000a- [ ] iOS에서 Sign in with Apple 병행 제공(심사 요건)\u000a\u000a관련 화면: login / 관련 도메인: User'),'epic','todo','high','high','medium','["auth"]',NULL,'cmrby4wah00021znnga9fbhfq','login','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',17,1783520310612,1784186642970,'CH-1',1);
INSERT INTO Issue VALUES('cmrc5y54o000d1zkp8hyykjkb','cmrby3y0000001znnofoo0a53','[Onboarding] 최초 온보딩 · 약관 동의',unistr('최초 로그인(회원가입) 시 약관 동의와 프로필(닉네임) 설정을 마쳐야 서비스에 진입한다.\u000a\u000a## 범위\u000a- 필수 약관(서비스 이용약관·개인정보 수집·이용·위치기반서비스) + 선택 약관(마케팅) 동의\u000a- 닉네임 설정\u000a- 동의 이력 저장, 약관 버전 관리·개정 재동의\u000a\u000a## 완료 조건\u000a- [ ] 필수 약관 미동의 또는 닉네임 미입력 시 진입 차단\u000a- [ ] 온보딩 완료 시 동의 이력(UserConsent) 저장 후 홈 진입\u000a- [ ] 재로그인 시 온보딩 스킵, 필수 약관 개정 시 변경분 재동의\u000a\u000a관련 화면: onboarding / 관련 도메인: Agreement, UserConsent, User'),'epic','in_progress','medium','medium','medium','["onboarding","auth"]',NULL,'cmrby4wah00021znnga9fbhfq','onboarding','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk30001rwgnoiejp8hz',11,1783520318328,1784172194829,'CH-2',2);
INSERT INTO Issue VALUES('cmrc5y7mw000f1zkpe26zkowk','cmrby3y0000001znnofoo0a53','[Room] 방(경주 세션) 관리',unistr('경주 세션인 방을 생성·조회·입장하고, 대기실에서 방장 관리와 자동 모집 마감/취소를 처리한다.\u000a\u000a## 범위\u000a- 방 생성 (목표 거리·제한 시간·시작 시간·최대 인원)\u000a- 방 목록/입장 (모집 중만 입장, 지각 입장 없음)\u000a- 대기실: 참가자 목록·카운트다운·완주 기준 페이스, 방장 조건 수정·강퇴\u000a- 자동 모집 마감(시작 10분 전)·2명 미만 시 자동 취소\u000a\u000a## 완료 조건\u000a- [ ] Room 상태 흐름(recruiting→ready→live→finished, ready→canceled) 준수\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a관련 도메인: Room'),'epic','in_progress','medium','high','high','["room"]',NULL,'cmrby4wah00021znnga9fbhfq',NULL,'cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',3,1783520321576,1784172194830,'CH-3',3);
INSERT INTO Issue VALUES('cmrc5ys21000h1zkpe8natml1','cmrby3y0000001znnofoo0a53','[Auth] OAuth 제공자 연동 (카카오·구글·애플)',unistr('각 소셜 제공자 OAuth 플로우를 연동하고 콜백에서 User를 조회/생성한다.\u000a\u000a## 완료 조건\u000a- [ ] 카카오·구글·애플 각각 인증 성공 후 provider·providerUserId로 User upsert\u000a- [ ] UQ(provider, providerUserId) 위반 없이 기존 계정 재사용\u000a- [ ] 애플: Sign in with Apple(iOS 필수)'),'task','todo','high','high','medium','["auth"]','cmrc5xz6b000b1zkpqyae6533','cmrby4wah00021znnga9fbhfq','login','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',12,1783520348041,1784172194831,'CH-4',4);
INSERT INTO Issue VALUES('cmrc5ytlo000j1zkpjku9hvg9','cmrby3y0000001znnofoo0a53','[Auth] 로그인 세션·토큰 관리 및 신규/기존 분기',unistr('로그인 성공 후 세션/토큰을 발급·유지하고 자동 로그인을 지원한다. User.status로 진입 화면을 분기한다.\u000a\u000a## 완료 조건\u000a- [ ] 토큰 발급·갱신·만료 처리, 앱 재실행 시 자동 로그인\u000a- [ ] 진입 분기 기준 = User.status: onboarding → 온보딩 화면(이어서 진행), active → 홈\u000a- [ ] suspended → 이용 정지 안내, exited → 복귀 처리 흐름으로 라우팅(상세는 운영 정책 확정 후)\u000a\u000a관련 도메인: User(status)'),'task','in_progress','high','high','medium','["auth"]','cmrc5xz6b000b1zkpqyae6533','cmrby4wah00021znnga9fbhfq',NULL,'cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',4,1783520350044,1784172194832,'CH-5',5);
INSERT INTO Issue VALUES('cmrc5yx9u000l1zkpsxusze3a','cmrby3y0000001znnofoo0a53','[Onboarding] 약관 동의 화면 및 필수 검증',unistr('필수/선택 약관 동의 UI와 진입 차단 검증을 구현한다.\u000a\u000a## 완료 조건\u000a- [ ] 전체 동의 토글, 개별 약관 보기(본문)\u000a- [ ] 필수 약관(서비스·개인정보·위치기반) 미동의 시 진행 차단\u000a- [ ] 선택 약관(마케팅)은 미동의로 진행 가능'),'task','done','high','medium','low','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','onboarding','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk30001rwgnoiejp8hz',6,1783520354803,1784172194832,'CH-6',6);
INSERT INTO Issue VALUES('cmrc5z095000n1zkp5l0q57qr','cmrby3y0000001znnofoo0a53','[Onboarding] 닉네임·프로필 설정',unistr('온보딩에서 닉네임을 설정해 User 프로필을 완성한다.\u000a\u000a## 완료 조건\u000a- [ ] 닉네임 입력 필수, 미입력 시 진행 차단\u000a- [ ] 저장 시 User.nickname 반영'),'task','done','high','medium','low','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','onboarding','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',3,1783520358666,1784172194833,'CH-7',7);
INSERT INTO Issue VALUES('cmrc5z30s000p1zkpaopnjrn4','cmrby3y0000001znnofoo0a53','[Onboarding] 동의 이력 저장 (UserConsent)',unistr('사용자가 동의/미동의한 약관(버전)을 UserConsent로 기록한다.\u000a\u000a## 완료 조건\u000a- [ ] 약관별 isAgreed·consentedOn 저장, UQ(userId, agreementId) 준수\u000a- [ ] 감사·분쟁 대비로 이력 보존'),'task','done','medium','low','low','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq',NULL,'cmrc4i7x7000x1z18dy48lysi','cmrmtwkk30001rwgnoiejp8hz',4,1783520362252,1784172194834,'CH-8',8);
INSERT INTO Issue VALUES('cmrc5z60n000r1zkp8qtb397i','cmrby3y0000001znnofoo0a53','[Onboarding] 약관 버전 관리 및 개정 재동의',unistr('약관을 버전 단위로 관리하고, 필수 약관 개정 시 기존 사용자에게 변경분 재동의를 요구한다.\u000a\u000a## 완료 조건\u000a- [ ] Agreement 상태 흐름(pending→active→archived) 및 타입당 active 1개 불변식 준수\u000a- [ ] 재로그인 시 미동의 상태인 최신 필수 약관이 있으면 재동의 화면 노출'),'task','todo','low','low','medium','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','profile','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk30001rwgnoiejp8hz',3,1783520366136,1784172194835,'CH-9',9);
INSERT INTO Issue VALUES('cmrc5zc6b000t1zkpvlwyvx9w','cmrby3y0000001znnofoo0a53','[Room] 방 생성',unistr('## 배경\u000a경주 세션인 "방"을 개설하는 최초 진입점. 방장이 목표 거리·제한 시간·시작 시각·정원을 설정해 방을 만든다. 와이어프레임 `room-create` 화면, Room 도메인(status 생명주기의 시작점 recruiting)에 해당한다.\u000a\u000a## 작업 내용\u000a- `POST /rooms` (UserGuard) — 로그인 사용자를 방장(hostUserId)으로 방 생성\u000a- Request DTO(`GeneralRoomCreateDto`): `title`(필수)·`goalDistanceMeter`·`goalLimitMinutes`·`startOn`·`capacity`(≥2)\u000a- 도메인 팩토리 `Room.create()`에서 불변식 검증 후 `status=recruiting`으로 생성\u000a- 진행중(recruiting/ready/live) 방을 이미 가진 호스트는 중복 개설 차단\u000a- 저장은 `RoomRepository.save()` (`@Transactional`)\u000a\u000a## 완료 조건\u000a- [x] 방 생성 시 status=recruiting, hostUserId=생성자(로그인 사용자)로 설정된다\u000a- [x] 입력값 검증(거리>0, 시간>0, 정원>=2)\u000a- [x] 시작 시각은 현재보다 미래여야 한다\u000a- [x] 호스트당 진행중인 방 1개만 허용\u000a\u000a## 관련 기획\u000a1차 MVP 기획서 "방(경주 세션) 관리" — 방 생성. 와이어프레임 `room-create`. 관련 도메인: Room(status=recruiting 진입).'),'task','done','high','high','medium','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','room-create','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',7,1783520374116,1784172194835,'CH-10',10);
INSERT INTO Issue VALUES('cmrc5zeav000v1zkpaxqklbxf','cmrby3y0000001znnofoo0a53','[Room] 방 목록 · 입장',unistr('참여 가능한 방을 목록으로 보여주고 입장을 처리한다.\u000a\u000a## 완료 조건\u000a- [x] 모집 중(recruiting) 방에만 입장 가능, 지각 입장 없음\u000a- [x] 정원 초과 입장 차단, 모집 중 방에 시작까지 남은 시간 표시(1시간 초과=시간, 이내=분)\u000a- [x] 입장 시 Participant 생성(status=joined)\u000a\u000a> 입장은 `POST /rooms/:id/join`(서버가 모집중·정원·중복 검증)으로 처리하고, 모바일 홈 ''참가'' 버튼에 연동(성공 시 대기실 진입, 실패 시 서버 메시지 SnackBar). 시작까지 남은 시간은 홈 카드에 표시.'),'task','done','high','high','medium','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','home','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',7,1783520376871,1784172194836,'CH-11',11);
INSERT INTO Issue VALUES('cmrc5zgsk000x1zkpv5st1x6l','cmrby3y0000001znnofoo0a53','[Room] 대기실 · 방장 관리',unistr('대기실에서 참가자 목록·카운트다운·완주 기준 페이스를 보여주고, 방장이 조건 수정·강퇴를 수행한다.\u000a\u000a## 완료 조건\u000a- [x] 완주 기준 페이스 = 제한시간 ÷ 목표거리 표시\u000a- [x] 모집 중에만 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능\u000a- [x] 강퇴 시 해당 Participant 제거(관계 orphan delete로 row 삭제)\u000a\u000a> 참고(2026-07-15): 강퇴는 상태 전이(status=kicked)가 아니라 참가자 row를 삭제(orphan delete)하는 방식으로 확정. `ParticipantStatus.KICKED` enum은 도메인·DB에서 제거(마이그레이션 `RemoveParticipantKickedStatus`). 모집(recruiting) 단계 이탈/강퇴는 보존할 이력이 없어 삭제로 통일(exit와 동일).\u000a> 진행(2026-07-15): 강퇴 mobile 연동 완료(대기실 강퇴 → POST /rooms/:id/participants/:participantId/kick → orphan delete, flutter test 통과). 방 조건 수정 완료: core-api `PUT /rooms/:id`(changeSetting, 방장·모집중·정원≥2·정원≥현재인원·거리>0·시간>0 검증) + mobile 편집 시트 ''적용'' 연동(km→m 변환·diff 전송·성공 시 상세 새로고침, flutter test 10/10). ② 두 축(수정·강퇴) 모두 완료.\u000a\u000a## 알려진 후속\u000a- [미해결] core-api `Room.changeSetting`: `goalDistanceMeter`/`goalLimitMinutes`가 **0이면 검증을 통과**하는 버그(`args.x && args.x <= 0` 단락). mobile 클라 검증(>0)이 막고 있으나 서버 방어 필요(`!== undefined` 가드 + DTO `@Min(1)`).\u000a- [해결 2026-07-15] 강퇴 경로 `:participantId` 정합화 — 도메인을 participant.id 비교로 변경(core-api) + mobile이 pl.id 전송. 경로명과 실제 식별자 일치.\u000a- [해결 2026-07-15] 방장 ''방 삭제'' 서버 연동 — core-api `DELETE /rooms/:id/cancel`(기존) + mobile `RoomApi.cancel()`/`_confirmDelete` 연동(성공 시 홈 복귀), `ApiClient.delete()` 추가. flutter analyze 무이슈·test 11개 통과.'),'task','done','high','high','medium','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','waiting-room','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',9,1783520380100,1784172194837,'CH-12',12);
INSERT INTO Issue VALUES('cmrc5zii9000z1zkpsve8xueh','cmrby3y0000001znnofoo0a53','[Room] 자동 모집 마감 · 취소',unistr('시작 시간 기준으로 방 상태를 자동 전이한다.\u000a\u000a## 완료 조건\u000a- [ ] 시작 10분 전 recruiting→ready(입장 차단)\u000a- [ ] ready 진입 시 참가자 2명 미만이면 canceled로 전이 + 참가자 취소 안내\u000a- [ ] 시작 시간 도달 시 ready→live'),'task','todo','medium','medium','medium','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','race-cancelled','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',6,1783520382321,1784172194837,'CH-13',13);
INSERT INTO Issue VALUES('cmrcsoze60007rwt4brdpphoa','cmrby3y0000001znnofoo0a53','[Race] 실시간 GPS 러닝',unistr('경주 중 기기 GPS로 이동 거리를 계산하고 WebSocket으로 실시간 공유한다. 서버 시각 기준으로 동시에 출발/종료하며, 판정은 서버 릴레이(클라이언트 계산값 신뢰) 모델을 따른다.\u000a\u000a## 범위\u000a- 위치 권한 확보(백그라운드 포함), 거부 시 앱 사용 불가 처리\u000a- GPS 이동 거리 누적 계산(클라이언트) 및 진행 상태 산출\u000a- WebSocket 진행(거리/페이스) 송수신\u000a- 백그라운드 위치 추적 유지\u000a- 네트워크 단절 시 재연결·거리 재동기화\u000a- 서버 시각 기준 start/ends 신호 수신·카운트다운\u000a\u000a## 완료 조건\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a- [ ] 원시 GPS 좌표는 보존하지 않음(TrackPoint 미도입), 진행값은 Participant.currentDistance로만 전송\u000a\u000a관련 도메인: Participant / 관련 화면: race'),'epic','todo','medium','high','high','["race","gps"]',NULL,'cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558522159,1784172194838,'CH-14',14);
INSERT INTO Issue VALUES('cmrcsp3f60009rwt4t8f82mgv','cmrby3y0000001znnofoo0a53','[Race] 실시간 리더보드',unistr('경주 중 참가자들의 거리 기준 순위·페이스를 실시간으로 계산해 리더보드로 표시한다. 동기화 지연 목표 3초 이내.\u000a\u000a## 범위\u000a- 참가자 진행값(Participant.currentDistance) 기준 실시간 순위 계산 — 순위는 휘발성이라 별도 컬럼에 저장하지 않고 브로드캐스트로만 전달\u000a- 리더보드 UI(선두·본인 강조)와 내 진행 패널(거리/목표 대비 진행률/페이스/현재 순위)\u000a- 재접속 시 최신 리더보드 스냅샷 재수신\u000a\u000a## 완료 조건\u000a- [ ] 타 참가자 진행이 3초 이내로 리더보드에 반영\u000a- [ ] 순위가 거리 기준으로 정확히 정렬\u000a\u000a관련 도메인: Participant / 관련 화면: race'),'epic','todo','medium','high','high','["race","realtime"]',NULL,'cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',3,1783558527378,1784172194840,'CH-15',15);
INSERT INTO Issue VALUES('cmrcsp8yz000brwt4qo6q9f0d','cmrby3y0000001znnofoo0a53','[Race] 등수 판정',unistr('목표 도달 순서로 등수를 확정하고, 제한 시간 만료·이탈을 처리해 최종 순위를 낸다. 판정은 클라이언트가 보낸 도달 이벤트의 서버 도착 순서로 확정한다(재계산 없음).\u000a\u000a## 범위\u000a- 목표 거리 도달 순서로 등수 확정, 동시 도달 시 공동 순위\u000a- 제한 시간 만료 종료 처리\u000a- 미완주·중도 이탈·앱 강제 종료 = dnf → 완주자 뒤 누적 거리순 정렬\u000a- Participant.finalRank·status 확정, Room→finished 전이\u000a\u000a## 완료 조건\u000a- [ ] 도달 순 등수·공동 순위 정확\u000a- [ ] 완주자 뒤 미완주자 누적 거리순 정렬\u000a- [ ] 종료 시 Room 상태 finished로 전이\u000a\u000a관련 도메인: Participant·Room / 관련 화면: result'),'epic','todo','medium','high','high','["race","ranking"]',NULL,'cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558534571,1784172194840,'CH-16',16);
INSERT INTO Issue VALUES('cmrcspa1u000drwt4wyxzkl2g','cmrby3y0000001znnofoo0a53','[Race] 결과 & 경주 이력',unistr('경주 종료 후 결과를 집계해 결과 화면으로 보여주고, 사용자별 경주 이력에서 지난 결과를 조회한다.\u000a\u000a## 범위\u000a- 경주 결과 집계(최종 순위·개인 기록: 거리/시간/페이스) 및 결과 화면\u000a- 사용자별 경주 이력 목록·상세 조회\u000a- 시간·페이스는 Room.startOn/finishedOn·Participant 값에서 파생\u000a\u000a## 완료 조건\u000a- [ ] 결과 화면에 최종 순위·내 기록 표시\u000a- [ ] 경주 이력에서 지난 경주의 등수·거리·시간·페이스 확인\u000a\u000a관련 도메인: Participant·Room / 관련 화면: result·history'),'epic','todo','medium','medium','medium','["race","history"]',NULL,'cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558535971,1784172194841,'CH-17',17);
INSERT INTO Issue VALUES('cmrcspsq9000frwt4k47e97a8','cmrby3y0000001znnofoo0a53','[Race] 위치 권한 확보 · 거부 시 앱 사용 불가',unistr('위치 권한(백그라운드 포함)을 요청하고, 거부 시 앱 사용 불가 안내 화면으로 차단한다.\u000a\u000a## 완료 조건\u000a- [ ] 권한 허용 시 정상 진입, 거부/미허용 시 안내 화면 노출\u000a- [ ] 설정 이동·재확인 흐름 제공 (시나리오 #15)'),'task','todo','high','high','low','["race","gps"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','location-denied',NULL,'cmrmtwkk30001rwgnoiejp8hz',2,1783558560177,1784172194841,'CH-18',18);
INSERT INTO Issue VALUES('cmrcspwqn000hrwt45qgzhpy0','cmrby3y0000001znnofoo0a53','[Race] GPS 이동 거리 계산 · 진행 상태 산출',unistr('기기 GPS 스트림으로 이동 거리를 누적 계산하고 페이스·목표 대비 진행률을 산출한다.\u000a\u000a## 완료 조건\u000a- [ ] 실사용 러닝에서 신뢰 가능한 누적 거리·페이스 산출 (오차 ±5% 목표)\u000a- [ ] 목표 도달 판정(클라이언트) 및 도달 이벤트 생성'),'task','todo','medium','high','high','["race","gps"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558565375,1784172194842,'CH-19',19);
INSERT INTO Issue VALUES('cmrcsq3eq000jrwt4006g31zw','cmrby3y0000001znnofoo0a53','[Race] WebSocket 진행 송수신 채널',unistr('경주 세션 WebSocket 채널로 내 진행값(거리/페이스)을 주기 송신하고, 타 참가자 진행을 수신한다. 서버는 재계산 없이 릴레이·순서 확정.\u000a\u000a## 완료 조건\u000a- [ ] 진행 송신 및 브로드캐스트 수신 동작, 지연 3초 이내\u000a- [ ] Participant.currentDistance 갱신 반영'),'task','todo','medium','high','high','["race","realtime"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558574018,1784172194842,'CH-20',20);
INSERT INTO Issue VALUES('cmrcsq5wh000lrwt41asy9c67','cmrby3y0000001znnofoo0a53','[Race] 백그라운드 위치 추적 유지',unistr('화면이 꺼지거나 앱이 백그라운드여도 GPS 추적과 진행 송신이 끊기지 않게 한다. (앱 강제 종료 후 복귀는 MVP 범위 밖)\u000a\u000a## 완료 조건\u000a- [ ] 백그라운드/화면 꺼짐 상태에서 추적·송신 지속 (iOS/Android)\u000a- [ ] 배터리 소모 실사용 가능 수준'),'task','todo','medium','high','high','["race","mobile"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race',NULL,'cmrmtwkk30001rwgnoiejp8hz',2,1783558577249,1784172194843,'CH-21',21);
INSERT INTO Issue VALUES('cmrcsq7j0000nrwt4kj5ufzmj','cmrby3y0000001znnofoo0a53','[Race] 네트워크 단절 재연결 · 거리 재동기화',unistr('러닝 중 네트워크 단절 시 WebSocket 재연결하고, 클라이언트가 보유한 현재 누적 거리를 재전송해 서버 상태를 복구한다.\u000a\u000a## 완료 조건\u000a- [ ] 단절 후 재연결 시 진행 유실 없이 서버 반영\u000a- [ ] 재연결 시 최신 리더보드 스냅샷 재수신'),'task','todo','low','medium','high','["race","reliability"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558579356,1784172194843,'CH-22',22);
INSERT INTO Issue VALUES('cmrcsqdt8000prwt422byd542','cmrby3y0000001znnofoo0a53','[Race] 서버 시각 기준 start/ends 신호 · 카운트다운',unistr('예약 startOn 기준으로 서버가 "start at T / ends at T+limit" 신호를 브로드캐스트하고, 클라이언트는 서버 시각 오프셋으로 카운트다운·동시 출발/종료한다.\u000a\u000a## 완료 조건\u000a- [ ] 참가자 전원 동시 출발(시계 오차 보정)\u000a- [ ] ends 도달 시 클라이언트 종료 처리 (시나리오 #10)'),'task','todo','high','high','medium','["race","realtime"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',2,1783558587500,1784172194844,'CH-23',23);
INSERT INTO Issue VALUES('cmrcsqhcg000rrwt4y4ee9zn9','cmrby3y0000001znnofoo0a53','[Race] 거리 기준 실시간 순위 계산',unistr('수신한 참가자 진행값(Participant.currentDistance)을 기준으로 실시간 순위를 계산해 리더보드로 브로드캐스트한다. 순위는 휘발성 값이라 별도 컬럼(currentRank 등)에 저장하지 않는다.\u000a\u000a## 완료 조건\u000a- [ ] 거리 내림차순 순위 정확, 동률 처리\u000a- [ ] 진행 갱신마다 순위 재계산'),'task','todo','high','high','medium','["race","realtime"]','cmrcsp3f60009rwt4t8f82mgv','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',3,1783558592081,1784172194844,'CH-24',24);
INSERT INTO Issue VALUES('cmrcsqihx000trwt4234ydxgm','cmrby3y0000001znnofoo0a53','[Race] 리더보드 · 내 진행 UI',unistr('리더보드(선두·본인 강조)와 내 진행 패널(거리/목표 대비 진행률/페이스/현재 순위)을 실시간 렌더한다.\u000a\u000a## 완료 조건\u000a- [ ] 내 진행/리더보드가 실시간 갱신 (시나리오 #11)\u000a- [ ] 재접속 시 즉시 복구'),'task','todo','high','high','medium','["race","ui"]','cmrcsp3f60009rwt4t8f82mgv','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558593574,1784172194845,'CH-25',25);
INSERT INTO Issue VALUES('cmrcsqjsi000vrwt44gdi67jv','cmrby3y0000001znnofoo0a53','[Race] 목표 도달 순 확정 · 공동 순위',unistr('완주자의 목표 도달 이벤트를 서버 도착 순서로 등수 확정하고, 동시 도달은 공동 순위로 처리한다.\u000a\u000a## 완료 조건\u000a- [ ] 도달 순 등수 확정, 동시 도달 공동 순위 (시나리오 #12)\u000a- [ ] 완주자 finalRank·status(finished) 확정'),'task','todo','high','high','medium','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558595250,1784172194846,'CH-26',26);
INSERT INTO Issue VALUES('cmrcsqph9000xrwt4dbnjlgw9','cmrby3y0000001znnofoo0a53','[Race] 제한 시간 만료 종료 · 이탈/강제종료 dnf 처리',unistr('제한 시간 만료 시 경주를 종료하고, 미완주·중도 이탈·앱 강제 종료 참가자는 dnf로 처리해 완주자 뒤 누적 거리순으로 정렬한다.\u000a\u000a## 완료 조건\u000a- [ ] 제한 시간 만료 종료 트리거\u000a- [ ] dnf 참가자 누적 거리순 정렬 (시나리오 #13)'),'task','todo','high','high','medium','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558602621,1784172194846,'CH-27',27);
INSERT INTO Issue VALUES('cmrcsqxgk000zrwt4eif2nahz','cmrby3y0000001znnofoo0a53','[Race] 최종 순위 확정 · Room finished 전이',unistr('완주자·dnf를 합쳐 최종 순위를 확정하고 Room 상태를 finished로 전이하며 finishedOn을 기록한다.\u000a\u000a## 완료 조건\u000a- [ ] 전체 참가자 finalRank 확정\u000a- [ ] Room.status=finished, finishedOn 기록'),'task','todo','high','high','medium','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',2,1783558612964,1784172194846,'CH-28',28);
INSERT INTO Issue VALUES('cmrcsr1c60011rwt4alblsjk4','cmrby3y0000001znnofoo0a53','[Race] 경주 결과 집계 · 결과 화면',unistr('종료된 경주의 최종 순위와 개인 기록(거리/시간/페이스)을 집계해 결과 화면으로 보여준다.\u000a\u000a## 완료 조건\u000a- [ ] 결과 화면에 최종 순위·내 기록 표시 (시나리오 #14)\u000a- [ ] 시간/페이스는 Room·Participant 값에서 파생'),'task','todo','medium','medium','medium','["race","result"]','cmrcspa1u000drwt4wyxzkl2g','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558617990,1784172194847,'CH-29',29);
INSERT INTO Issue VALUES('cmrcsr5a80013rwt43bsuy2ot','cmrby3y0000001znnofoo0a53','[Race] 사용자별 경주 이력 조회',unistr('사용자가 참여했던 지난 경주들을 이력 목록·상세로 조회한다.\u000a\u000a## 완료 조건\u000a- [ ] 이력 목록에서 지난 경주의 등수·거리·시간·페이스 확인\u000a- [ ] Participant·Room 조인으로 사용자별 조회'),'task','todo','medium','low','low','["race","history"]','cmrcspa1u000drwt4wyxzkl2g','cmrby4wah00021znnga9fbhfq','history','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',2,1783558623104,1784172194847,'CH-30',30);
INSERT INTO Issue VALUES('cmrij834q000brwgdtsk4qon7','cmrby3y0000001znnofoo0a53','[Onboarding] 계정 선-생성 & 온보딩 재개 (User.status)',unistr('## 배경\u000a로그인과 온보딩을 분리한다. 첫 로그인 시점에 User를 먼저 생성하고(status=onboarding, nickname null 허용), 온보딩(닉네임+필수약관)을 마치면 status=active로 전이한다. 온보딩을 중간에 그만둬도 계정은 이미 존재하므로, 재로그인 시 새 계정을 만들지 않고 기존 계정을 찾아 온보딩을 이어서 진행한다.\u000a\u000a## 작업 내용\u000a- 첫 로그인 콜백에서 providerKey(UQ(provider,providerUserId))로 조회 → 없으면 User 생성(status=onboarding, nickname=null)\u000a- 로그인 후 진입 분기: status=onboarding → 온보딩 화면, status=active → 홈\u000a- 온보딩 완료 처리: 닉네임 저장 + 필수 약관 동의(UserConsent) 완료를 원자적으로 검증한 뒤 status=onboarding→active 전이\u000a- 온보딩 미완료 재로그인 시 기존 User 재사용(중복 생성 방지) 및 마지막 단계부터 재개\u000a- (모델링만) status 전이 active↔suspended, active↔exited 경로 존재 인지 — 실제 트리거는 운영 정책에서 확정(범위 밖)\u000a\u000a## 완료 조건\u000a- [x] 첫 로그인 시 User가 status=onboarding으로 생성된다\u000a- [x] 온보딩 미완료 상태로 종료 후 재로그인하면 계정이 중복 생성되지 않고 기존 계정(status=onboarding)으로 매칭된다 (시나리오 #5)\u000a- [x] 닉네임+필수약관을 모두 마치면 status=active로 전이되고 홈에 진입한다 (시나리오 #2)\u000a- [x] status=active 사용자는 재로그인 시 온보딩을 건너뛴다 (시나리오 #4)\u000a\u000a> 참고: 현재는 dev 로그인(POST /auth/dev/login) 경로 기준으로 충족. 실 소셜 OAuth 연동은 [Auth] 이슈에서 이어진다.\u000a\u000a## 관련 기획\u000a1차 MVP 기획서 §3 온보딩 & 약관 동의, §8 확정(온보딩 계정 생명주기), 진행 메모(2026-07-13). 관련 도메인: User(status 생명주기)'),'task','done','low','low','medium','["onboarding","auth"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','onboarding','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',8,1783905414363,1784172194848,'CH-31',31);
INSERT INTO Issue VALUES('cmriysef7000drwgd8xaconsl','cmrby3y0000001znnofoo0a53','[Profile] 내 정보(프로필)',unistr('## 배경\u000a온보딩을 마친 사용자가 하단 탭 "내 정보"에서 자신의 프로필(닉네임·가입 정보), 러닝 통계, 설정(약관·연결 계정 등)을 보고 관리한다. 와이어프레임 `profile` 화면에 해당하며, 기존에 이슈가 없어 보강한다.\u000a\u000a## 작업 내용\u000a- 프로필 헤더(아바타·닉네임·가입 정보) + 러닝 통계 + 설정 목록 + 로그아웃으로 구성된 화면\u000a- 현재 사용자 조회 API 연동(GET /users/me)\u000a- 세부는 하위 이슈 참조\u000a\u000a## 완료 조건\u000a- [ ] 내 정보 화면에서 닉네임·가입 정보·러닝 통계·설정이 표시된다 (닉네임·연결 계정은 실데이터, 가입일·러닝 통계는 아직 목업)\u000a- [x] 닉네임 수정, 로그아웃이 동작한다\u000a- [ ] 약관·개인정보 재동의는 기존 [Onboarding] 약관 버전 관리·재동의 이슈와 연결된다 (재동의 흐름 미구현)\u000a\u000a## 관련 기획\u000a1차 MVP 기획서(온보딩 이후 사용자 관리), 와이어프레임 `profile`. 러닝 통계는 [Race] 경주 이력, 재동의는 [Onboarding] 약관 버전 관리·재동의와 연계.\u000a\u000a> 참고(2차 이관): 프로필 사진 변경(미디어 스토리지 필요), 경주 알림 토글(푸시)은 1차 범위 밖 — 2차에서 다룬다.'),'epic','in_progress','high','medium','low','["profile"]',NULL,'cmrby4wah00021znnga9fbhfq','profile','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',6,1783931556354,1784172194848,'CH-32',32);
INSERT INTO Issue VALUES('cmriysvqq000frwgdx93hqeh5','cmrby3y0000001znnofoo0a53','[Profile] 내 정보 조회 (GET /auth/me 재사용) · 화면',unistr('## 배경\u000a내 정보 화면이 현재 사용자의 프로필·설정을 표시하려면 서버에서 사용자 정보를 조회해야 한다. 별도 `GET /users/me`를 새로 만들지 않고 **기존 `GET /auth/me`를 재사용**한다.\u000a\u000a## 작업 내용\u000a- `GET /auth/me`(UserGuard) 재사용 — 닉네임·provider(연결 계정)·status·프로필이미지·**가입일(createdAt)** 을 `MeDto`로 반환. **별도 `createdOn` 필드 없이 공통 감사 컬럼 `createdAt`을 가입일로 사용.**\u000a- mobile: 내 정보 화면이 이 응답으로 헤더(닉네임·연결 계정·가입일)를 실데이터로 렌더.\u000a\u000a## 완료 조건\u000a- [x] `GET /auth/me`가 현재 사용자의 닉네임·provider·status·가입일(createdAt)을 반환한다 (provider 추가 완료 · 가입일=createdAt은 ResponseDto 상속으로 이미 포함)\u000a- [x] mobile 내 정보 화면이 실데이터로 렌더된다 (닉네임·연결 계정·가입일 실데이터, 러닝 통계는 별도 이슈로 목업 유지)\u000a- [x] 미인증(토큰 없음/만료) 시 401 (UserGuard)\u000a\u000a## 관련 기획\u000a와이어프레임 `profile` 헤더·설정. 관련 도메인: User(가입일 = 공통 `createdAt`).\u000a\u000a> 진행(2026-07-16): 설계 확정 — 신규 `/users/me` 대신 **`/auth/me` 재사용**, `createdOn` 필드 미도입(가입일 = 공통 `createdAt`). core-api: `MeDto`에 provider 추가(가입일 createdAt은 `ResponseDto` 상속으로 이미 반환), typecheck 0 에러. mobile: `me()` provider 실파싱 + `AuthUser.createdAt` 추가로 프로필에 provider·가입일 실데이터 렌더, flutter analyze 무이슈·test 16/16. 도메인 문서(User) createdOn→createdAt 정리.'),'task','done','high','medium','low','["profile","backend"]','cmriysef7000drwgd8xaconsl','cmrby4wah00021znnga9fbhfq','profile','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',7,1783931578802,1784172194849,'CH-33',33);
INSERT INTO Issue VALUES('cmriyt1jo000hrwgdi1oepjey','cmrby3y0000001znnofoo0a53','[Profile] 닉네임 수정 (PUT /users/me)',unistr('## 배경\u000a사용자가 온보딩 이후에도 내 정보 화면에서 닉네임을 변경할 수 있어야 한다. mobile에는 인라인 닉네임 편집 UI가 이미 있으나 서버 반영 경로가 없다.\u000a\u000a## 작업 내용\u000a- `PUT /users/me` 구현(UserGuard) — 닉네임 수정. (컨벤션: 모든 수정은 PUT, 부분 수정)\u000a- 닉네임 검증(빈 값/길이) 및 저장, User.nickname 반영.\u000a- mobile: 인라인 편집 저장 시 이 API 호출 → 성공 시 세션 사용자 갱신.\u000a\u000a## 완료 조건\u000a- [x] `PUT /users/me`로 닉네임이 변경·저장된다\u000a- [x] 빈 닉네임 등 잘못된 입력은 400\u000a- [x] mobile 인라인 편집이 서버에 반영되고 화면이 갱신된다 (변경 시에만 PUT + me() 갱신)\u000a\u000a## 관련 기획\u000a와이어프레임 `profile` 닉네임 편집. 관련 도메인: User'),'task','done','medium','low','low','["profile"]','cmriysef7000drwgd8xaconsl','cmrby4wah00021znnga9fbhfq','profile','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk30001rwgnoiejp8hz',5,1783931586324,1784172194849,'CH-34',34);
INSERT INTO Issue VALUES('cmriyt7qj000jrwgd66wtj79d','cmrby3y0000001znnofoo0a53','[Profile] 러닝 통계 집계·표시',unistr('## 배경\u000a내 정보 화면 상단에 경쟁 수·우승 수·총 거리·완주율 등 러닝 통계를 보여준다. 지금은 mobile 목업 값이다.\u000a\u000a## 작업 내용\u000a- 사용자의 Participant·Room 이력에서 통계 집계: 참가한 경주 수, 우승(1위) 수, 총 달린 거리, 완주율(finished/전체).\u000a- 조회 API(예: `GET /users/me/stats` 또는 경주 이력 조회에 포함) 설계·구현.\u000a- mobile: 통계 타일을 실제 값으로 렌더.\u000a\u000a## 완료 조건\u000a- [x] 경쟁 수·우승 수·총 거리·완주율이 실제 이력에서 집계되어 반환된다\u000a- [x] mobile 통계 타일이 실데이터로 표시된다\u000a\u000a## 관련 기획\u000a와이어프레임 `profile` 통계 영역. [Race] 사용자별 경주 이력과 연계. 관련 도메인: Participant'),'task','done','low','low','medium','["profile","backend"]','cmriysef7000drwgd8xaconsl','cmrby4wah00021znnga9fbhfq','profile','cmrbzmtbf00051z1i7c5sjkag','cmrmtwkk30001rwgnoiejp8hz',4,1783931594347,1784192220406,'CH-35',35);
INSERT INTO Issue VALUES('cmriytegh000lrwgd9gstqj10','cmrby3y0000001znnofoo0a53','[Profile] 로그아웃',unistr('## 배경\u000a내 정보 화면에서 로그아웃해 로그인 화면으로 돌아갈 수 있어야 한다.\u000a\u000a## 작업 내용\u000a- mobile: 로그아웃 확인 다이얼로그 → 세션(토큰) 클리어 후 로그인 화면으로 이동. (구현 완료)\u000a- 서버: 스테이트리스 JWT라 별도 무효화는 없음. 추후 리프레시 토큰 도입 시 폐기 처리 검토(범위 밖).\u000a\u000a## 완료 조건\u000a- [x] 로그아웃 시 세션 토큰이 제거되고 로그인 화면으로 이동한다\u000a- [x] 재로그인 시 정상 동작한다\u000a\u000a## 관련 기획\u000a와이어프레임 `profile` 로그아웃.'),'task','done','high','medium','low','["profile"]','cmriysef7000drwgd8xaconsl','cmrby4wah00021znnga9fbhfq','profile',NULL,'cmrmtwkk30001rwgnoiejp8hz',4,1783931603057,1784172194850,'CH-36',36);
INSERT INTO Issue VALUES('cmrkb1wcp0003rwk37u4u4d1p','cmrby3y0000001znnofoo0a53','[Room] 방 목록 필터 거리·시간 상한 정책 확정 및 반영',unistr('## 배경\u000a홈 방 목록 필터의 **거리 상한(12km)·시간 상한(120분)이 하드코딩**돼 있었다 (`home_screen.dart`의 `_distMax=12`, `_limitMax=120`). 방 생성 화면은 "직접 입력"으로 이 상한을 넘는 방(예: 13km)을 만들 수 있고, 서버에는 정상 생성되지만 **홈 필터 기본 범위(0~상한)가 이 방을 걸러내 목록에 조용히 나타나지 않는** 문제가 있었다. → **정책 확정(2026-07-15): 거리 상한 100km, 시간 상한 24시간(1,440분).** (하한은 0.1km·5분.)\u000a\u000a## 작업 내용\u000a확정 정책 = (a) 상한 있음 — 거리 100km / 시간 1,440분.\u000a- 홈 필터 상한을 **100km·1,440분**으로 맞춰, 정책상 유효한 방이 필터에 의해 숨지 않도록 한다 (`_distMax` 12→100, `_limitMax` 120→1,440).\u000a- **"상한 초과 방이 목록에서 소리 없이 사라지는" 동작 제거** — 상한을 정책 캡과 일치시켜, 서버가 허용한 방은 항상 필터 기본 범위 안에 들어온다.\u000a- 방 생성·수정 시 상·하한 검증 자체는 별도 이슈에서 처리 → **[Room] 방 조건 거리·시간 상·하한 검증 (생성·수정)** (cmrls5jjp). ✅ 완료(done).\u000a\u000a## 완료 조건\u000a- [x] 목표 거리·제한 시간의 최대 허용값 정책 결정 (거리 100km·시간 1,440분 — 2026-07-15 확정)\u000a- [x] 홈 필터 상한이 정책과 일치하여, 정책상 유효한 방이 필터로 인해 숨지 않는다\u000a- [x] 방 생성 시 상한 검증 추가 (→ cmrls5jjp에서 반영·done: create/changeSetting 상·하한 검증)\u000a\u000a## 관련 기획\u000a1차 MVP 기획서 "방(경주 세션) 관리", §8 확정(방 조건 범위·단위). 관련 화면: `home`(방 목록 필터), `room-create`(직접 입력). 관련 도메인: Room(goalDistanceMeter·goalLimitMinutes). 관련 이슈: 방 조건 상·하한 검증(cmrls5jjp, done).\u000a\u000a> 발견 경위(2026-07-14): 방 생성 → 뒤로가기 시 목록 미갱신 이슈를 고치던 중, 상한 초과 방은 새로고침해도 필터에 걸려 안 보이는 별개 문제로 확인됨. 정책 미정이라 분리 등록.\u000a> 정책 확정(2026-07-15): 거리 0.1~100km, 시간 5~1,440분. 필터 상한은 상한값(100km/1,440분)에 맞춘다.\u000a> 완료(2026-07-15): `home_screen.dart` `_distMax 12→100`, `_limitMax 120→1,440`. 슬라이더 max·divisions·기본 RangeValues·`_filterActive`·`_visible`가 상수 참조라 자동 반영. `_visible`는 km(goalMeter/1000)·분으로 비교 → 상한=정책캡이라 유효 방은 항상 표시. flutter analyze 무이슈·test 14/14.'),'task','done','high','medium','low','["room","mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','home','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',6,1784012621063,1784172194851,'CH-37',37);
INSERT INTO Issue VALUES('cmrkr10je00011zbp992wq0gp','cmrby3y0000001znnofoo0a53','[Room] 방 상세 조회 (GET /rooms/:id) · 대기실 연동',unistr('방 목록에서 방을 탭했을 때 서버의 방 상세(참가자 포함)를 조회해 대기실 화면에 실제 데이터로 표시한다. 지금까지 대기실은 목업 데이터였고, core-api에 방 상세 조회 엔드포인트가 추가되어 이를 모바일에 연결한다.\u000a\u000a## 작업 내용\u000a- **core-api**: `GET /rooms/:id` (UserGuard) — 방 + 참가자(참가자별 user 포함)를 `GeneralRoomRetrieveResponseDto`로 반환. (완료)\u000a- **mobile**: `RoomApi.retrieve({accessToken, id})` + `RoomDetail`/`Participant` 모델 추가 (GET /rooms/:id 파싱).\u000a- **mobile**: 홈 카드 탭 시 방 `id`를 `/waiting-room` 라우트로 전달(`settings.arguments` 또는 `onGenerateRoute`), `WaitingRoomScreen`이 `roomId`를 받아 상세를 로드.\u000a- **mobile**: 대기실을 실제 상세로 렌더 — 제목·목표 거리·제한 시간·완주 기준 페이스·정원·참가자 목록(방장 표시)·시작 카운트다운. 로딩/실패 상태 처리.\u000a\u000a## 완료 조건\u000a- [x] `GET /rooms/:id`가 방 상세(참가자+user)를 반환한다 (core-api)\u000a- [x] 모바일 `RoomApi.retrieve` + `RoomDetail` 모델 추가, GET /rooms/:id 파싱\u000a- [x] 홈 카드 탭 시 방 id가 대기실로 전달되어 해당 방 상세가 로드된다\u000a- [x] 대기실이 목업이 아닌 서버 상세(제목·참가자·정원·방장·목표/제한·시작)를 표시한다\u000a- [x] 로딩/실패(에러) 상태가 처리된다\u000a\u000a> 참고: 실제 ''참가(join)''로 Participant를 생성하는 엔드포인트는 아직 없다. 이 이슈는 방 상세 **조회·표시**까지이며, 조인 API는 `[Room] 방 목록 · 입장`에서 이어서 다룬다.'),'task','done','high','high','medium','["backend","mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','waiting-room','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',4,1784039453684,1784172194851,'CH-38',38);
INSERT INTO Issue VALUES('cmrkrigjh000b1zbplkpxqye0','cmrby3y0000001znnofoo0a53','[Room] 방 목록에 ''내 방''(방장) 표시',unistr('홈 방 목록에서 로그인 사용자가 방장인 방(내가 만든 방)을 한눈에 알아보도록 ''내 방'' 배지를 카드에 표시한다.\u000a\u000a## 작업 내용\u000a- **mobile**: `RoomListItem`에 `hostUserId` 추가 및 `GET /rooms` 응답 파싱(서버 목록 DTO에 이미 포함됨).\u000a- **mobile**: 홈 카드 뷰모델에서 `hostUserId == AuthService.instance.user?.id`로 ''내 방'' 여부 판정.\u000a- **mobile**: 내가 방장인 카드에 디자인 시스템에 맞는 ''내 방'' 배지/칩을 표시(상태 배지와 시각적으로 구분되게).\u000a\u000a## 완료 조건\u000a- [x] `RoomListItem`이 `hostUserId`를 파싱한다\u000a- [x] 로그인 사용자가 방장인 방에만 ''내 방'' 표시가 나타난다\u000a- [x] 배지가 기존 상태 배지·정보 칩과 시각적으로 구분되고 레이아웃이 깨지지 않는다\u000a\u000a> 배지: 코랄(primary) 아웃라인 알약(person 아이콘 + ''내 방''), 제목 Row 왼쪽 배치. 긴 제목은 Expanded+Flexible+ellipsis로 오버플로우 방어. `flutter analyze` 무이슈·테스트 7/7 통과.'),'task','done','high','medium','low','["mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','home','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',4,1784040267581,1784172194852,'CH-39',39);
INSERT INTO Issue VALUES('cmrks2htq000p1zbpx4mc0vcl','cmrby3y0000001znnofoo0a53','[Room] 방 목록 ''참여중'' 상태 표시 및 입장 분기 (isJoined)',unistr('홈 방 목록에서 이미 참여 중인 방인데도 ''참가'' 버튼이 떠서, 참여 여부에 따라 표시/동작을 다르게 한다. 서버 목록 API에 `isJoined`(현재 유저 참가 여부)가 추가되었다.\u000a\u000a## 작업 내용\u000a- **mobile**: `RoomListItem`·`RoomSummary`에 `isJoined`(bool) 추가, `GET /rooms` 응답 파싱.\u000a- **mobile 배지**: 방장(isMine)은 ''내 방''(기존), 참여했지만 방장 아님(isJoined && !isMine)은 ''참여중'' 배지(내 방과 구분되는 톤).\u000a- **mobile 액션 버튼**: `isJoined`면 ''참가''가 아니라 ''입장'' — join API 호출 없이 바로 대기실(`/waiting-room`, arguments: id) 진입. 미참여 recruiting만 기존 ''참가''(join) 플로우 유지. live는 ''관전''(→/race) 유지, ready 미참여는 ''마감'' 유지.\u000a\u000a## 완료 조건\u000a- [x] `RoomListItem`/`RoomSummary`가 `isJoined`를 파싱·보유한다\u000a- [x] 이미 참여한 방은 ''참가''가 아니라 ''입장''으로 표시되고, 탭 시 join 호출 없이 대기실로 진입한다\u000a- [x] 참여중(방장 아님) 방에 ''참여중'' 표시가 나타나고 ''내 방''과 시각적으로 구분된다\u000a- [x] 미참여 recruiting 방의 기존 ''참가''(join) 동작은 그대로다\u000a\u000a> ''참여중'' 배지는 success(그린) 톤(`check_circle_outline`)으로 ''내 방''(primary 코랄)과 구분. 버튼 분기: live→관전 / isJoined→입장(join 없이) / 미참여 recruiting→참가 / 그 외→마감. `flutter analyze` 무이슈·테스트 7/7.'),'task','done','high','medium','low','["mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','home','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',4,1784041202360,1784172194852,'CH-40',40);
INSERT INTO Issue VALUES('cmrksea4u00131zbp27gz8wo7','cmrby3y0000001znnofoo0a53','[Room] 방 이탈(나가기) — 참가자 방 나가기',unistr('방장이 아닌 참가자가 대기실에서 방을 나갈(이탈) 수단이 없다. 대기실 와이어프레임(v9)에 참가자 전용 ''방 나가기'' 버튼과 확인 모달이 반영되어, 이를 실제로 구현한다.\u000a\u000a## 작업 내용\u000a- **core-api**: `POST /rooms/:id/exit` 구현 — 로그인 유저의 Participant 제거(`Room.exit`, 관계 `orphanedRowAction:''delete''`로 row 삭제). **방장이 exit를 호출하면 이탈 대신 방을 취소(cancelled)** 처리(`Room.cancel`). 모집중(recruiting)에서만 가능. 컨트롤러 핸들러 배선 포함.\u000a- **mobile**: 대기실에서 **비방장 참가자에게만** ''방 나가기'' 버튼 노출(방장에겐 미노출), 확인 다이얼로그 후 exit API 호출 → 성공 시 홈(방 목록)으로 이동. `RoomApi.exit({accessToken, id})` 추가.\u000a- 나간 뒤 홈 목록의 참가자 수·`isJoined`(참여중 표시)와 상세가 갱신되도록 한다.\u000a\u000a## 완료 조건\u000a- [x] `POST /rooms/:id/exit`가 로그인 참가자를 방에서 제거한다(관계 orphan delete로 실제 삭제, 미존재 방은 예외)\u000a- [x] 방장이 exit를 호출하면 이탈 대신 방이 취소(cancelled)된다 — 모바일은 방장에게 ''방 나가기''를 노출하지 않는다\u000a- [x] 모바일 대기실에서 비방장 참가자에게만 ''방 나가기''가 보이고, 확인 후 나가면 홈으로 이동한다\u000a- [x] 이탈 후 목록/상세의 참가자 수·참여중(isJoined) 표시가 갱신된다\u000a\u000a## 범위 / 미결\u000a- 이 이슈는 **모집중(recruiting) 대기실에서의 자발적 이탈** 범위다. 경주 진행중(live) 도중 이탈=dnf 처리는 `[Race] 제한 시간 만료 종료 · 이탈/강제종료 dnf 처리`에서 다룬다.\u000a- 이탈이 자동 취소(2명 미만) 조건에 미치는 영향은 `[Room] 자동 모집 마감 · 취소`와 함께 확인.\u000a\u000a> 구현: mobile 대기실 하단 액션을 역할별 분기(방장=경주 시작 / 비방장=방 나가기 danger). `_confirmExit`→`exit` API→성공 시 `Navigator.pop()`(홈 목록 자동 갱신), 실패 시 서버 메시지 SnackBar. core-api 컨트롤러 `exit` 스텁을 서비스 호출로 배선 수정. `flutter analyze` 무이슈·테스트 8/8, core-api typecheck 통과.'),'task','done','medium','medium','medium','["backend","mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','waiting-room','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',5,1784041752270,1784172194853,'CH-41',41);
INSERT INTO Issue VALUES('cmrls5jjp0009rwz8nok0yd2d','cmrby3y0000001znnofoo0a53','[Room] 방 조건 거리·시간 상·하한 검증 (생성·수정)',unistr('## 배경\u000a방 조건(목표 거리·제한 시간)의 허용 범위가 기획서 §3/§8에서 확정됨: **거리 0.1km(100m)~100km, 시간 5분~24시간(1,440분)**. 그러나 현재 core-api `Room.create`/`Room.changeSetting`은 `> 0`만 검증하고 상한·하한을 강제하지 않는다. (관련: `changeSetting`은 `args.x && args.x <= 0` 단락으로 **0도 통과**하는 버그가 있음.)\u000a\u000a## 작업 내용\u000a- **core-api 도메인**: `Room.create`·`Room.changeSetting`에 거리 100~100,000m, 시간 5~1,440분 상·하한 검증 추가. 0·음수·범위 밖 모두 거부. 기존 `args.x && args.x <= 0`(0-통과) 버그도 함께 수정.\u000a- **core-api DTO**: `GeneralRoomCreateDto`·`GeneralRoomChangeSettingDto`의 `goalDistanceMeter`에 `@Min(100) @Max(100000)`, `goalLimitMinutes`에 `@Min(5) @Max(1440)` 추가(방어).\u000a- **mobile**: 방 생성/방 조건 변경 입력에 클라 검증(거리 0.1~100km, 시간 5~1,440분) + 범위 밖 안내. 거리 입력·표시는 km 소수 1자리(=100m 스텝), 서버 전송 시 ×1000.\u000a\u000a## 완료 조건\u000a- [x] core-api가 거리 100~100,000m·시간 5~1,440분 밖 값을 **생성·수정 모두**에서 거부한다 (0 포함)\u000a- [x] 생성·수정 DTO에 min/max 반영\u000a- [x] mobile 생성/수정 입력이 범위를 클라에서 검증하고 범위 밖은 안내한다\u000a- [x] 거리 입력·표시가 km 소수 1자리로 일관되고 저장/전송은 m로 환산된다\u000a\u000a## 관련 기획\u000a1차 MVP 기획서 §3 방 생성·대기실, §8 확정(방 조건 범위·단위), 진행 메모(2026-07-15). 관련 도메인: Room(goalDistanceMeter·goalLimitMinutes). 화면: room-create.\u000a\u000a> 진행(2026-07-15): **core-api** — `Room.validGoalConditionRange`(private static, 경계값은 `static readonly Room.GOAL_*`)로 `create`·`changeSetting` 상·하한 검증 + 0-통과 버그 해소. 생성·수정 DTO는 `@Min/@Max` 보유. typecheck 0 에러. **mobile** — 공유 상수 `room_limits.dart`(0.1~100km / 5~1,440분) + 방 생성(`_submit`)·대기실 편집 시트(`_EditRoomSheet._apply`) 범위 검증·안내 + km→m(×1000) 환산. flutter analyze 무이슈·test 통과.\u000a> 참고: 방 생성 화면의 제한 시간 **슬라이더**는 아직 최대 120분(120분 초과는 직접 입력으로만) — 슬라이더 UX 확장은 별도 디자인 판단(범위 밖).'),'task','done','high','high','medium','["room","backend","mobile"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','room-create','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk30001rwgnoiejp8hz',4,1784101810741,1784172194853,'CH-42',42);
INSERT INTO Issue VALUES('cmrmsr3n5002rrwz8cpzufu9e','cmrby3y0000001znnofoo0a53','[백오피스] 관리자 인증',unistr('## 배경\u000a백오피스는 사내 관리자 전용이므로, 앱 사용자(User)와 **분리된 관리자 계정(Admin)** 으로 인증한다. 1차는 자체 이메일/비밀번호 + JWT (2차 구글 로그인).\u000a\u000a## 작업 내용\u000a- Admin 도메인·초기 관리자 시드, 관리자 인증 API(`/admins/auth/*`)와 관리자 가드, 백오피스 로그인 화면. 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 관리자 이메일/비밀번호로 로그인·JWT 발급, 미인증 시 `/admins/*` 접근 차단\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 인증, §5 인증/보안. 관련 도메인: Admin. 화면: admin-login.'),'epic','todo','high','high','medium','["backoffice","auth"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','admin-login','cmrmsp45v002nrwz81oyne94a','cmrmtwkk80003rwgnkid249iz',1,1784163282737,1784172194855,'BO-1',1);
INSERT INTO Issue VALUES('cmrmsr7xx002vrwz8azmwq0jl','cmrby3y0000001znnofoo0a53','[백오피스] 운영 대시보드',unistr('## 배경\u000a관리자가 로그인 직후 서비스 상태를 한눈에 파악하도록 핵심 운영 지표를 요약 표시한다.\u000a\u000a## 작업 내용\u000a- 지표 집계 API + 대시보드 화면(KPI 카드·최근 경주·상태별 방). 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 가입자 수·활성 방 수·오늘 경주·완주율 등 핵심 지표가 집계되어 표시된다\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 운영 대시보드, §7 #5. 화면: dashboard.'),'epic','todo','high','high','medium','["backoffice"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','dashboard',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163288309,1784172194856,'BO-2',2);
INSERT INTO Issue VALUES('cmrmsrc0d002zrwz84a3by3x2','cmrby3y0000001znnofoo0a53','[백오피스] 사용자 관리',unistr('## 배경\u000aCS·제재를 코드/DB 조작 없이 처리하도록 사용자 조회와 계정 상태 관리를 제공한다.\u000a\u000a## 작업 내용\u000a- 사용자 목록/검색/상세 조회 API, 상태 변경(suspended/active) API, 목록·상세 화면. 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 사용자 검색·상세 확인, 상태(active/suspended) 변경이 백오피스에서 처리된다\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 사용자 관리, §7 #2. 관련 도메인: User. 화면: user-list·user-detail.'),'epic','todo','high','high','medium','["backoffice"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','user-list','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk80003rwgnkid249iz',1,1784163293582,1784172194856,'BO-3',3);
INSERT INTO Issue VALUES('cmrmsrg0e0033rwz8lzeh90iw','cmrby3y0000001znnofoo0a53','[백오피스] 방(경주) 관리',unistr('## 배경\u000a운영 중 문제 방(스팸·부적절)을 관리자가 모니터링하고 강제 취소할 수 있어야 한다.\u000a\u000a## 작업 내용\u000a- 방 목록/상세(참가자 포함) 조회 API, 강제 취소 API, 목록·상세 화면. 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 방 상태 모니터링과 문제 방 강제 취소가 백오피스에서 처리된다\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 방(경주) 관리, §7 #3. 관련 도메인: Room. 화면: room-list·room-detail.'),'epic','todo','high','high','medium','["backoffice"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','room-list','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk80003rwgnkid249iz',1,1784163298766,1784172194857,'BO-4',4);
INSERT INTO Issue VALUES('cmrmsrkpa0037rwz8jaqwoq9i','cmrby3y0000001znnofoo0a53','[백오피스] 약관 관리',unistr('## 배경\u000a약관 개정을 개발자 개입 없이 관리자가 셀프서비스로 처리한다. 타입당 active 버전 1개 불변식을 지킨다.\u000a\u000a## 작업 내용\u000a- 약관 목록/버전 등록·수정 API, 활성화(이전 버전 archived) API, 약관 관리 화면. 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 약관 새 버전 등록·활성화가 백오피스에서 처리되고, 활성화 시 이전 active가 archived로 전이(타입당 active 1개 유지)\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 약관 관리, §7 #4. 관련 도메인: Agreement. 화면: agreement-list.'),'epic','todo','high','high','medium','["backoffice"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','agreement-list','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk80003rwgnkid249iz',1,1784163304846,1784172194857,'BO-5',5);
INSERT INTO Issue VALUES('cmrmsrsaa003frwz8umyx3ev5','cmrby3y0000001znnofoo0a53','[백오피스] 관리자 계정 관리',unistr('## 배경\u000a관리자를 추가·비활성화한다. 1차는 단일 역할(모든 관리자 동일 권한)이라 역할 부여는 없다.\u000a\u000a## 작업 내용\u000a- 관리자 목록/추가/비활성(활성) API + 관리자 계정 화면. 세부는 하위 이슈 참조.\u000a\u000a## 완료 조건\u000a- [ ] 관리자 계정 추가·비활성/활성이 백오피스에서 처리된다\u000a- [ ] 각 세부 기능은 하위 이슈 참조\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 계정 관리, §7 #7. 관련 도메인: Admin. 화면: admin-accounts.'),'epic','todo','high','medium','low','["backoffice"]',NULL,'cmrmrup9j001frwz8i9v8o7pn','admin-accounts','cmrmsp45v002nrwz81oyne94a','cmrmtwkk80003rwgnkid249iz',1,1784163314674,1784172194858,'BO-7',7);
INSERT INTO Issue VALUES('cmrmswj8x003lrwz8parwgisi','cmrby3y0000001znnofoo0a53','[백오피스] Admin 엔티티·마이그레이션·초기 관리자 시드',unistr('## 배경\u000a관리자 계정을 앱 User와 분리해 저장한다(`Admin`). 인증·계정 관리의 기반.\u000a\u000a## 작업 내용\u000a- core-api `Admin` 엔티티(email UQ, password, name, status(active/disabled)) + 마이그레이션. 생성/수정 시각은 공통 감사 컬럼(createdAt/updatedAt)을 사용한다(별도 createdOn 두지 않음).\u000a- 초기 관리자 시드(환경변수/시드 스크립트)로 최초 관리자 1명 생성.\u000a\u000a## 완료 조건\u000a- [ ] Admin 테이블 생성(마이그레이션), email 유니크 제약\u000a- [ ] 초기 관리자 계정이 시드로 생성되어 로그인 가능\u000a- [ ] 비밀번호는 해시(bcrypt 등)로 password 컬럼에 저장\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 인증, §8 관리자 계정 분리. 도메인: Admin.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsr3n5002rrwz8cpzufu9e','cmrmrup9j001frwz8i9v8o7pn',NULL,'cmrmsp45v002nrwz81oyne94a','cmrmtwkk80003rwgnkid249iz',2,1784163536241,1784189223125,'BO-8',8);
INSERT INTO Issue VALUES('cmrmswnda003prwz8ovf6x15l','cmrby3y0000001znnofoo0a53','[백오피스] 관리자 인증 API · 관리자 가드',unistr('## 배경\u000a관리자 이메일/비밀번호 로그인과 `/admins/*` 네임스페이스 보호.\u000a\u000a## 작업 내용\u000a- `POST /admins/auth/login` — 이메일/비번 검증(bcrypt), JWT 발급. **disabled 계정 로그인 차단.**\u000a- `AdminGuard`(JWT 검증 → Admin 주입)로 `/admins/*` 보호. `GET /admins/auth/me`.\u000a\u000a## 완료 조건\u000a- [ ] 올바른 자격증명 → JWT 발급, 틀리면 401\u000a- [ ] status=disabled 관리자는 로그인 차단\u000a- [ ] AdminGuard로 미인증 `/admins/*` 접근 시 401\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 인증, §5 인증/보안. 도메인: Admin. 화면: admin-login.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsr3n5002rrwz8cpzufu9e','cmrmrup9j001frwz8i9v8o7pn','admin-login','cmrmsp45v002nrwz81oyne94a','cmrmtwkk80003rwgnkid249iz',1,1784163541583,1784172194859,'BO-9',9);
INSERT INTO Issue VALUES('cmrmswrdz003trwz8uskoexfv','cmrby3y0000001znnofoo0a53','[백오피스] 로그인 화면 · 세션/라우팅 가드',unistr('## 배경\u000a`apps/back-office` 로그인 UI와 인증 상태 관리.\u000a\u000a## 작업 내용\u000a- 로그인 폼(이메일/비번) → `POST /admins/auth/login` 호출, JWT 저장.\u000a- 인증 상태 기반 라우팅 가드(미인증 시 로그인으로), 로그아웃.\u000a\u000a## 완료 조건\u000a- [ ] 로그인 성공 시 대시보드 진입, 실패 시 에러 표시\u000a- [ ] 미인증 상태로 보호 라우트 접근 시 로그인으로 리다이렉트\u000a- [ ] 로그아웃 동작\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 인증. 화면: admin-login.'),'task','todo','high','high','low','["backoffice","frontend"]','cmrmsr3n5002rrwz8cpzufu9e','cmrmrup9j001frwz8i9v8o7pn','admin-login',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163546792,1784172194860,'BO-10',10);
INSERT INTO Issue VALUES('cmrmswwbr003xrwz8qks7sl7w','cmrby3y0000001znnofoo0a53','[백오피스] 대시보드 지표 집계 API',unistr('## 배경\u000a관리자 로그인 직후 서비스 상태 파악용 지표.\u000a\u000a## 작업 내용\u000a- `GET /admins/dashboard` — 누적 가입자, 활성 방(recruiting/ready/live), 오늘 경주 수, 완주율(최근 7일), 상태별 방 수 등 집계.\u000a\u000a## 완료 조건\u000a- [ ] 핵심 지표가 집계 쿼리로 반환된다\u000a- [ ] AdminGuard로 보호된다\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 운영 대시보드, §7 #5.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsr7xx002vrwz8azmwq0jl','cmrmrup9j001frwz8i9v8o7pn',NULL,NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163553191,1784172194860,'BO-11',11);
INSERT INTO Issue VALUES('cmrmswy930041rwz89t40rwkm','cmrby3y0000001znnofoo0a53','[백오피스] 대시보드 화면',unistr('## 배경\u000a지표를 시각적으로 요약.\u000a\u000a## 작업 내용\u000a- KPI 카드(가입자·활성 방·오늘 경주·완주율) + 최근 경주 테이블 + 상태별 방. `GET /admins/dashboard` 연동.\u000a\u000a## 완료 조건\u000a- [ ] 지표가 실데이터로 렌더된다\u000a- [ ] 로딩/에러 상태 처리\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 운영 대시보드. 화면: dashboard.'),'task','todo','high','high','low','["backoffice","frontend"]','cmrmsr7xx002vrwz8azmwq0jl','cmrmrup9j001frwz8i9v8o7pn','dashboard',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163555688,1784172194861,'BO-12',12);
INSERT INTO Issue VALUES('cmrmsxge90045rwz8rb7yvj9n','cmrby3y0000001znnofoo0a53','[백오피스] 사용자 목록·검색·상세 API',unistr('## 배경\u000aCS·제재를 위해 사용자를 조회한다.\u000a\u000a## 작업 내용\u000a- `GET /admins/users` — 페이지네이션 + 검색(닉네임·이메일·ID) + 상태 필터.\u000a- `GET /admins/users/:id` — 상세(프로필·상태·가입 정보 + 참가 이력 요약).\u000a\u000a## 완료 조건\u000a- [ ] 목록이 서버 페이지네이션·검색·상태 필터로 반환된다\u000a- [ ] 상세에 프로필·상태·참가 이력이 포함된다\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 사용자 관리. 도메인: User. 화면: user-list·user-detail.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsrc0d002zrwz84a3by3x2','cmrmrup9j001frwz8i9v8o7pn','user-list','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk80003rwgnkid249iz',1,1784163579200,1784172194861,'BO-13',13);
INSERT INTO Issue VALUES('cmrmsxhxa0049rwz8oiway08l','cmrby3y0000001znnofoo0a53','[백오피스] 사용자 상태 변경 API (정지/해제)',unistr('## 배경\u000a운영자가 사용자 계정을 정지/해제한다.\u000a\u000a## 작업 내용\u000a- `PUT /admins/users/:id/status` — active ↔ suspended 전이(User.status). (선택) 사유 파라미터.\u000a- User 도메인의 상태 전이 규칙(active↔suspended) 준수.\u000a\u000a## 완료 조건\u000a- [ ] active → suspended, suspended → active 전이가 반영된다\u000a- [ ] 잘못된 전이/대상은 적절히 거부(400/404)\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 사용자 관리, §7 #2. 도메인: User. 화면: user-detail.'),'task','todo','high','high','low','["backoffice","backend"]','cmrmsrc0d002zrwz84a3by3x2','cmrmrup9j001frwz8i9v8o7pn','user-detail','cmrbzjtmr00011z1ivhzc2lbk','cmrmtwkk80003rwgnkid249iz',1,1784163581182,1784172194862,'BO-14',14);
INSERT INTO Issue VALUES('cmrmsxkb9004drwz8568b781z','cmrby3y0000001znnofoo0a53','[백오피스] 사용자 목록·상세 화면 · 상태 변경 UI',unistr('## 배경\u000a사용자 조회·상태 관리 화면.\u000a\u000a## 작업 내용\u000a- 목록(검색·상태 필터·페이지네이션) + 상세(프로필·참가 이력).\u000a- 상세에서 정지/해제 버튼 → 확인 모달 → `PUT /admins/users/:id/status` 호출·반영.\u000a\u000a## 완료 조건\u000a- [ ] 목록 검색·필터·페이지네이션 동작\u000a- [ ] 상세에서 상태 변경이 서버에 반영되고 화면 갱신\u000a- [ ] 로딩/에러 처리\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 사용자 관리. 화면: user-list·user-detail.'),'task','todo','high','high','medium','["backoffice","frontend"]','cmrmsrc0d002zrwz84a3by3x2','cmrmrup9j001frwz8i9v8o7pn','user-list',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163584277,1784172194862,'BO-15',15);
INSERT INTO Issue VALUES('cmrmsxs2p004hrwz8igplm12s','cmrby3y0000001znnofoo0a53','[백오피스] 방 목록·검색·상세 API (관리자)',unistr('## 배경\u000a관리자가 모든 방을 상태 무관하게 모니터링한다(앱 목록 API는 참여 가능 방만 노출). 종료(finished) 방의 결과 조회도 별도 API 없이 이 상세 API에 흡수한다.\u000a\u000a## 작업 내용\u000a- `GET /admins/rooms` — 페이지네이션 + 상태 필터(recruiting~cancelled, **finished 포함**) + 검색(제목·방장). 종료 경주는 status=finished 필터로 탐색.\u000a- `GET /admins/rooms/:id` — 상세(방 정보 + 참가자 목록). **방이 finished면 참가자 결과(등수·거리·시간·페이스)를 함께 반환.** 시간/페이스는 Room.startOn/finishedOn·Participant에서 파생.\u000a\u000a## 완료 조건\u000a- [ ] 모든 상태의 방을 필터·검색·페이지네이션으로 조회 (finished 포함)\u000a- [ ] 상세에 참가자 목록 포함\u000a- [ ] 종료 방 상세에 참가자 결과(등수·거리·시간·페이스) 포함\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 방(경주) 관리, §7 #6. 도메인: Room·Participant. 화면: room-list·room-detail.\u000a(별도 `/admins/races` 결과 API는 폐기 — 이 상세 API로 흡수)'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsrg0e0033rwz8lzeh90iw','cmrmrup9j001frwz8i9v8o7pn','room-list','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk80003rwgnkid249iz',2,1784163594337,1784185953643,'BO-16',16);
INSERT INTO Issue VALUES('cmrmsxv4m004lrwz8zjdcx2f6','cmrby3y0000001znnofoo0a53','[백오피스] 방 강제 취소 API',unistr('## 배경\u000a문제 방(스팸·부적절)을 관리자가 운영상 강제 취소한다.\u000a\u000a## 작업 내용\u000a- `POST /admins/rooms/:id/cancel` — 방을 cancelled로 전이(관리자 권한). 방장 취소(`Room.cancel`)와 별개로 **관리자 강제 취소** 경로. 종료/취소된 방은 거부.\u000a- 취소 이벤트 발행(RoomCancelledEvent) → 참가자 반영(대기실 클라).\u000a\u000a## 완료 조건\u000a- [ ] 모집·진행 전 방을 관리자가 cancelled로 전이\u000a- [ ] 이미 finished/cancelled면 거부(400)\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 방(경주) 관리, §7 #3. 도메인: Room. 화면: room-detail.'),'task','todo','high','high','low','["backoffice","backend"]','cmrmsrg0e0033rwz8lzeh90iw','cmrmrup9j001frwz8i9v8o7pn','room-detail','cmrbzjy7400031z1i4kv14kgo','cmrmtwkk80003rwgnkid249iz',1,1784163598295,1784172194863,'BO-17',17);
INSERT INTO Issue VALUES('cmrmsxyhg004prwz8dl9boutg','cmrby3y0000001znnofoo0a53','[백오피스] 방 목록·상세 화면 · 강제 취소 UI',unistr('## 배경\u000a방 모니터링·강제 취소 화면. 종료 경주 결과 조회도 별도 화면 없이 방 상세에 통합한다.\u000a\u000a## 작업 내용\u000a- 목록(상태 칩 필터·검색·페이지네이션, finished 포함) + 상세(방 정보·참가자).\u000a- 상세에서 강제 취소 버튼 → 확인 → `POST /admins/rooms/:id/cancel` 호출·반영.\u000a- **방이 finished면 상세에 참가자 결과(등수·거리·시간·페이스) 표시** (`GET /admins/rooms/:id` 응답의 결과 필드 렌더).\u000a\u000a## 완료 조건\u000a- [ ] 상태 필터·검색·페이지네이션 동작 (finished 포함)\u000a- [ ] 상세에서 강제 취소가 서버에 반영되고 상태 갱신\u000a- [ ] 종료 방 상세에서 참가자 결과(등수·거리·시간·페이스)가 표시된다\u000a- [ ] 로딩/에러 처리\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 방(경주) 관리, §7 #6. 화면: room-list·room-detail.\u000a(별도 race-result 화면은 폐기 — 방 상세에 흡수)'),'task','todo','high','high','medium','["backoffice","frontend"]','cmrmsrg0e0033rwz8lzeh90iw','cmrmrup9j001frwz8i9v8o7pn','room-list',NULL,'cmrmtwkk80003rwgnkid249iz',2,1784163602644,1784185958749,'BO-18',18);
INSERT INTO Issue VALUES('cmrmsyd76004trwz8fkwhw4ry','cmrby3y0000001znnofoo0a53','[백오피스] 약관 목록·버전 등록/수정 API',unistr('## 배경\u000a약관을 버전 단위로 관리한다(등록은 pending 상태로).\u000a\u000a## 작업 내용\u000a- `GET /admins/agreements` — 유형·버전·상태 목록.\u000a- `POST /admins/agreements` — 새 버전 등록(pending). `PUT /admins/agreements/:id` — pending 버전 수정.\u000a- 유형+버전 유니크(UQ) 준수.\u000a\u000a## 완료 조건\u000a- [ ] 약관 목록 조회, 새 버전 pending으로 등록, pending 수정 가능\u000a- [ ] UQ(type, version) 위반 시 거부\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 약관 관리. 도메인: Agreement. 화면: agreement-list.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsrkpa0037rwz8jaqwoq9i','cmrmrup9j001frwz8i9v8o7pn','agreement-list','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk80003rwgnkid249iz',1,1784163621714,1784172194864,'BO-19',19);
INSERT INTO Issue VALUES('cmrmsyhtm004xrwz8fv20ye2i','cmrby3y0000001znnofoo0a53','[백오피스] 약관 활성화 API (타입당 active 1개)',unistr('## 배경\u000a약관 개정 시 새 버전을 활성화하고 이전 버전을 보관한다. **타입당 active 1개 불변식.**\u000a\u000a## 작업 내용\u000a- `POST /admins/agreements/:id/activate` — pending → active 전이. 같은 type의 기존 active를 **archived로 전이**(원자적).\u000a- Agreement 도메인 상태 흐름(pending→active→archived) 준수.\u000a\u000a## 완료 조건\u000a- [ ] 활성화 시 대상은 active, 같은 타입의 이전 active는 archived\u000a- [ ] 타입당 active 버전이 항상 1개 유지된다\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 약관 관리, §7 #4. 도메인: Agreement. 화면: agreement-list.'),'task','todo','high','high','medium','["backoffice","backend"]','cmrmsrkpa0037rwz8jaqwoq9i','cmrmrup9j001frwz8i9v8o7pn','agreement-list','cmrc4i1j8000v1z185z3b2pdk','cmrmtwkk80003rwgnkid249iz',1,1784163627706,1784172194864,'BO-20',20);
INSERT INTO Issue VALUES('cmrmsymfm0051rwz8bjhfnglz','cmrby3y0000001znnofoo0a53','[백오피스] 약관 관리 화면 (목록·등록·활성화)',unistr('## 배경\u000a약관 셀프서비스 관리 화면.\u000a\u000a## 작업 내용\u000a- 약관 목록(유형·버전·상태·시행일) + 새 버전 등록 모달 + 활성화 버튼.\u000a- 활성화 시 확인 → `POST /admins/agreements/:id/activate` → 목록 갱신(이전 active가 archived로).\u000a\u000a## 완료 조건\u000a- [ ] 목록·등록·활성화가 서버에 반영되고 화면 갱신\u000a- [ ] 활성화 후 타입당 active 1개가 화면에서 확인된다\u000a- [ ] 로딩/에러 처리\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 약관 관리. 화면: agreement-list.'),'task','todo','high','high','medium','["backoffice","frontend"]','cmrmsrkpa0037rwz8jaqwoq9i','cmrmrup9j001frwz8i9v8o7pn','agreement-list',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163633683,1784172194865,'BO-21',21);
INSERT INTO Issue VALUES('cmrmsyz9o005drwz8i9cevmug','cmrby3y0000001znnofoo0a53','[백오피스] 관리자 계정 CRUD API',unistr('## 배경\u000a관리자 계정을 추가·비활성한다(단일 역할).\u000a\u000a## 작업 내용\u000a- `GET /admins` — 관리자 목록. `POST /admins` — 관리자 추가(이메일·이름·임시 비번, 해시 저장).\u000a- `PUT /admins/:id/status` — active ↔ disabled 전이. 본인 계정 비활성 방지.\u000a\u000a## 완료 조건\u000a- [ ] 관리자 목록 조회·추가·상태(active/disabled) 변경\u000a- [ ] 이메일 유니크, 본인 비활성화 차단\u000a- [ ] AdminGuard 보호\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 계정 관리, §7 #7. 도메인: Admin. 화면: admin-accounts.'),'task','todo','high','medium','low','["backoffice","backend"]','cmrmsrsaa003frwz8umyx3ev5','cmrmrup9j001frwz8i9v8o7pn','admin-accounts','cmrmsp45v002nrwz81oyne94a','cmrmtwkk80003rwgnkid249iz',1,1784163650316,1784172194866,'BO-24',24);
INSERT INTO Issue VALUES('cmrmsz3i6005hrwz8tr9ego6q','cmrby3y0000001znnofoo0a53','[백오피스] 관리자 계정 화면 (목록·추가·비활성)',unistr('## 배경\u000a관리자 계정 관리 화면.\u000a\u000a## 작업 내용\u000a- 관리자 목록 + 추가 모달(이메일·이름·임시 비번) + 비활성/활성 토글. `GET/POST /admins`·`PUT /admins/:id/status` 연동.\u000a\u000a## 완료 조건\u000a- [ ] 관리자 목록·추가·상태 변경이 서버에 반영되고 화면 갱신\u000a- [ ] 본인 계정 비활성 버튼 비노출/차단\u000a- [ ] 로딩/에러 처리\u000a\u000a## 관련 기획\u000a백오피스 1차 기획서 §3 관리자 계정 관리. 화면: admin-accounts.'),'task','todo','high','medium','low','["backoffice","frontend"]','cmrmsrsaa003frwz8umyx3ev5','cmrmrup9j001frwz8i9v8o7pn','admin-accounts',NULL,'cmrmtwkk80003rwgnkid249iz',1,1784163655806,1784172194866,'BO-25',25);
INSERT INTO "Plan" VALUES('cmrby4wah00021znnga9fbhfq','cmrby3y0000001znnofoo0a53','1차 MVP 기획서',unistr('# 추노\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 장소에 상관없이, 실시간 GPS로 각자 뛰면서 "누가 목표 거리에 먼저 도달하는가"를 겨루는 경쟁 러닝 앱.\u000a\u000a같은 트랙에 모이지 않아도 방 하나로 원격 러닝 대결이 성립한다. 러닝을 습관화하고 싶지만 동기부여가 부족한 사람에게 "혼자 뛰어도 함께 경쟁하는" 경험을 제공한다. 1차 MVP는 Android/iOS 두 플랫폼을 Flutter 단일 코드베이스로 동시 지원하며, 소셜 로그인(첫 로그인 시 계정 즉시 생성) → **최초 온보딩(약관 동의·프로필 설정)** → 방 생성 → 대기 → 실시간 경주 → 등수 판정 → 결과의 한 사이클을 안정적으로 완주시키는 것을 목표로 한다. 위치 정보를 상시 수집하는 서비스 특성상, 최초 가입 시 개인정보·위치기반서비스 약관 동의를 필수로 받는다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 동기부여가 필요한 러너 | 혼자 뛰면 지루하고 꾸준하지 못함 | 친구와 방을 만들어 목표 거리 대결, 이겨서 성취감을 얻는다 |\u000a| 원격의 지인 그룹 | 서로 다른 지역에 살아 같이 못 뜀 | 각자 동네에서 같은 방에 입장해 동시에 스타트, 실시간 순위를 본다 |\u000a| 가벼운 경쟁을 즐기는 사람 | 기록 경쟁·게임성 | 짧은 거리(예: 3km) 방에 참여해 빠르게 승부를 낸다 |\u000a| 신규 가입자 | 안심하고 서비스를 시작하고 싶음 | 최초 로그인 후 약관·개인정보 동의와 닉네임 설정을 마치고 서비스에 진입한다 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 소셜 로그인 | 카카오 / 구글 / 애플 인증으로 가입·로그인 (자체 이메일 가입 없음). **첫 로그인 시 계정이 즉시 생성**되고(User.status=onboarding), 이후 재로그인은 providerKey로 기존 계정에 매칭 |\u000a| 높음 | 온보딩 & 약관 동의 | 최초 가입 시 필수 약관(서비스 이용약관·개인정보 수집·이용·위치기반서비스 이용약관) 동의, 닉네임 설정. 선택 약관(마케팅 수신)은 건너뛰기 가능. 필수 미동의 시 진입 차단. **온보딩을 끝까지 마쳐야 User.status=active가 되며, 중단하면 계정은 남되 미완료(onboarding) 상태로 유지되어 재로그인 시 온보딩을 이어서 진행** |\u000a| 높음 | 약관 버전 관리·개정 재동의 | 약관은 버전 단위로 관리한다. 필수 약관이 개정되면 재로그인 시 변경된 약관만 재동의 요구 |\u000a| 높음 | 방 생성 | 목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방 개설. **목표 거리 0.1~100km(저장 m, 표시 km 소수 1자리)·제한 시간 5분~24시간(1,440분)** 상·하한을 검증한다 (아래 📏 콜아웃 참조) |\u000a| 높음 | 방 목록 / 입장 | 모집 중 상태의 방에만 입장 가능. 지각 입장 없음. 홈 목록 필터의 거리·시간 상한은 방 조건 상한(100km·1,440분)과 일치시킨다 |\u000a| 높음 | 대기실 & 방장 관리 | 현 인원/정원·참가자 목록·시작 카운트다운·완주 기준 페이스 표시. 모집 중 방장이 목표 거리·제한 시간·최대 인원 수정(생성과 **동일한 거리·시간 상·하한 검증**) 및 참가자 강퇴 가능 |\u000a| 높음 | 자동 모집 마감·취소 | 시작 10분 전 모집 마감. 이 시점에 참가자 2명 미만이면 경주 자동 취소 |\u000a| 높음 | 실시간 GPS 러닝 | 디바이스 GPS로 이동 거리 누적, WebSocket으로 참가자 위치/거리 실시간 동기화 |\u000a| 높음 | 실시간 리더보드 | 경주 중 참가자 순위·거리·페이스를 실시간 표시 |\u000a| 높음 | 등수 판정 | 클라이언트 GPS 기반으로 목표 도달 순서에 따라 등수 확정. 동시 도달 시 공동 순위. 미완주·중도 이탈자는 완주자 뒤 누적 거리순 |\u000a| 보통 | 결과 & 경주 이력 | 경주 종료 후 사용자별 경주 이력에서 결과(등수·거리·시간·페이스) 조회 |\u000a\u000a> 📌 **참고** — 방(Room)의 상태와 전이 규칙은 도메인 문서(`/ib-domain`)에서 정의한다. 약관 동의는 **Agreement(약관 마스터: 유형·버전·필수 여부·본문)** 와 **UserConsent(사용자별 동의 이력: 약관·동의 여부·동의 시각)** 도메인으로 관리한다 (정의 완료). 사용자 계정의 상태(가입~이용~정지/이탈)는 **User.status 생명주기**로 관리한다 (아래 §8 확정 참조).\u000a\u000a> 📏 **방 조건 범위·단위 (확정)** — 목표 거리·제한 시간은 방 **생성·방장 수정 모두 아래 범위로 검증**한다. 저장은 **거리 meter · 시간 분**, 화면 표시는 **거리 km(소수 1자리) · 시간 분**이다. 프론트 입력도 km 소수 1자리 단위(=100m 스텝)로 받아 서버 전송 시 미터로 환산한다. 홈 방 목록 필터의 상한도 이 정책값에 맞춘다.\u000a\u000a| 방 조건 | 최소(하한) | 최대(상한) | 저장 단위 | 표시 단위 |\u000a| --- | --- | --- | --- | --- |\u000a| 목표 거리 | 0.1km (100m) | 100km (100,000m) | meter (int) | km · 소수 1자리 |\u000a| 제한 시간 | 5분 | 24시간 (1,440분) | 분 (int) | 분 |\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 MVP에서 하지 않는다.\u000a> - 약관 원문(법무 문안) 작성 자체 — 법무/운영 영역, 기획은 동의 흐름·데이터만 다룸\u000a> - 만 14세 미만 연령 확인·법정대리인 동의 — 이번 MVP에서 제외\u000a> - 계정 정지(suspended)·이탈(exited)의 운영 도구/자동화 — 상태값·전이는 정의하되, 제재 콘솔·휴면 배치 등 운영 기능은 이후로 미룸\u000a> - 소셜 기능 (친구, 팔로우, 채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a\u000a> ➡️ **2차 이관** — 아래 항목은 「2차 MVP 기획서」로 옮겼다: 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시 · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지(GPS 스푸핑·차량 이동 탐지) · GPS 튐 보정 · 개인정보 관리 화면(동의 철회·다운로드).\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | Flutter 단일 코드베이스로 Android / iOS 동시 지원 |\u000a| 실시간성 | 리더보드/위치 동기화 지연 수 초 이내 (WebSocket) |\u000a| 개인정보/약관 | 필수 약관 동의 없이는 서비스 이용 불가. 동의 이력(약관 유형·버전·동의 시각)을 보관하고 개인정보보호법·위치정보법을 준수 |\u000a| 위치 권한 | 위치 권한(백그라운드 포함)은 필수. 거부 시 앱 사용 불가 처리 |\u000a| 위치 정확도 | GPS 이동 거리 오차 허용 범위 내, 백그라운드 위치 추적 지원 |\u000a| 데이터 단위 규약 | 거리는 **meter(int)**, 시간은 **분(int)** 로 저장·전송한다. 표시(입력·출력)는 거리 **km 소수 1자리**, 시간 **분**. 클라이언트가 km↔m 환산을 책임진다 |\u000a| 안정성 | 방 생성 → 경주 완료까지 크래시 없이 완주 가능 |\u000a| 복원력 | 러닝 중 네트워크 단절 시 재연결·거리 재동기화 처리 |\u000a| 인증/보안 | OAuth 기반 소셜 로그인 (카카오/구글/애플) |\u000a| 배터리 | 지속 GPS 추적에도 실사용 가능한 배터리 소모 수준 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 온보딩 완료율 | 로그인 사용자의 90% 이상이 약관 동의·닉네임 설정까지 완료(status=active) | 온보딩 단계별 이벤트 로그 |\u000a| 온보딩 재개 성공률 | 온보딩 중단(status=onboarding) 사용자의 재로그인 시 이어서 완료하는 비율 | status 전이 로그 |\u000a| 경주 완주율 | 시작한 경주의 95% 이상 크래시 없이 결과 도달 | 세션 로그/크래시 리포트 |\u000a| 리더보드 동기화 지연 | 평균 3초 이내 | 서버-클라이언트 타임스탬프 비교 |\u000a| 거리 측정 오차 | 실측 대비 ±5% 이내 | 기준 코스 실측 테스트 |\u000a| 리텐션(참고) | 첫 경주 후 재참여율 측정 | 사용자별 경주 참여 이벤트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 소셜 로그인 | 앱 실행 → 카카오/구글/애플 중 선택 → 인증 | 로그인 성공, 첫 로그인이면 계정 즉시 생성(status=onboarding) |\u000a| 2 | 최초 온보딩 | 최초 로그인 → 필수 약관 전체 동의 + 닉네임 입력 → 완료 | 홈 진입, 동의 이력 저장, status=active |\u000a| 3 | 필수 약관 미동의 | 온보딩에서 필수 약관 일부 미동의 상태로 진행 시도 | 진행 버튼 비활성/차단, 진입 불가 |\u000a| 4 | 재로그인 스킵 | 이미 온보딩 완료(status=active)한 사용자가 재로그인 | 온보딩 생략, 곧바로 홈 |\u000a| 5 | 온보딩 중단 후 재개 | 첫 로그인 후 온보딩 미완료 상태로 앱 종료 → 재로그인 | 계정이 새로 생기지 않고 기존 계정(status=onboarding) 매칭, 온보딩을 이어서 진행 |\u000a| 6 | 약관 개정 재동의 | 필수 약관 개정(새 버전) 후 기존 사용자 로그인 | 변경된 약관만 재동의 화면 노출, 동의 후 진입 |\u000a| 7 | 방 생성·입장 | 홈 → 방 생성(거리·시간·정원 입력) → 다른 사용자 입장 | 대기실에 현 인원/정원·참가자 반영, 모집 중 상태 |\u000a| 8 | 방장 조건 수정·강퇴 | 모집 중 방장이 목표 거리 변경, 참가자 강퇴 | 변경 즉시 반영(페이스 재계산), 강퇴된 사용자 방에서 제거 |\u000a| 9 | 지각 입장 차단 | 모집 마감/경기 중 방에 입장 시도 | 입장 거부 |\u000a| 10 | 자동 취소 | 시작 10분 전(모집 마감) 참가자 1명 | 경주 취소, 참가자에 취소 안내 |\u000a| 11 | 동시 스타트 | 2명 이상 유지 → 시작 시간 도달 | 경기 시작, 참가자 전원 동시 스타트 |\u000a| 12 | 실시간 경주 | 각자 러닝 → 거리 누적 전송 | 리더보드에 실시간 순위·거리 갱신 |\u000a| 13 | 등수 판정 (공동 순위) | 참가자들이 목표 거리 도달, 일부 동시 도달 | 도달 순 등수 확정, 동시 도달자는 공동 순위 |\u000a| 14 | 제한 시간 만료·이탈 | 목표 미도달 또는 중도 이탈 상태로 종료 | 완주자 뒤로 누적 거리순 정렬, 경주 종료 |\u000a| 15 | 경주 이력 확인 | 종료 후 사용자 경주 이력 진입 | 최종 등수·개인 기록(거리/시간/페이스) 표시 |\u000a| 16 | 위치 권한 거부 | 위치 권한 거부/미허용 | 앱 사용 불가 안내 화면 |\u000a| 17 | 방 조건 범위 검증 | 방 생성/수정에서 목표 거리 100km 초과 또는 0.1km 미만, 제한 시간 24시간 초과 또는 5분 미만 입력 | 범위 밖 값은 저장 차단(안내 메시지), 범위 내 값만 생성/수정 성공 |\u000a| 18 | 거리 단위 표시·환산 | 목표 거리 3.5km로 방 생성 → 대기실·목록·수정 화면 확인 | 입력·표시는 km 소수 1자리(3.5km), 서버 저장/전송은 3,500m로 일관 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> ✅ **확정** — 약관 구성: 필수 = 서비스 이용약관 · 개인정보 수집·이용 동의 · 위치기반서비스 이용약관 / 선택 = 마케팅 정보 수신. (만 14세 이상 확인 제외) · 약관은 **버전 단위로 관리**하고, 개정 시 **변경된 약관만 재동의**. 관련 도메인(Agreement / UserConsent) 정의 완료.\u000a\u000a> ✅ **확정 (온보딩 계정 생명주기)** — 로그인과 온보딩을 분리한다. **첫 로그인 시점에 User를 즉시 생성**(status=onboarding, nickname은 null 허용)하고, 닉네임 설정 + 필수 약관 동의를 모두 마치면 **status=active**로 전이한다. 온보딩을 중단해도 계정은 남으므로, 재로그인 시 providerKey(UQ)로 기존 계정을 찾아 **온보딩을 이어서 진행**한다(계정 중복 생성 없음). 이후 상태는 active ↔ suspended(이용 정지) / active ↔ exited(탈퇴·이탈)로 전이하며, 정지 해제·복귀 시 다시 active로 회귀한다. → 상태 흐름은 User 도메인 lifecycle 참조.\u000a\u000a> ✅ **확정 (방 조건 범위·단위)** — 방 목표 거리·제한 시간의 허용 범위와 단위를 확정한다. **거리 0.1km(100m) ~ 100km, 시간 5분 ~ 24시간(1,440분).** 저장은 거리 meter·시간 분, 표시는 거리 km(소수 1자리)·시간 분. **방 생성·방장 수정 모두 동일 상·하한을 검증**한다. 이 정책으로 기존 미결이던 "홈 방 목록 필터 거리·시간 상한(하드코딩 12km/120분)"을 대체한다 → 이슈 `[Room] 방 목록 필터 거리·시간 상한 정책 확정 및 반영`.\u000a\u000a> 📝 **가정 / 미결** — 확정 안 된 사항 및 의도적 단순화. 착수 전 인지 필요.\u000a> - **약관 원문 확보(미결)**: 실제 약관 문안은 법무 검토 필요 — 기획은 흐름/데이터만 정의.\u000a> - **클라이언트 판정의 신뢰성(의도적 단순화)**: MVP는 목표 도달을 클라이언트 GPS 계산으로 판정하고 GPS 튐도 무시한다. 서버 검증·부정행위 방지·GPS 보정은 2차에서 보완.\u000a> - **백엔드 스택 미정**: 서버 언어/프레임워크, WebSocket 서버, DB 선정 필요.\u000a> - **거리 측정 방식**: 순수 GPS 누적 vs 스텝/센서 융합 — 정확도/배터리 트레이드오프.\u000a> - **동시 시작 정합성**: startTime 기준 클라이언트 시계 오차 보정 방식.\u000a> - **백그라운드 추적 정책**: iOS/Android 백그라운드 위치 권한·배터리 정책 대응.\u000a> - **suspended/exited 운영 트리거(미결)**: 정지·이탈을 유발하는 실제 조건(제재 정책, 휴면 기준)·복귀 절차는 이후 운영 정책에서 확정 — 1차는 상태·전이만 모델링.\u000a> - **가정**: 애플 로그인 포함으로 iOS 소셜 로그인 심사 요건(Sign in with Apple 병행 제공) 충족.\u000a\u000a---\u000a### 진행 메모 (2026-07-09) — 1차 확정 스코프\u000a\u000a**입장 / 재동의**\u000a- 방 입장은 **공개 방 목록 입장 전용** (초대 코드·비공개 방 없음 — Room에 inviteCode 미도입).\u000a- 약관 **개정 재동의는 프로필 화면**에서 처리 (온보딩과 별도). `data-screen=profile`, `[Onboarding] 약관 버전 관리·재동의` 이슈를 profile에 연동.\u000a\u000a**경주 실행 (에픽 A~D)**\u000a- **판정 = 서버 릴레이(클라이언트 판정)**: 각 클라이언트가 GPS로 거리·목표 도달을 계산해 전송, 서버는 재계산 없이 도달/진행 순서만 확정. **원시 GPS 좌표 미보존**(TrackPoint 미도입) — 진행값은 `Participant.currentDistance`로만 전송.\u000a- **동시 스타트 = 서버 시각 기준**: 서버가 "start at T / ends at T+limit" 신호를 WS로 브로드캐스트, 클라이언트는 서버 시각 오프셋으로 카운트다운·종료.\u000a- **미완주·중도 이탈·앱 강제 종료 = dnf** → 완주자 뒤 누적 거리순.\u000a- **단일 기기 전제**(멀티기기 미지원), **푸시 알림 없음** → 대기실에서 앱을 열어둔 채 카운트다운하는 흐름을 전제로 한다.\u000a\u000a**2차로 이관됨** (→ 「2차 MVP 기획서」): 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시(TrackPoint 재도입) · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지 · GPS 튐 보정 · 개인정보 관리 화면.\u000a\u000a---\u000a### 진행 메모 (2026-07-13) — 온보딩 계정 생명주기 반영\u000a\u000a- **로그인 ↔ 온보딩 분리**: 첫 로그인 시 User를 먼저 생성(status=onboarding, nickname null 허용). 온보딩 완료(닉네임+필수약관) 시 status=active. 중단해도 계정 유지 → 재로그인 시 providerKey로 매칭해 온보딩 재개(중복 계정 없음).\u000a- **User.status 생명주기**: `onboarding → active`, 이후 `active ↔ suspended`(이용 정지/해제), `active ↔ exited`(탈퇴·이탈/복귀). User 도메인 lifecycle에 상태 흐름도 반영 완료.\u000a- **도메인 변경**: User.nickname NN 해제(온보딩 전 null), status 컬럼 추가. `isOnboarded`/`onboardingCompletedOn`은 status로 대체하여 미도입.\u000a- **이슈**: `[Onboarding] 최초 온보딩 · 약관 동의` 에픽 아래 **`[Onboarding] 계정 선-생성 & 온보딩 재개 (User.status)`** 하위 이슈 추가. `[Auth] 로그인 세션·토큰 관리 및 신규/기존 분기`의 분기 기준을 온보딩 완료 여부 → **User.status(onboarding/active)** 로 명확화.\u000a\u000a---\u000a[도메인 결정] 2026-07-15 — Participant.status에서 `kicked` 제거\u000a\u000a- 강퇴(방장의 참가자 추방)는 상태 전이(status=kicked)가 아니라 **참가자 row 삭제(관계 orphan delete)** 방식으로 확정. 대기실은 recruiting 단계라 보존할 이력이 없어, 자발적 이탈(exit)과 동일하게 삭제로 통일한다.\u000a- `ParticipantStatus`에서 `KICKED` enum 제거(참조 0건). DB는 마이그레이션 `RemoveParticipantKickedStatus`로 participant.status enum을 (''joined'',''running'',''finished'',''dnf'')로 변경.\u000a- 최종 ParticipantStatus = joined / running / finished / dnf.\u000a- 관련 이슈: [Room] 대기실 · 방장 관리(cmrc5zgsk000x1zkpv5st1x6l). 남은 작업: mobile 강퇴 서버 연동, 방 조건 수정 PUT /rooms/:id 구현.\u000a\u000a---\u000a### 진행 메모 (2026-07-15) — 방 조건(거리·시간) 범위·단위 확정\u000a\u000a- **정책 확정**: 방 목표 거리 **0.1km(100m) ~ 100km**, 제한 시간 **5분 ~ 24시간(1,440분)**. 방 생성·방장 수정 모두 동일 상·하한 검증.\u000a- **단위**: 저장 = 거리 **meter(int)** · 시간 **분(int)**. 표시 = 거리 **km(소수 1자리)** · 시간 **분**. 프론트 입력도 km 소수 1자리(=100m 스텝) → 서버 전송 시 ×1000으로 미터 환산.\u000a- **연쇄 영향**:\u000a  - 기존 미결(홈 방 목록 필터 상한 하드코딩 12km/120분)을 이 정책값(100km·1,440분)으로 대체 → 이슈 `[Room] 방 목록 필터 거리·시간 상한 정책 확정 및 반영`(cmrkb1wcp) 해소 방향.\u000a  - core-api 방 생성/수정 검증 보강 필요: 현재 `Room.create`/`Room.changeSetting`은 `>0`만 검증 → **상한(100km·1,440분)·하한(0.1km·5분) 추가** 필요. DTO에도 min/max 반영.\u000a  - 도메인 문서(Room)·와이어프레임(`room-create`, `home` 필터)·이슈에 순차 반영.\u000a- **관련 도메인**: Room(goalDistanceMeter, goalLimitMinutes).'),'approved',16,'cmrmtwkk30001rwgnoiejp8hz',1783507196537,1784165217562);
INSERT INTO "Plan" VALUES('cmrcstk4t0015rwt4x4tn1p3s','cmrby3y0000001znnofoo0a53','2차 MVP 기획서',unistr('# 추노 — 2차 MVP\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 1차 MVP에서 "한 사이클 완주"를 위해 의도적으로 미뤄둔 항목들을 채워, **여러 기기에서·앱을 닫아둔 채로도 경주가 매끄럽게 성립하고, 결과를 신뢰할 수 있는** 서비스로 끌어올린다.\u000a\u000a1차 MVP는 소셜 로그인 → 온보딩 → 방 → 실시간 경주 → 등수 → 결과의 한 사이클을 단일 기기·앱 포그라운드·클라이언트 판정 전제로 완주시키는 데 집중했다. 2차는 그 전제에서 생긴 UX·신뢰성 공백을 메운다: **푸시 알림**으로 예약 스타트를 앱을 닫아둔 채로도 놓치지 않게 하고, **멀티기기**를 지원하며, **진행 중 경주 복귀**로 러닝 도중 앱이 죽어도 이어달릴 수 있게 하고, **서버 재검증·부정행위 방지·GPS 보정**으로 결과의 공정성을 높인다. 여력에 따라 **경주 중 지도·경로 표시**와 **개인정보 관리 화면**을 더한다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 예약 경주 참가자 | 시작 시각까지 앱을 계속 켜두기 번거로움 | 방 예약 후 앱을 닫아둬도 시작 임박·시작 푸시를 받고 제때 합류한다 |\u000a| 여러 기기 사용자 | 폰 교체·태블릿 병행 | 새 기기에서 로그인해도 동일 계정으로 이어 쓰고, 알림은 현재 쓰는 기기로 온다 |\u000a| 장거리 러너 | 러닝 중 앱이 죽으면 기록이 날아갈까 불안 | 앱이 강제 종료돼도 재실행하면 진행 중 경주로 자동 복귀해 이어 달린다 |\u000a| 공정성을 중시하는 경쟁자 | 치팅·GPS 튐으로 순위가 왜곡되는 게 싫음 | 서버가 도달을 재검증하고 이상 이동을 걸러 신뢰할 수 있는 등수를 받는다 |\u000a| 개인정보 민감 사용자 | 동의 철회·내 데이터 관리를 원함 | 설정에서 약관 동의를 철회하거나 내 데이터를 내려받는다 |\u000a\u000a## 3. 핵심 기능 (2차)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 푸시 알림 | 시작 임박(모집 마감=시작 10분 전) / 시작(live) / 종료(finished) 3종 푸시. 예약 스타트를 앱을 닫아둔 채로도 놓치지 않게 한다. FCM/APNs 연동 |\u000a| 높음 | 멀티기기 지원 | 사용자 1명이 여러 기기에서 로그인·사용. 기기별 세션과 **기기별 푸시 토큰** 관리(로그인/권한 시 등록·갱신, 로그아웃 시 해지) |\u000a| 보통 | 진행 중 경주 복귀 | 앱 강제 종료 후 재실행 시 진행 중인 경주로 자동 복귀. 로컬 저장(마지막 누적 거리·경주 식별자)+서버 재동기화 |\u000a| 보통 | 서버 측 목표 도달 재검증 | 클라이언트 판정을 서버가 재검증(전송 거리·페이스·타임스탬프 정합성)해 등수 신뢰도를 높인다 |\u000a| 보통 | 부정행위 방지 | GPS 스푸핑·비정상 속도(차량 이동 등) 탐지 및 처리(경고·기록 무효). MVP는 클라 판정이라 열려 있던 부분 |\u000a| 보통 | GPS 튐 보정 | 순간 거리 급증(정확도 낮은 포인트) 필터링·스무딩으로 거리 오차를 줄인다 |\u000a| 보통 | 개인정보 관리 화면 | 약관 동의 철회, 내 데이터 다운로드/삭제 요청 등 개인정보 관리 진입점(개인정보보호법 대응 강화) |\u000a| 낮음 | 경주 중 지도·경로 표시 | 러닝 화면에 본인 경로/지도를 표시. 이를 위해 GPS 좌표 보존(TrackPoint 재도입) |\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 2차에서도 하지 않는다 (3차 이후 검토).\u000a> - 소셜 기능 (친구·팔로우·채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a> - 만 14세 미만 연령 확인·법정대리인 동의\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 알림 | 푸시 발송 지연 수십 초 이내, 미수신 시 앱 진입 시 상태 동기화로 보완 |\u000a| 멀티기기 | 기기별 토큰 유일성 관리, 로그아웃/기기 해지 시 해당 토큰으로 발송 중단 |\u000a| 복원력 | 앱 강제 종료·네트워크 단절 후에도 진행 중 경주 상태 복구, 로컬-서버 거리 정합 |\u000a| 판정 신뢰성 | 서버 재검증으로 클라이언트 조작·이상치의 순위 반영 최소화 |\u000a| 위치 정확도 | GPS 튐 보정 적용 후 거리 오차 실측 대비 ±3% 이내(1차 ±5%에서 강화) |\u000a| 개인정보 | 동의 철회·데이터 열람/삭제 요청 처리 흐름 및 이력 보관 |\u000a| 플랫폼 | 1차와 동일하게 Flutter 단일 코드베이스로 Android/iOS 동시 지원 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 예약→시작 합류율 | 예약자의 85% 이상이 시작 시각에 경주 합류 | 푸시 발송/오픈·경주 합류 이벤트 |\u000a| 푸시 오픈율 | 시작 임박 푸시 오픈율 50% 이상 | 푸시 오픈 이벤트 |\u000a| 경주 복귀 성공률 | 러닝 중 앱 종료 케이스의 90% 이상 정상 복귀 | 복귀 시도/성공 로그 |\u000a| 판정 이의 감소 | 부정·오측 관련 이슈 리포트 1차 대비 50% 감소 | 신고/문의 집계 |\u000a| 거리 측정 오차 | 실측 대비 ±3% 이내 | 기준 코스 실측 테스트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 시작 임박 푸시 | 방 예약 → 앱 백그라운드/종료 → 시작 10분 전 도달 | 시작 임박 푸시 수신, 탭 시 대기실 진입 |\u000a| 2 | 시작/종료 푸시 | 경주 시작(live)·종료(finished) 시점 도달 | 각 시점 푸시 수신 |\u000a| 3 | 멀티기기 로그인 | 기기 A 로그인 사용 → 기기 B 로그인 | 두 기기 동일 계정, 각 기기 토큰 등록 |\u000a| 4 | 기기 해지 알림 중단 | 기기 A 로그아웃 | A 토큰 해지, 이후 알림 A로 미발송 |\u000a| 5 | 경주 복귀 | 러닝 중 앱 강제 종료 → 재실행 | 진행 중 경주로 자동 복귀, 누적 거리 재동기화 |\u000a| 6 | 서버 재검증 | 클라가 비정상 거리 급증 전송 | 서버가 이상치 반려/보정, 순위 미반영 |\u000a| 7 | 부정행위 탐지 | GPS 스푸핑·차량 속도 패턴 주입 | 탐지·경고 또는 기록 무효 처리 |\u000a| 8 | GPS 튐 보정 | 정확도 낮은 튐 포인트 포함 러닝 | 보정 후 거리 오차 ±3% 이내 |\u000a| 9 | 지도·경로 표시 | 러닝 중 지도 화면 진입 | 본인 경로 실시간 표시(TrackPoint 기반) |\u000a| 10 | 동의 철회 | 개인정보 관리 화면에서 동의 철회 | 철회 처리·이력 저장, 정책상 후속 안내 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> 📝 **가정 / 미결** — 착수 전 인지 필요.\u000a> - **1차 완료 전제**: 2차는 1차 MVP(로그인·온보딩·방·경주 실행)가 동작하는 상태 위에 얹는다.\u000a> - **도메인 변경(가정)**: 멀티기기·푸시를 위해 **Device(또는 PushToken) 도메인 신규**, 지도 표시를 위해 **TrackPoint 도메인 재도입**이 필요. 도메인 확정은 `/ib-domain`에서.\u000a> - **판정 모델 전환(미결)**: 1차의 "서버 릴레이(클라 판정)"에서 2차의 "서버 재검증"으로 이동. 재검증 강도(정합성 체크 수준 vs 완전 재계산)와 클라-서버 판정 충돌 시 우선순위 규칙 미정.\u000a> - **부정행위 정책(미결)**: 탐지 후 처리(경고/무효/제재) 수위와 오탐 대응 기준 미정.\u000a> - **푸시 인프라(미결)**: FCM/APNs 프로젝트·인증서 셋업, 백엔드 발송 파이프라인 스택 미정.\u000a> - **복귀 범위(미결)**: 얼마나 오래 끊겨도 복귀 허용할지(종료 시각 경과·이탈 판정과의 관계) 미정.\u000a> - **개인정보 관리 범위(미결)**: 열람/삭제/철회 중 2차 포함 범위와 법무 검토 필요.\u000a'),'draft',1,'cmrmtwkk30001rwgnoiejp8hz',1783558735661,1784165217562);
INSERT INTO "Plan" VALUES('cmrmrup9j001frwz8i9v8o7pn','cmrby3y0000001znnofoo0a53','백오피스 1차 기획서',unistr('# 추노 백오피스\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 추노 앱의 사용자·방(경주)·약관·운영 지표를 **사내 관리자가 한 곳에서 조회·관리**하는 웹 백오피스.\u000a\u000a앱이 운영되면서 CS 대응, 사용자 제재, 약관 개정, 경주 상태 확인 등을 **DB 직접 조작 없이** 처리할 관리 도구가 필요하다. 1차 백오피스는 **조회 + 핵심 관리 액션**(사용자 상태 변경·방 강제 취소·약관 버전 활성화)에 집중한다. 기술적으로는 모노레포의 `apps/back-office`(React + Vite + TS)를 사용하고, core-api에 **관리자 전용 API(`/admins/*`)** 를 추가해 앱 유저 API와 분리한다. 관리자 계정은 앱 사용자(User)와 별개(`Admin`)로 관리하며, **1차는 자체 이메일/비밀번호 로그인**(2차에서 구글 로그인)으로 인증한다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a> 📌 **단일 역할** — 1차 백오피스의 사용자는 **관리자(Admin) 한 종류**다. 세분화된 역할(RBAC)은 두지 않으며, 모든 관리자가 동일 권한을 갖는다. 역할 분리는 이후 버전에서 검토.\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 관리자(Admin) | 서비스 운영·CS·정책 관리를 코드 없이 처리 | 사용자 검색·상태(정지/해제) 변경, 문제 방 강제 취소, 약관 새 버전 등록·활성화, 운영 지표 확인 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 관리자 인증 | 관리자 전용 로그인(앱 유저와 분리). **1차: 자체 이메일/비밀번호 + JWT** (2차: 구글 로그인). 단일 역할이라 별도 권한 분기 없음 |\u000a| 높음 | 운영 대시보드 | 가입자 수·활성 방 수·진행/종료 경주·완주율 등 핵심 지표 요약 카드 |\u000a| 높음 | 사용자 관리 | 사용자 목록/검색/상세, 계정 상태(active/suspended/exited) 변경, 닉네임·가입 정보·제재 이력 확인 |\u000a| 높음 | 방(경주) 관리 | 방 목록/상세/상태 모니터링(recruiting~finished), 문제 방 **강제 취소·종료**, 참가자 확인. **종료(finished) 방은 상세에서 참가자 결과(등수·거리·시간·페이스)를 조회** (별도 결과 페이지 없이 방 상세에 통합) |\u000a| 높음 | 약관 관리 | Agreement 버전 등록·수정, **활성화/보관**(타입당 active 1개 불변식), 사용자 동의 현황 확인 |\u000a| 낮음 | 관리자 계정 관리 | 관리자 계정 추가·비활성화 (역할 구분 없음, 동일 권한) |\u000a\u000a> 📌 **참고** — 각 기능 행이 이후 이슈(에픽) 분리의 단위다. 사용자(User)·방(Room)·참가자(Participant)·약관(Agreement)은 **기존 앱 도메인을 재사용**하고, 백오피스 전용으로 **Admin**(관리자 계정) 하나를 신규 도출한다. 종료 경주 결과 조회는 별도 기능/화면을 두지 않고 **방(경주) 관리의 방 상세에 흡수**한다.\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 백오피스에서 하지 않는다.\u000a> - **세분 역할/권한(RBAC)** — 1차는 단일 관리자 역할, 모든 관리자 동일 권한\u000a> - **구글 로그인** — 2차 (1차는 자체 이메일/비밀번호)\u000a> - **감사 로그(Audit Log)** — 이후 검토 (1차 미포함)\u000a> - 실시간 경주 관제(라이브 위치 지도·리더보드 미러링) — 2차\u000a> - 자동 부정행위 탐지·룰 엔진 — 2차 (앱 부정행위 방지 자체가 2차 이관)\u000a> - 신고 접수 큐·워크플로 — 2차 (앱에 신고 기능 미도입)\u000a> - 푸시/이메일 발송 콘솔 — 2차\u000a> - 정산·결제·환불 — 서비스가 무료라 범위 밖\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | 웹 — `apps/back-office`(React + Vite + TS), 데스크톱 브라우저 우선 |\u000a| 인증/보안 | 관리자 계정을 앱 User와 **분리**(`Admin`), 자체 이메일/비번 + JWT. `/admins/*` 는 관리자 가드로 보호. 단일 역할 |\u000a| 연동 | core-api 관리자 API(`/admins/*`) — 앱 유저 엔드포인트와 네임스페이스·가드 분리 |\u000a| 데이터 규모 | 사용자·방 목록은 **서버 페이지네이션·검색**, 조회 인덱스 활용 |\u000a| 지표 | 1차는 단순 집계 쿼리(실시간 정확도보다 운영 파악 우선) |\u000a| 언어 | 사내용 — 한국어 우선 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| DB 직접 조작 건수 | 0건 (운영 액션을 백오피스로 대체) | 운영 로그/인터뷰 |\u000a| CS 처리 리드타임 | 사용자 조회·조치 3분 이내 | 운영자 태스크 측정 |\u000a| 약관 개정 셀프서비스율 | 개발자 개입 없이 100% 백오피스에서 처리 | 약관 활성화 이력 |\u000a| 방 문제 대응 | 문제 방을 백오피스에서 즉시 강제 취소 | 방 상태 전이 이력 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 관리자 로그인 | 관리자 이메일/비밀번호로 로그인 | 로그인 성공·백오피스 진입, 미인증 시 차단 |\u000a| 2 | 사용자 정지·해제 | 사용자 검색 → 상세 → 정지(suspended) → 해제(active) | 상태 전이가 반영됨 |\u000a| 3 | 방 강제 취소 | 진행 전 방 상세 → 강제 취소 | 방 status=cancelled, 참가자에 반영 |\u000a| 4 | 약관 신규 버전 활성화 | 약관 새 버전 등록 → 활성화 | 새 버전 active, 이전 버전 archived(타입당 active 1개 유지) |\u000a| 5 | 대시보드 지표 | 대시보드 진입 | 가입자·활성 방·완주율 등 핵심 지표가 집계 표시 |\u000a| 6 | 경주 결과 조회 | 방 관리 목록에서 종료(finished) 방 → 방 상세 진입 | 참가자 등수·거리·시간·페이스가 방 상세에 표시 |\u000a| 7 | 관리자 계정 추가 | 관리자 계정 추가 → 로그인 | 신규 관리자 생성·로그인 가능 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> 📝 **가정 / 미결** — 초안 단계의 가정과 열린 질문. 체크포인트에서 조정.\u000a> - **(확정) 관리자 계정 분리** — 앱 `User`와 별개 `Admin` 테이블. 초기 관리자는 시드로 생성.\u000a> - **(확정) 단일 역할** — 1차는 모든 관리자가 동일 권한(RBAC·operator/superadmin 구분 없음).\u000a> - **(확정) 인증** — 1차 자체 이메일/비밀번호 + JWT, 2차 구글 로그인.\u000a> - **(확정) API prefix** — 관리자 API는 `/admins/*` 네임스페이스, 관리자 가드로 보호.\u000a> - **(확정) 감사 로그 미포함** — 1차 범위 밖(이후 검토).\u000a> - **(확정) 경주 결과 조회 위치** — 별도 결과 페이지/API(`/admins/races`)를 두지 않고, 방 상세 API(`GET /admins/rooms/:id`)와 방 상세 화면(room-detail)에 흡수. 종료 방은 방 목록 status=finished 필터로 탐색.\u000a> - **(가정) 신규 도메인** — `Admin` 1개. (User/Room/Participant/Agreement는 재사용)\u000a> - **(미결) 지표 소스** — 실시간 집계 vs 배치. 1차는 단순 쿼리 집계.\u000a> - **(미결) 제재 정책 연계** — User.status의 suspended/exited 운영 트리거(제재 기준)는 앱 기획서 §8에서도 미결 — 백오피스는 "수동 상태 변경 도구"까지만 제공.\u000a\u000a---\u000a[2026-07-16] 경주 이력·결과 조회 → 방(경주) 관리로 흡수. 별도 "경주 결과 조회" 기능/화면/API를 두지 않기로 결정. 변경: §3 기능표에서 "경주 이력·결과 조회" 행 삭제, 방 관리 행에 종료 방 결과 조회 통합. 이슈: BO-22(종료 경주 결과 API) 삭제 완료, BO-6(에픽)·BO-23(결과 화면) 삭제 예정. BO-16(방 상세 API)·BO-18(방 상세 화면)에 종료(finished) 방 참가자 결과(등수·거리·시간·페이스) 조회를 흡수. 종료 방 탐색은 방 목록 status=finished 필터 사용.'),'draft',4,'cmrmtwkk80003rwgnkid249iz',1784161771089,1784186029181);
INSERT INTO Wireframe VALUES('cmrc09bag00091z187dj593eb','cmrby3y0000001znnofoo0a53','로그인','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap)}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a</style></head>\u000a<body data-screen="login">\u000a<div class="wf">\u000a <header class="wf-topbar">추노</header>\u000a <main class="wf-body" style="justify-content:center;text-align:center">\u000a   <div class="wf-ph" style="width:96px;height:96px;border-radius:24px;margin:0 auto"></div>\u000a   <div class="wf-title">장소 무관 경쟁 러닝</div>\u000a   <div class="wf-sub">방을 만들어 목표 거리를 먼저 완주하세요</div>\u000a   <div style="height:16px"></div>\u000a   <button class="wf-btn" data-p="카카오">카카오로 시작</button>\u000a   <button class="wf-btn" data-p="구글">구글로 시작</button>\u000a   <button class="wf-btn" data-p="Apple">Apple로 시작</button>\u000a   <div id="msg" class="wf-sub" style="min-height:18px"></div>\u000a </main>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''[data-p]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''[data-p]'').forEach(function(x){x.classList.remove(''wf-btn-primary'')});\u000a    b.classList.add(''wf-btn-primary'');\u000a    var m=document.getElementById(''msg''),p=b.getAttribute(''data-p'');\u000a    m.textContent=p+'' 인증 중…'';\u000a    setTimeout(function(){m.textContent=p+'' 로그인 완료 ✓'';},700);\u000a  });\u000a});\u000a</script>\u000a</body></html>'),1,1,'cmrmtwkk30001rwgnoiejp8hz',1783510761832);
INSERT INTO Wireframe VALUES('cmrc0a433000d1z188fcz9jya','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-chip{border:1px solid var(--wf-line);border-radius:999px;padding:6px 12px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <form class="wf-body" id="f">\u000a   <div class="wf-field"><span class="wf-label">방 제목</span><input class="wf-input" placeholder="예: 아침 3km 대결"></div>\u000a   <div class="wf-field"><span class="wf-label">목표 거리</span>\u000a     <div style="display:flex;gap:8px;flex-wrap:wrap" id="dist">\u000a       <button type="button" class="wf-chip" data-v="2">2km</button>\u000a       <button type="button" class="wf-chip on" data-v="3">3km</button>\u000a       <button type="button" class="wf-chip" data-v="5">5km</button>\u000a       <button type="button" class="wf-chip" data-v="10">10km</button>\u000a     </div>\u000a   </div>\u000a   <div class="wf-field"><span class="wf-label">제한 시간 (분)</span><input class="wf-input" type="number" value="30"></div>\u000a   <div class="wf-field"><span class="wf-label">시작 시간</span><input class="wf-input" placeholder="2026-07-09 07:00:00"></div>\u000a   <div class="wf-field"><span class="wf-label">최대 인원</span>\u000a     <div style="display:flex;align-items:center;gap:14px">\u000a       <button type="button" class="wf-btn" id="minus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:24px;text-align:center">6</b>\u000a       <button type="button" class="wf-btn" id="plus">+</button>\u000a     </div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" type="submit">방 개설</button>\u000a   <div class="wf-card" id="summary" style="display:none"></div>\u000a </form>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''#dist .wf-chip'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#dist .wf-chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    c.classList.add(''on'');\u000a  });\u000a});\u000avar cap=6,capEl=document.getElementById(''cap'');\u000adocument.getElementById(''plus'').onclick=function(){if(cap<20){cap++;capEl.textContent=cap;}};\u000adocument.getElementById(''minus'').onclick=function(){if(cap>2){cap--;capEl.textContent=cap;}};\u000adocument.getElementById(''f'').addEventListener(''submit'',function(e){\u000a  e.preventDefault();\u000a  var d=document.querySelector(''#dist .on'').getAttribute(''data-v'');\u000a  var s=document.getElementById(''summary'');\u000a  s.style.display=''block'';\u000a  s.innerHTML=''<b>개설 확인</b><div class="wf-sub">목표 ''+d+''km · 최대 ''+cap+''명 · 상태 모집 중으로 생성됩니다</div>'';\u000a});\u000a</script>\u000a</body></html>'),3,1,'cmrmtwkk30001rwgnoiejp8hz',1783510799151);
