x;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a.startin{font-size:11px;padding:2px 8px;border-radius:999px;border:1px solid var(--wf-line);color:var(--wf-ink);font-weight:600;white-space:nowrap}\u000a.rowtop{display:flex;justify-content:space-between;align-items:center;gap:8px}\u000a.meta{display:flex;justify-content:space-between;align-items:center;margin-top:4px;gap:8px}\u000a</style></head>\u000a<body data-screen="home">\u000a<div class="wf">\u000a <header class="wf-topbar">홈</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;align-items:center;justify-content:space-between">\u000a     <div class="wf-title">참여 가능한 방</div>\u000a     <button class="wf-btn" id="filter" style="padding:6px 10px;font-size:12px">모집 중만</button>\u000a   </div>\u000a   <div class="wf-list" id="rooms">\u000a     <div class="wf-card" data-status="recruiting" data-start="7800" style="cursor:pointer">\u000a       <div class="rowtop"><b>아침 3km 대결</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="meta"><span class="wf-sub">목표 3km · 30분 · 정원 2/6</span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="recruiting" data-start="2700" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>주말 10km 롱런</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="meta"><span class="wf-sub">목표 10km · 90분 · 정원 1/8</span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="recruiting" data-start="240" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>번개 2km 스프린트</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="meta"><span class="wf-sub">목표 2km · 20분 · 정원 3/5</span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="closed" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>퇴근런 5km</b><span class="wf-badge">모집 마감</span></div>\u000a       <div class="meta"><span class="wf-sub">목표 5km · 45분 · 정원 4/4</span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="live" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>새벽 3km</b><span class="wf-badge">경기 중</span></div>\u000a       <div class="meta"><span class="wf-sub">목표 3km · 30분 · 정원 5/5</span></div>\u000a     </div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" id="create">+ 방 만들기</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a <nav class="wf-tabbar"><button class="active">홈</button><button>이력</button><button>내 정보</button></nav>\u000a</div>\u000a<script>\u000a// 시작까지 남은 시간: 1시간 초과면 시간, 1시간 이내면 분 단위\u000afunction fmt(sec){\u000a  if(sec<=0) return ''곧 시작'';\u000a  if(sec>=3600){ return Math.floor(sec/3600)+''시간 후 시작''; }\u000a  return Math.ceil(sec/60)+''분 후 시작'';\u000a}\u000avar cards=[].slice.call(document.querySelectorAll(''#rooms .wf-card[data-start]''));\u000acards.forEach(function(c){ c._sec=parseInt(c.getAttribute(''data-start''),10); });\u000afunction paint(){ cards.forEach(function(c){ c.querySelector(''.startin'').textContent=fmt(c._sec); }); }\u000apaint();\u000asetInterval(function(){ cards.forEach(function(c){ if(c._sec>0) c._sec--; }); paint(); },1000);\u000a\u000avar onlyRec=false;\u000adocument.getElementById(''filter'').addEventListener(''click'',function(){\u000a  onlyRec=!onlyRec; this.classList.toggle(''wf-btn-primary'',onlyRec);\u000a  document.querySelectorAll(''#rooms .wf-card'').forEach(function(c){\u000a    c.style.display=(onlyRec && c.getAttribute(''data-status'')!==''recruiting'')?''none'':'''';\u000a  });\u000a});\u000adocument.querySelectorAll(''#rooms .wf-card'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#rooms .wf-card'').forEach(function(x){x.style.borderColor=''var(--wf-line)''});\u000a    c.style.borderColor=''var(--wf-ink)'';\u000a  });\u000a});\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')});\u000a    b.classList.add(''active'');\u000a  });\u000a});\u000adocument.getElementById(''create'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 만들기 화면으로 이동 (별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),2,3,'cmrmtwkk30001rwgnoiejp8hz',1783511906475);
INSERT INTO Wireframe VALUES('cmrc10f56000t1z181j2kjee7','cmrby3y0000001znnofoo0a53','대기실','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.stats{display:flex;gap:8px}\u000a.stat{flex:1;border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:10px;text-align:center}\u000a.stat b{display:block;font-size:16px}\u000a.efield{display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:8px}\u000a.efield input{width:110px;text-align:right}\u000a</style></head>\u000a<body data-screen="waiting-room">\u000a<div class="wf">\u000a <header class="wf-topbar">← 대기실</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <div class="wf-title">아침 3km 대결</div><span class="wf-badge">모집 중</span>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">시작까지</div>\u000a     <div style="font-size:28px;font-weight:700" id="cd">09:58</div>\u000a   </div>\u000a   <div class="stats">\u000a     <div class="stat"><span class="wf-sub">목표 거리</span><b id="sGoal">3.0km</b></div>\u000a     <div class="stat"><span class="wf-sub">제한 시간</span><b id="sLimit">30분</b></div>\u000a     <div class="stat"><span class="wf-sub">완주 기준 페이스</span><b id="sPace">10''00"</b><span class="wf-sub">/km</span></div>\u000a   </div>\u000a   <div class="wf-sub" style="margin-top:-4px">제한 시간 내 완주하려면 평균 <span id="paceInline">10''00"</span>/km 이상 유지해야 합니다.</div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-label">참가자</span><span class="wf-sub" id="count">3 / 6</span>\u000a   </div>\u000a   <div class="wf-list" id="plist">\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><b style="flex:1">나 (방장)</b><span class="wf-badge">HOST</span></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_김</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_이</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a   </div>\u000a   <button class="wf-btn" id="editToggle">조건 수정 (방장)</button>\u000a   <div class="wf-card" id="editBox" style="display:none">\u000a     <div class="wf-label" style="margin-bottom:8px">조건 수정 — 모집 중에만 가능</div>\u000a     <div class="efield"><span>목표 거리 (km)</span><input class="wf-input" id="eGoal" type="number" step="0.5" value="3"></div>\u000a     <div class="efield"><span>제한 시간 (분)</span><input class="wf-input" id="eLimit" type="number" value="30"></div>\u000a     <div class="efield"><span>최대 인원</span><input class="wf-input" id="eCap" type="number" value="6"></div>\u000a     <div class="wf-sub">→ 완주 기준 페이스 <b id="ePace">10''00"</b>/km</div>\u000a   </div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" disabled style="opacity:.6">시작 시간에 자동 시작</button>\u000a </main>\u000a</div>\u000a<script>\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000a// 평균(완주 기준) 페이스 = 제한시간 / 목표거리 → 분:초 per km\u000afunction pace(goalKm,limitMin){\u000a  if(!goalKm||goalKm<=0) return "--''--\\"";\u000a  var sec=Math.round(limitMin*60/goalKm);\u000a  return Math.floor(sec/60)+"''"+pad(sec%60)+''"'';\u000a}\u000afunction applyTop(goalKm,limitMin){\u000a  var p=pace(goalKm,limitMin);\u000a  document.getElementById(''sGoal'').textContent=goalKm.toFixed(1)+''km'';\u000a  document.getElementById(''sLimit'').textContent=limitMin+''분'';\u000a  document.getElementById(''sPace'').textContent=p;\u000a  document.getElementById(''paceInline'').textContent=p;\u000a}\u000aapplyTop(3,30);\u000a\u000a// 카운트다운\u000avar t=598,cd=document.getElementById(''cd'');\u000asetInterval(function(){ if(t>0){t--; cd.textContent=pad(Math.floor(t/60))+'':''+pad(t%60);} },1000);\u000a\u000a// 강퇴\u000afunction refresh(){ document.getElementById(''count'').textContent=document.querySelectorAll(''#plist .wf-list-item'').length+'' / ''+(document.getElementById(''eCap'').value||6); }\u000adocument.querySelectorAll(''.kick'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){ b.closest(''.wf-list-item'').remove(); refresh(); });\u000a});\u000a\u000a// 조건 수정 → 페이스 실시간 재계산\u000adocument.getElementById(''editToggle'').addEventListener(''click'',function(){\u000a  var e=document.getElementById(''editBox''); var open=e.style.display===''none'';\u000a  e.style.display=open?''block'':''none''; this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000afunction recalc(){\u000a  var g=parseFloat(document.getElementById(''eGoal'').value),l=parseFloat(document.getElementById(''eLimit'').value);\u000a  document.getElementById(''ePace'').textContent=pace(g,l);\u000a  if(g>0&&l>0) applyTop(g,l);\u000a  refresh();\u000a}\u000a[''eGoal'',''eLimit'',''eCap''].forEach(function(id){ document.getElementById(id).addEventListener(''input'',recalc); });\u000a</script>\u000a</body></html>'),4,2,'cmrmtwkk30001rwgnoiejp8hz',1783512026538);
INSERT INTO Wireframe VALUES('cmrc4vptd00131z187d1yy2m7','cmrby3y0000001znnofoo0a53','온보딩 (약관 동의)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:12px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-btn:disabled{opacity:.45;cursor:not-allowed}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.cbox{width:22px;height:22px;border:1px solid var(--wf-line);border-radius:6px;flex:0 0 auto;display:flex;align-items:center;justify-content:center;color:transparent;font-size:13px}\u000a.cbox.on{background:var(--wf-ink);border-color:var(--wf-ink);color:#fff}\u000a.allrow{display:flex;align-items:center;gap:10px;cursor:pointer;padding:2px 0}\u000a.allrow .txt{flex:1;font-weight:700}\u000a.agree{border-bottom:1px solid var(--wf-line)}\u000a.agree-row{display:flex;align-items:center;gap:10px;padding:12px 0;cursor:pointer}\u000a.agree-row .txt{flex:1}\u000a.tag{font-size:11px;font-weight:700;margin-right:4px}\u000a.req{color:var(--wf-ink)}\u000a.opt{color:var(--wf-muted)}\u000a.view{font-size:12px;color:var(--wf-ink);text-decoration:underline;background:none;border:none;cursor:pointer;flex:0 0 auto}\u000a.terms-body{display:none;background:var(--wf-fill);border-radius:8px;padding:10px;margin-bottom:12px}\u000a.hint{color:var(--wf-muted);font-size:12px;min-height:16px;text-align:center}\u000a</style></head>\u000a<body data-screen="onboarding">\u000a<div class="wf">\u000a <header class="wf-topbar">환영합니다 👋</header>\u000a <main class="wf-body">\u000a   <div>\u000a     <div class="wf-title">시작하기 전에</div>\u000a     <div class="wf-sub">닉네임을 정하고 약관에 동의해 주세요.</div>\u000a   </div>\u000a\u000a   <div>\u000a     <div class="wf-label" style="margin-bottom:6px">닉네임</div>\u000a     <input class="wf-input" id="nick" placeholder="예: 달리는너구리" maxlength="16">\u000a   </div>\u000a\u000a   <div class="wf-card">\u000a     <div class="allrow" id="all">\u000a       <span class="cbox" id="allbox">✓</span>\u000a       <span class="txt">약관 전체 동의</span>\u000a     </div>\u000a     <div class="wf-sub" style="margin-left:32px">필수·선택 약관에 모두 동의합니다.</div>\u000a   </div>\u000a\u000a   <div id="list">\u000a     <div class="agree" data-required="1">\u000a       <div class="agree-row"><span class="cbox">✓</span><span class="txt"><span class="tag req">[필수]</span>서비스 이용약관</span><button class="view">보기</button></div>\u000a       <div class="terms-body"><div class="wf-ph" style="height:8px;width:90%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:100%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:75%"></div></div>\u000a     </div>\u000a     <div class="agree" data-required="1">\u000a       <div class="agree-row"><span class="cbox">✓</span><span class="txt"><span class="tag req">[필수]</span>개인정보 수집·이용 동의</span><button class="view">보기</button></div>\u000a       <div class="terms-body"><div class="wf-ph" style="height:8px;width:85%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:100%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:60%"></div></div>\u000a     </div>\u000a     <div class="agree" data-required="1">\u000a       <div class="agree-row"><span class="cbox">✓</span><span class="txt"><span class="tag req">[필수]</span>위치기반서비스 이용약관</span><button class="view">보기</button></div>\u000a       <div class="terms-body"><div class="wf-sub" style="margin-bottom:6px">경주 중 실시간 위치·거리 수집에 대한 동의입니다.</div><div class="wf-ph" style="height:8px;width:95%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:70%"></div></div>\u000a     </div>\u000a     <div class="agree" data-required="0">\u000a       <div class="agree-row"><span class="cbox">✓</span><span class="txt"><span class="tag opt">[선택]</span>마케팅 정보 수신</span><button class="view">보기</button></div>\u000a       <div class="terms-body"><div class="wf-ph" style="height:8px;width:80%;margin-bottom:6px"></div><div class="wf-ph" style="height:8px;width:65%"></div></div>\u000a     </div>\u000a   </div>\u000a\u000a   <div style="flex:1"></div>\u000a   <div class="hint" id="hint">필수 약관 동의와 닉네임을 입력해야 시작할 수 있어요.</div>\u000a   <button class="wf-btn wf-btn-primary" id="go" disabled>시작하기</button>\u000a </main>\u000a</div>\u000a<script>\u000avar boxes=[].slice.call(document.querySelectorAll(''#list .agree''));\u000afunction setBox(agree,on){ agree.querySelector(''.cbox'').classList.toggle(''on'',on); }\u000afunction isOn(agree){ return agree.querySelector(''.cbox'').classList.contains(''on''); }\u000a\u000a// 개별 약관 체크 토글 (보기 버튼은 제외)\u000aboxes.forEach(function(a){\u000a  a.querySelector(''.agree-row'').addEventListener(''click'',function(e){\u000a    if(e.target.classList.contains(''view'')) return;\u000a    setBox(a,!isOn(a)); sync();\u000a  });\u000a  a.querySelector(''.view'').addEventListener(''click'',function(e){\u000a    e.stopPropagation();\u000a    var b=a.querySelector(''.terms-body'');\u000a    b.style.display=b.style.display===''block''?''none'':''block'';\u000a  });\u000a});\u000a\u000a// 전체 동의\u000adocument.getElementById(''all'').addEventListener(''click'',function(){\u000a  var target=!document.getElementById(''allbox'').classList.contains(''on'');\u000a  boxes.forEach(function(a){ setBox(a,target); });\u000a  sync();\u000a});\u000a\u000adocument.getElementById(''nick'').addEventListener(''input'',sync);\u000a\u000afunction sync(){\u000a  var allOn=boxes.every(isOn);\u000a  document.getElementById(''allbox'').classList.toggle(''on'',allOn);\u000a  var reqOk=boxes.filter(function(a){return a.getAttribute(''data-required'')===''1'';}).every(isOn);\u000a  var nickOk=document.getElementById(''nick'').value.trim().length>0;\u000a  var ok=reqOk&&nickOk;\u000a  document.getElementById(''go'').disabled=!ok;\u000a  document.getElementById(''hint'').textContent = ok ? ''모든 준비가 끝났어요!'' :\u000a    (!nickOk ? ''닉네임을 입력해 주세요.'' : ''필수 약관에 모두 동의해야 시작할 수 있어요.'');\u000a}\u000adocument.getElementById(''go'').addEventListener(''click'',function(){\u000a  document.getElementById(''hint'').textContent=''가입 완료 — 홈으로 이동합니다 ✓'';\u000a});\u000async();\u000a</script>\u000a</body></html>'),0,1,'cmrmtwkk30001rwgnoiejp8hz',1783518525554);
INSERT INTO Wireframe VALUES('cmrcs94hp0001rwt4l42lwizn','cmrby3y0000001znnofoo0a53','프로필','html',unistr('<style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow-y:auto}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit;text-align:center}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-avatar{width:80px;height:80px;border-radius:50%;background:var(--wf-fill);margin:0 auto}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;justify-content:space-between;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-between{display:flex;align-items:center;justify-content:space-between;gap:8px}\u000a.wf-alert{border:1px solid var(--wf-ink);border-radius:var(--wf-radius);padding:14px;display:flex;flex-direction:column;gap:10px}\u000a.wf-modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:center;justify-content:center;padding:24px}\u000a.wf-modal.show{display:flex}\u000a.wf-modal .wf-card{background:var(--wf-surface);width:100%;max-width:320px;display:flex;flex-direction:column;gap:12px}\u000a.wf-toast{position:absolute;left:50%;bottom:24px;transform:translateX(-50%);background:var(--wf-ink);color:#fff;padding:8px 14px;border-radius:999px;font-size:12px;opacity:0;transition:opacity .2s;pointer-events:none}\u000a.wf-toast.show{opacity:1}\u000a</style>\u000a<body data-screen="profile">\u000a  <div class="wf">\u000a    <header class="wf-topbar">← 프로필</header>\u000a    <main class="wf-body">\u000a      <div class="wf-avatar"></div>\u000a      <div style="display:flex;gap:8px;align-items:center;justify-content:center">\u000a        <input class="wf-input" id="nick" value="런너" style="max-width:180px" disabled>\u000a        <button class="wf-btn" id="edit">수정</button>\u000a      </div>\u000a\u000a      <div class="wf-alert" id="reconsent">\u000a        <div class="wf-between"><b>재동의가 필요한 약관</b><span class="wf-badge">1건</span></div>\u000a        <div class="wf-sub">위치기반서비스 이용약관이 <b style="color:var(--wf-ink)">v2</b>로 개정되었습니다. 계속 이용하려면 변경분에 재동의해 주세요.</div>\u000a        <button class="wf-btn wf-btn-primary" id="reBtn">변경 약관 보기 · 재동의</button>\u000a      </div>\u000a\u000a      <div style="font-weight:600;margin-top:4px">계정</div>\u000a      <div class="wf-list">\u000a        <div class="wf-list-item"><span>연결 계정</span><span class="wf-sub">카카오</span></div>\u000a        <div class="wf-list-item"><span>위치 권한</span><span class="wf-badge">허용됨 (백그라운드)</span></div>\u000a      </div>\u000a\u000a      <div style="font-weight:600;margin-top:4px">약관 · 개인정보</div>\u000a      <div class="wf-list">\u000a        <div class="wf-list-item"><span>서비스 이용약관</span><span class="wf-sub">v1 · 동의 ✓</span></div>\u000a        <div class="wf-list-item"><span>개인정보 수집·이용</span><span class="wf-sub">v1 · 동의 ✓</span></div>\u000a        <div class="wf-list-item"><span>위치기반서비스</span><span class="wf-badge">v2 · 재동의 필요</span></div>\u000a        <div class="wf-list-item"><span>마케팅 수신(선택)</span><span class="wf-sub">미동의</span></div>\u000a      </div>\u000a\u000a      <button class="wf-btn" id="logout">로그아웃</button>\u000a    </main>\u000a\u000a    <div class="wf-modal" id="reModal">\u000a      <div class="wf-card">\u000a        <div style="font-weight:700">위치기반서비스 이용약관 (v2)</div>\u000a        <div class="wf-card" style="max-height:160px;overflow-y:auto;background:var(--wf-fill);border:none;font-size:13px;color:var(--wf-muted)">개정 요지: 위치정보 보관 기간 및 제3자 제공 범위 관련 조항이 변경되었습니다. (본문 목업 — 법무 문안은 범위 밖)</div>\u000a        <label class="wf-between" style="justify-content:flex-start;gap:8px"><input type="checkbox" id="agree"> 위 변경 약관에 동의합니다 (필수)</label>\u000a        <div style="display:flex;gap:8px"><button class="wf-btn" id="reCancel" style="flex:1">나중에</button><button class="wf-btn wf-btn-primary" id="reOk" style="flex:1">재동의</button></div>\u000a      </div>\u000a    </div>\u000a\u000a    <div class="wf-modal" id="outModal">\u000a      <div class="wf-card">\u000a        <div style="font-weight:700">로그아웃 할까요?</div>\u000a        <div style="display:flex;gap:8px"><button class="wf-btn" id="outCancel" style="flex:1">취소</button><button class="wf-btn wf-btn-primary" id="outOk" style="flex:1">로그아웃</button></div>\u000a      </div>\u000a    </div>\u000a    <div class="wf-toast" id="toast"></div>\u000a  </div>\u000a  <script>\u000a    var toast=document.getElementById(''toast'');\u000a    function say(m){toast.textContent=m;toast.classList.add(''show'');setTimeout(function(){toast.classList.remove(''show'');},1500);}\u000a\u000a    var editing=false, nick=document.getElementById(''nick''), eb=document.getElementById(''edit'');\u000a    eb.addEventListener(''click'',function(){\u000a      editing=!editing; nick.disabled=!editing;\u000a      eb.textContent=editing?''저장'':''수정''; eb.classList.toggle(''wf-btn-primary'',editing);\u000a      if(editing) nick.focus(); else say(''닉네임 저장됨'');\u000a    });\u000a\u000a    var rm=document.getElementById(''reModal'');\u000a    document.getElementById(''reBtn'').addEventListener(''click'',function(){rm.classList.add(''show'');});\u000a    document.getElementById(''reCancel'').addEventListener(''click'',function(){rm.classList.remove(''show'');});\u000a    document.getElementById(''reOk'').addEventListener(''click'',function(){\u000a      if(!document.getElementById(''agree'').checked){ say(''필수 약관 동의가 필요합니다''); return; }\u000a      rm.classList.remove(''show'');\u000a      document.getElementById(''reconsent'').style.display=''none'';\u000a      say(''재동의 완료 (UserConsent 갱신)'');\u000a    });\u000a\u000a    var om=document.getElementById(''outModal'');\u000a    document.getElementById(''logout'').addEventListener(''click'',function(){om.classList.add(''show'');});\u000a    document.getElementById(''outCancel'').addEventListener(''click'',function(){om.classList.remove(''show'');});\u000a    document.getElementById(''outOk'').addEventListener(''click'',function(){om.classList.remove(''show'');});\u000a  </script>\u000a</body>\u000a'),8,1,'cmrmtwkk30001rwgnoiejp8hz',1783557782269);
INSERT INTO Wireframe VALUES('cmrcsoi4w0003rwt4q9qnay71','cmrby3y0000001znnofoo0a53','위치 권한 거부','html',unistr('<style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);align-items:center;justify-content:center;text-align:center}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:12px 14px;background:var(--wf-surface);cursor:pointer;font:inherit;width:100%}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-ph{background:var(--wf-fill);border-radius:50%}\u000a</style>\u000a<body data-screen="location-denied">\u000a  <div class="wf">\u000a    <header class="wf-topbar">위치 권한 필요</header>\u000a    <main class="wf-body">\u000a      <div class="wf-ph" style="width:72px;height:72px"></div>\u000a      <div style="font-size:17px;font-weight:700">위치 권한이 필요해요</div>\u000a      <div class="wf-sub">추노는 실시간 경주 거리 측정을 위해 <b style="color:var(--wf-ink)">위치 권한(백그라운드 포함)</b>이 필수입니다. 권한 없이는 경주에 참여할 수 없어요.</div>\u000a      <div class="wf-card" style="width:100%;text-align:left;background:var(--wf-fill);border:none">\u000a        <div class="wf-sub" id="state">현재 상태: <b style="color:var(--wf-ink)">거부됨</b></div>\u000a      </div>\u000a      <div style="width:100%;display:flex;flex-direction:column;gap:8px;margin-top:8px">\u000a        <button class="wf-btn wf-btn-primary" id="settings">설정에서 권한 허용</button>\u000a        <button class="wf-btn" id="recheck">권한 다시 확인</button>\u000a      </div>\u000a    </main>\u000a  </div>\u000a  <script>\u000a    document.getElementById(''settings'').addEventListener(''click'',function(){\u000a      document.getElementById(''state'').innerHTML=''현재 상태: <b style="color:var(--wf-ink)">설정 화면 이동 (목업)</b>'';\u000a    });\u000a    var tries=0;\u000a    document.getElementById(''recheck'').addEventListener(''click'',function(){\u000a      tries++;\u000a      document.getElementById(''state'').innerHTML = tries<2\u000a        ? ''현재 상태: <b style="color:var(--wf-ink)">여전히 거부됨</b> — 설정에서 허용 후 다시 시도''\u000a        : ''현재 상태: <b style="color:var(--wf-ink)">허용됨 ✓ (앱 진입 가능)</b>'';\u000a    });\u000a  </script>\u000a</body>\u000a'),9,1,'cmrmtwkk30001rwgnoiejp8hz',1783558499792);
INSERT INTO Wireframe VALUES('cmrcsorxg0005rwt45ghswtwa','cmrby3y0000001znnofoo0a53','자동 취소 안내','html',unistr('<style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap)}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-chip{font-size:12px;padding:4px 10px;border-radius:999px;background:var(--wf-fill)}\u000a.wf-between{display:flex;align-items:center;justify-content:space-between;gap:8px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:12px 14px;background:var(--wf-surface);cursor:pointer;font:inherit;width:100%}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:flex;align-items:center;justify-content:center;padding:24px}\u000a.wf-modal.hide{display:none}\u000a.wf-modal .wf-card{background:var(--wf-surface);width:100%;max-width:320px;display:flex;flex-direction:column;gap:12px;text-align:center}\u000a.wf-ph{background:var(--wf-fill);border-radius:50%;margin:0 auto}\u000a</style>\u000a<body data-screen="race-cancelled">\u000a  <div class="wf">\u000a    <header class="wf-topbar">← 대기실</header>\u000a    <main class="wf-body">\u000a      <div class="wf-card">\u000a        <div style="font-weight:700;font-size:16px">아침 5K 대결</div>\u000a        <div class="wf-between" style="margin-top:10px"><span class="wf-chip">🎯 5.0km</span><span class="wf-chip">⏱ 30분</span><span class="wf-chip" style="opacity:.5">취소됨</span></div>\u000a      </div>\u000a      <div class="wf-sub">이 방은 모집 마감 시점(시작 10분 전)에 참가자가 2명 미만이어서 자동 취소되었습니다.</div>\u000a    </main>\u000a\u000a    <div class="wf-modal" id="modal">\u000a      <div class="wf-card">\u000a        <div class="wf-ph" style="width:56px;height:56px"></div>\u000a        <div style="font-weight:700;font-size:16px">경주가 취소되었어요</div>\u000a        <div class="wf-sub">시작 10분 전까지 참가자가 2명 미만이라 자동 취소되었습니다. 다른 방에 참여하거나 새 방을 만들어보세요.</div>\u000a        <button class="wf-btn wf-btn-primary" id="ok">확인</button>\u000a      </div>\u000a    </div>\u000a  </div>\u000a  <script>\u000a    document.getElementById(''ok'').addEventListener(''click'',function(){\u000a      document.getElementById(''modal'').classList.add(''hide'');\u000a    });\u000a  </script>\u000a</body>\u000a'),10,1,'cmrmtwkk30001rwgnoiejp8hz',1783558512485);
INSERT INTO Wireframe VALUES('cmrcywn0l0001rwziam0443u7','cmrby3y0000001znnofoo0a53','홈 (방 목록)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a.startin{font-size:11px;padding:2px 8px;border-radius:999px;border:1px solid var(--wf-line);color:var(--wf-ink);font-weight:600;white-space:nowrap}\u000a.starttime{font-size:12px;color:var(--wf-ink);font-weight:600;display:flex;align-items:center;gap:4px}\u000a.rowtop{display:flex;justify-content:space-between;align-items:center;gap:8px}\u000a.meta{display:flex;justify-content:space-between;align-items:center;margin-top:6px;gap:8px}\u000a</style></head>\u000a<body data-screen="home">\u000a<div class="wf">\u000a <header class="wf-topbar">홈</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;align-items:center;justify-content:space-between">\u000a     <div class="wf-title">참여 가능한 방</div>\u000a     <button class="wf-btn" id="filter" style="padding:6px 10px;font-size:12px">모집 중만</button>\u000a   </div>\u000a   <div class="wf-list" id="rooms">\u000a     <div class="wf-card" data-status="recruiting" data-start="7800" style="cursor:pointer">\u000a       <div class="rowtop"><b>아침 3km 대결</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 2/6</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="recruiting" data-start="2700" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>주말 10km 롱런</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 10km · 90분 · 정원 1/8</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="recruiting" data-start="240" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>번개 2km 스프린트</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 2km · 20분 · 정원 3/5</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="closed" data-start="480" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>퇴근런 5km</b><span class="wf-badge">모집 마감</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 5km · 45분 · 정원 4/4</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card" data-status="live" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>새벽 3km</b><span class="wf-badge">경기 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 5/5</div>\u000a       <div class="meta"><span class="starttime">🏃 경기 중</span><span class="startin">12:04 경과</span></div>\u000a     </div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" id="create">+ 방 만들기</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a <nav class="wf-tabbar"><button class="active">홈</button><button>이력</button><button>내 정보</button></nav>\u000a</div>\u000a<script>\u000afunction two(n){return (n<10?''0'':'''')+n;}\u000a// 절대 시작 시각 (오전/오후 h:mm)\u000afunction absLabel(ts){\u000a  var d=new Date(ts), h=d.getHours(), m=d.getMinutes();\u000a  var ap=h<12?''오전'':''오후'', h12=h%12; if(h12===0) h12=12;\u000a  return ap+'' ''+h12+'':''+two(m);\u000a}\u000a// 시작까지 남은 시간: 1시간 초과면 ''시간 분'', 이내면 분\u000afunction relLabel(sec){\u000a  if(sec<=0) return ''곧 시작'';\u000a  if(sec>=3600){ var h=Math.floor(sec/3600), m=Math.floor((sec%3600)/60); return h+''시간 ''+(m>0?m+''분 '':'''')+''후''; }\u000a  return Math.ceil(sec/60)+''분 후'';\u000a}\u000avar cards=[].slice.call(document.querySelectorAll(''#rooms .wf-card[data-start]''));\u000acards.forEach(function(c){ c._target = Date.now() + parseInt(c.getAttribute(''data-start''),10)*1000; });\u000afunction paint(){\u000a  cards.forEach(function(c){\u000a    var sec = Math.round((c._target - Date.now())/1000);\u000a    c.querySelector(''.starttime'').innerHTML = ''🕘 <b>''+absLabel(c._target)+''</b> 시작'';\u000a    c.querySelector(''.startin'').textContent = relLabel(sec);\u000a  });\u000a}\u000apaint();\u000asetInterval(paint,1000);\u000a\u000avar onlyRec=false;\u000adocument.getElementById(''filter'').addEventListener(''click'',function(){\u000a  onlyRec=!onlyRec; this.classList.toggle(''wf-btn-primary'',onlyRec);\u000a  document.querySelectorAll(''#rooms .wf-card'').forEach(function(c){\u000a    c.style.display=(onlyRec && c.getAttribute(''data-status'')!==''recruiting'')?''none'':'''';\u000a  });\u000a});\u000adocument.querySelectorAll(''#rooms .wf-card'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#rooms .wf-card'').forEach(function(x){x.style.borderColor=''var(--wf-line)''});\u000a    c.style.borderColor=''var(--wf-ink)'';\u000a  });\u000a});\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')});\u000a    b.classList.add(''active'');\u000a  });\u000a});\u000adocument.getElementById(''create'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 만들기 화면으로 이동 (별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),2,4,'cmrmtwkk30001rwgnoiejp8hz',1783568957060);
INSERT INTO Wireframe VALUES('cmrczkmsp0003rwzigh8h13gc','cmrby3y0000001znnofoo0a53','홈 (방 목록)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a.startin{font-size:11px;padding:2px 8px;border-radius:999px;border:1px solid var(--wf-line);color:var(--wf-ink);font-weight:600;white-space:nowrap}\u000a.starttime{font-size:12px;color:var(--wf-ink);font-weight:600;display:flex;align-items:center;gap:4px}\u000a.rowtop{display:flex;justify-content:space-between;align-items:center;gap:8px}\u000a.meta{display:flex;justify-content:space-between;align-items:center;margin-top:6px;gap:8px}\u000a/* 필터 패널 */\u000a.frow{display:flex;justify-content:space-between;align-items:center}\u000a.chip-toggle{font-size:12px;padding:6px 12px;border-radius:999px;border:1px solid var(--wf-line);background:var(--wf-surface);cursor:pointer}\u000a.chip-toggle.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.range{position:relative;height:34px;margin-top:6px}\u000a.range .track{position:absolute;left:0;right:0;top:14px;height:6px;background:var(--wf-fill);border-radius:999px}\u000a.range .fill{position:absolute;top:0;height:100%;background:var(--wf-ink);border-radius:999px}\u000a.range input[type=range]{position:absolute;left:0;top:0;width:100%;height:34px;margin:0;background:none;pointer-events:none;-webkit-appearance:none;appearance:none}\u000a.range input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000a.range input[type=range]::-moz-range-thumb{pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a</style></head>\u000a<body data-screen="home">\u000a<div class="wf">\u000a <header class="wf-topbar">홈</header>\u000a <main class="wf-body">\u000a   <div class="frow">\u000a     <div class="wf-title">참여 가능한 방</div>\u000a     <button class="wf-btn" id="filterBtn" style="padding:6px 12px;font-size:12px">필터 ▾</button>\u000a   </div>\u000a\u000a   <!-- 필터 패널 -->\u000a   <div class="wf-card" id="filterPanel" style="display:none">\u000a     <div class="frow">\u000a       <b style="font-size:13px">모집 상태</b>\u000a       <button class="chip-toggle" id="onlyRec">모집 중만</button>\u000a     </div>\u000a     <div style="margin-top:14px">\u000a       <div class="frow"><b style="font-size:13px">거리</b><span class="wf-sub" id="distLabel">0 ~ 12 km</span></div>\u000a       <div class="range" data-key="dist" data-min="0" data-max="12" data-step="1" data-unit="km">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="12" step="1" value="0">\u000a         <input type="range" class="hi" min="0" max="12" step="1" value="12">\u000a       </div>\u000a     </div>\u000a     <div style="margin-top:10px">\u000a       <div class="frow"><b style="font-size:13px">제한 시간</b><span class="wf-sub" id="timeLabel">0 ~ 120 분</span></div>\u000a       <div class="range" data-key="time" data-min="0" data-max="120" data-step="5" data-unit="분">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="120" step="5" value="0">\u000a         <input type="range" class="hi" min="0" max="120" step="5" value="120">\u000a       </div>\u000a     </div>\u000a     <div class="frow" style="margin-top:14px">\u000a       <span class="wf-sub" id="count">5개 방</span>\u000a       <button class="wf-btn" id="reset" style="padding:6px 12px;font-size:12px">초기화</button>\u000a     </div>\u000a   </div>\u000a\u000a   <div class="wf-list" id="rooms">\u000a     <div class="wf-card room" data-status="recruiting" data-start="7800" data-dist="3" data-limit="30" style="cursor:pointer">\u000a       <div class="rowtop"><b>아침 3km 대결</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 2/6</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="2700" data-dist="10" data-limit="90" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>주말 10km 롱런</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 10km · 90분 · 정원 1/8</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="240" data-dist="2" data-limit="20" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>번개 2km 스프린트</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 2km · 20분 · 정원 3/5</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="closed" data-start="480" data-dist="5" data-limit="45" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>퇴근런 5km</b><span class="wf-badge">모집 마감</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 5km · 45분 · 정원 4/4</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="live" data-dist="3" data-limit="30" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>새벽 3km</b><span class="wf-badge">경기 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 5/5</div>\u000a       <div class="meta"><span class="starttime">🏃 경기 중</span><span class="startin">12:04 경과</span></div>\u000a     </div>\u000a   </div>\u000a   <div id="empty" class="wf-sub" style="display:none;text-align:center;padding:24px 0">조건에 맞는 방이 없어요</div>\u000a   <button class="wf-btn wf-btn-primary" id="create">+ 방 만들기</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a <nav class="wf-tabbar"><button class="active">홈</button><button>이력</button><button>내 정보</button></nav>\u000a</div>\u000a<script>\u000afunction two(n){return (n<10?''0'':'''')+n;}\u000afunction absLabel(ts){var d=new Date(ts),h=d.getHours(),m=d.getMinutes();var ap=h<12?''오전'':''오후'',h12=h%12;if(h12===0)h12=12;return ap+'' ''+h12+'':''+two(m);}\u000afunction relLabel(sec){if(sec<=0)return ''곧 시작'';if(sec>=3600){var h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60);return h+''시간 ''+(m>0?m+''분 '':'''')+''후'';}return Math.ceil(sec/60)+''분 후'';}\u000avar startCards=[].slice.call(document.querySelectorAll(''.room[data-start]''));\u000astartCards.forEach(function(c){c._target=Date.now()+parseInt(c.getAttribute(''data-start''),10)*1000;});\u000afunction paintStart(){startCards.forEach(function(c){var sec=Math.round((c._target-Date.now())/1000);c.querySelector(''.starttime'').innerHTML=''🕘 <b>''+absLabel(c._target)+''</b> 시작'';c.querySelector(''.startin'').textContent=relLabel(sec);});}\u000apaintStart();setInterval(paintStart,1000);\u000a\u000a// 이중 범위 슬라이더 (min/max)\u000avar state={onlyRec:false,dist:[0,12],time:[0,120]};\u000afunction initRange(box,key){\u000a  var lo=box.querySelector(''.lo''),hi=box.querySelector(''.hi''),fill=box.querySelector(''.fill'');\u000a  var mn=+box.dataset.min,mx=+box.dataset.max,unit=box.dataset.unit;\u000a  var label=document.getElementById(key+''Label'');\u000a  function upd(){\u000a    var a=+lo.value,b=+hi.value;\u000a    if(a>b){ if(this===lo){b=a;hi.value=a;} else {a=b;lo.value=b;} }\u000a    state[key]=[a,b];\u000a    var l=(a-mn)/(mx-mn)*100, r=(b-mn)/(mx-mn)*100;\u000a    fill.style.left=l+''%''; fill.style.width=(r-l)+''%'';\u000a    label.textContent=a+'' ~ ''+b+'' ''+unit;\u000a    applyFilter();\u000a  }\u000a  lo.addEventListener(''input'',upd);hi.addEventListener(''input'',upd);\u000a  box._reset=function(){lo.value=mn;hi.value=mx;upd();};\u000a  upd();\u000a}\u000avar boxes={dist:document.querySelector(''.range[data-key=dist]''),time:document.querySelector(''.range[data-key=time]'')};\u000ainitRange(boxes.dist,''dist'');initRange(boxes.time,''time'');\u000a\u000afunction applyFilter(){\u000a  var shown=0;\u000a  document.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a    var d=+c.getAttribute(''data-dist''), t=+c.getAttribute(''data-limit'');\u000a    var ok=(!state.onlyRec || c.getAttribute(''data-status'')===''recruiting'')\u000a      && d>=state.dist[0] && d<=state.dist[1]\u000a      && t>=state.time[0] && t<=state.time[1];\u000a    c.style.display=ok?'''':''none''; if(ok)shown++;\u000a  });\u000a  document.getElementById(''count'').textContent=shown+''개 방'';\u000a  document.getElementById(''empty'').style.display=shown?''none'':''block'';\u000a}\u000a\u000adocument.getElementById(''filterBtn'').addEventListener(''click'',function(){\u000a  var p=document.getElementById(''filterPanel'');\u000a  var open=p.style.display===''none'';\u000a  p.style.display=open?''block'':''none'';\u000a  this.textContent=open?''필터 ▴'':''필터 ▾'';\u000a  this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000adocument.getElementById(''onlyRec'').addEventListener(''click'',function(){\u000a  state.onlyRec=!state.onlyRec; this.classList.toggle(''on'',state.onlyRec); applyFilter();\u000a});\u000adocument.getElementById(''reset'').addEventListener(''click'',function(){\u000a  state.onlyRec=false; document.getElementById(''onlyRec'').classList.remove(''on'');\u000a  boxes.dist._reset(); boxes.time._reset();\u000a});\u000a\u000adocument.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#rooms .room'').forEach(function(x){x.style.borderColor=''var(--wf-line)''});\u000a    c.style.borderColor=''var(--wf-ink)'';\u000a  });\u000a});\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')});b.classList.add(''active'');});\u000a});\u000adocument.getElementById(''create'').addEventListener(''click'',function(){document.getElementById(''note'').textContent=''방 만들기 화면으로 이동 (별도 화면)'';});\u000a</script>\u000a</body></html>'),2,5,'cmrmtwkk30001rwgnoiejp8hz',1783570076521);
INSERT INTO Wireframe VALUES('cmrczoxw50005rwzij0svr1w1','cmrby3y0000001znnofoo0a53','홈 (방 목록)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a.startin{font-size:11px;padding:2px 8px;border-radius:999px;border:1px solid var(--wf-line);color:var(--wf-ink);font-weight:600;white-space:nowrap}\u000a.starttime{font-size:12px;color:var(--wf-ink);font-weight:600;display:flex;align-items:center;gap:4px}\u000a.rowtop{display:flex;justify-content:space-between;align-items:center;gap:8px}\u000a.meta{display:flex;justify-content:space-between;align-items:center;margin-top:6px;gap:8px}\u000a/* 필터 아이콘 버튼 */\u000a.icon-btn{display:flex;align-items:center;justify-content:center;width:38px;height:38px;padding:0;color:var(--wf-ink);position:relative}\u000a.icon-btn.wf-btn-primary{color:#fff}\u000a.icon-btn .dot{position:absolute;top:-3px;right:-3px;width:9px;height:9px;border-radius:50%;background:var(--wf-ink);border:2px solid var(--wf-surface);display:none}\u000a.icon-btn .dot.on{display:block}\u000a/* 필터 패널 */\u000a.frow{display:flex;justify-content:space-between;align-items:center}\u000a.chip-toggle{font-size:12px;padding:6px 12px;border-radius:999px;border:1px solid var(--wf-line);background:var(--wf-surface);cursor:pointer}\u000a.chip-toggle.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.range{position:relative;height:34px;margin-top:6px}\u000a.range .track{position:absolute;left:0;right:0;top:14px;height:6px;background:var(--wf-fill);border-radius:999px}\u000a.range .fill{position:absolute;top:0;height:100%;background:var(--wf-ink);border-radius:999px}\u000a.range input[type=range]{position:absolute;left:0;top:0;width:100%;height:34px;margin:0;background:none;pointer-events:none;-webkit-appearance:none;appearance:none}\u000a.range input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000a.range input[type=range]::-moz-range-thumb{pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a</style></head>\u000a<body data-screen="home">\u000a<div class="wf">\u000a <header class="wf-topbar">홈</header>\u000a <main class="wf-body">\u000a   <div class="frow">\u000a     <div class="wf-title">참여 가능한 방</div>\u000a     <button class="wf-btn icon-btn" id="filterBtn" aria-label="필터" title="필터">\u000a       <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">\u000a         <line x1="4" y1="7" x2="20" y2="7"/><circle cx="9" cy="7" r="2.6" fill="var(--wf-surface)"/>\u000a         <line x1="4" y1="12" x2="20" y2="12"/><circle cx="15" cy="12" r="2.6" fill="var(--wf-surface)"/>\u000a         <line x1="4" y1="17" x2="20" y2="17"/><circle cx="8" cy="17" r="2.6" fill="var(--wf-surface)"/>\u000a       </svg>\u000a       <span class="dot" id="filterDot"></span>\u000a     </button>\u000a   </div>\u000a\u000a   <!-- 필터 패널 -->\u000a   <div class="wf-card" id="filterPanel" style="display:none">\u000a     <div class="frow">\u000a       <b style="font-size:13px">모집 상태</b>\u000a       <button class="chip-toggle" id="onlyRec">모집 중만</button>\u000a     </div>\u000a     <div style="margin-top:14px">\u000a       <div class="frow"><b style="font-size:13px">거리</b><span class="wf-sub" id="distLabel">0 ~ 12 km</span></div>\u000a       <div class="range" data-key="dist" data-min="0" data-max="12" data-step="1" data-unit="km">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="12" step="1" value="0">\u000a         <input type="range" class="hi" min="0" max="12" step="1" value="12">\u000a       </div>\u000a     </div>\u000a     <div style="margin-top:10px">\u000a       <div class="frow"><b style="font-size:13px">제한 시간</b><span class="wf-sub" id="timeLabel">0 ~ 120 분</span></div>\u000a       <div class="range" data-key="time" data-min="0" data-max="120" data-step="5" data-unit="분">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="120" step="5" value="0">\u000a         <input type="range" class="hi" min="0" max="120" step="5" value="120">\u000a       </div>\u000a     </div>\u000a     <div class="frow" style="margin-top:14px">\u000a       <span class="wf-sub" id="count">5개 방</span>\u000a       <button class="wf-btn" id="reset" style="padding:6px 12px;font-size:12px">초기화</button>\u000a     </div>\u000a   </div>\u000a\u000a   <div class="wf-list" id="rooms">\u000a     <div class="wf-card room" data-status="recruiting" data-start="7800" data-dist="3" data-limit="30" style="cursor:pointer">\u000a       <div class="rowtop"><b>아침 3km 대결</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 2/6</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="2700" data-dist="10" data-limit="90" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>주말 10km 롱런</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 10km · 90분 · 정원 1/8</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="240" data-dist="2" data-limit="20" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>번개 2km 스프린트</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 2km · 20분 · 정원 3/5</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="closed" data-start="480" data-dist="5" data-limit="45" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>퇴근런 5km</b><span class="wf-badge">모집 마감</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 5km · 45분 · 정원 4/4</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="live" data-dist="3" data-limit="30" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>새벽 3km</b><span class="wf-badge">경기 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 5/5</div>\u000a       <div class="meta"><span class="starttime">🏃 경기 중</span><span class="startin">12:04 경과</span></div>\u000a     </div>\u000a   </div>\u000a   <div id="empty" class="wf-sub" style="display:none;text-align:center;padding:24px 0">조건에 맞는 방이 없어요</div>\u000a   <button class="wf-btn wf-btn-primary" id="create">+ 방 만들기</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a <nav class="wf-tabbar"><button class="active">홈</button><button>이력</button><button>내 정보</button></nav>\u000a</div>\u000a<script>\u000afunction two(n){return (n<10?''0'':'''')+n;}\u000afunction absLabel(ts){var d=new Date(ts),h=d.getHours(),m=d.getMinutes();var ap=h<12?''오전'':''오후'',h12=h%12;if(h12===0)h12=12;return ap+'' ''+h12+'':''+two(m);}\u000afunction relLabel(sec){if(sec<=0)return ''곧 시작'';if(sec>=3600){var h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60);return h+''시간 ''+(m>0?m+''분 '':'''')+''후'';}return Math.ceil(sec/60)+''분 후'';}\u000avar startCards=[].slice.call(document.querySelectorAll(''.room[data-start]''));\u000astartCards.forEach(function(c){c._target=Date.now()+parseInt(c.getAttribute(''data-start''),10)*1000;});\u000afunction paintStart(){startCards.forEach(function(c){var sec=Math.round((c._target-Date.now())/1000);c.querySelector(''.starttime'').innerHTML=''🕘 <b>''+absLabel(c._target)+''</b> 시작'';c.querySelector(''.startin'').textContent=relLabel(sec);});}\u000apaintStart();setInterval(paintStart,1000);\u000a\u000a// 이중 범위 슬라이더 (min/max)\u000avar state={onlyRec:false,dist:[0,12],time:[0,120]};\u000avar BOUND={dist:[0,12],time:[0,120]};\u000afunction initRange(box,key){\u000a  var lo=box.querySelector(''.lo''),hi=box.querySelector(''.hi''),fill=box.querySelector(''.fill'');\u000a  var mn=+box.dataset.min,mx=+box.dataset.max,unit=box.dataset.unit;\u000a  var label=document.getElementById(key+''Label'');\u000a  function upd(){\u000a    var a=+lo.value,b=+hi.value;\u000a    if(a>b){ if(this===lo){b=a;hi.value=a;} else {a=b;lo.value=b;} }\u000a    state[key]=[a,b];\u000a    var l=(a-mn)/(mx-mn)*100, r=(b-mn)/(mx-mn)*100;\u000a    fill.style.left=l+''%''; fill.style.width=(r-l)+''%'';\u000a    label.textContent=a+'' ~ ''+b+'' ''+unit;\u000a    applyFilter();\u000a  }\u000a  lo.addEventListener(''input'',upd);hi.addEventListener(''input'',upd);\u000a  box._reset=function(){lo.value=mn;hi.value=mx;upd();};\u000a  upd();\u000a}\u000avar boxes={dist:document.querySelector(''.range[data-key=dist]''),time:document.querySelector(''.range[data-key=time]'')};\u000ainitRange(boxes.dist,''dist'');initRange(boxes.time,''time'');\u000a\u000afunction isActive(){\u000a  return state.onlyRec\u000a    || state.dist[0]!==BOUND.dist[0] || state.dist[1]!==BOUND.dist[1]\u000a    || state.time[0]!==BOUND.time[0] || state.time[1]!==BOUND.time[1];\u000a}\u000afunction applyFilter(){\u000a  var shown=0;\u000a  document.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a    var d=+c.getAttribute(''data-dist''), t=+c.getAttribute(''data-limit'');\u000a    var ok=(!state.onlyRec || c.getAttribute(''data-status'')===''recruiting'')\u000a      && d>=state.dist[0] && d<=state.dist[1]\u000a      && t>=state.time[0] && t<=state.time[1];\u000a    c.style.display=ok?'''':''none''; if(ok)shown++;\u000a  });\u000a  document.getElementById(''count'').textContent=shown+''개 방'';\u000a  document.getElementById(''empty'').style.display=shown?''none'':''block'';\u000a  document.getElementById(''filterDot'').classList.toggle(''on'',isActive());\u000a}\u000a\u000adocument.getElementById(''filterBtn'').addEventListener(''click'',function(){\u000a  var p=document.getElementById(''filterPanel'');\u000a  var open=p.style.display===''none'';\u000a  p.style.display=open?''block'':''none'';\u000a  this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000adocument.getElementById(''onlyRec'').addEventListener(''click'',function(){\u000a  state.onlyRec=!state.onlyRec; this.classList.toggle(''on'',state.onlyRec); applyFilter();\u000a});\u000adocument.getElementById(''reset'').addEventListener(''click'',function(){\u000a  state.onlyRec=false; document.getElementById(''onlyRec'').classList.remove(''on'');\u000a  boxes.dist._reset(); boxes.time._reset();\u000a});\u000a\u000adocument.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#rooms .room'').forEach(function(x){x.style.borderColor=''var(--wf-line)''});\u000a    c.style.borderColor=''var(--wf-ink)'';\u000a  });\u000a});\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')});b.classList.add(''active'');});\u000a});\u000adocument.getElementById(''create'').addEventListener(''click'',function(){document.getElementById(''note'').textContent=''방 만들기 화면으로 이동 (별도 화면)'';});\u000a</script>\u000a</body></html>'),2,6,'cmrmtwkk30001rwgnoiejp8hz',1783570277525);
