idth:84px;height:84px;border-radius:50%;background:var(--wf-fill);position:relative}\u000a.ava-face{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:38px}\u000a.cam{position:absolute;right:-2px;bottom:-2px;width:28px;height:28px;border-radius:50%;background:var(--wf-ink);color:#fff;border:2px solid var(--wf-surface);display:flex;align-items:center;justify-content:center;font-size:13px;cursor:pointer}\u000a.namerow,.nameedit{display:flex;align-items:center;justify-content:center;gap:4px;height:34px}\u000a.pname{font-size:20px;font-weight:700}\u000a.nick-inline{border:none;border-bottom:1.5px solid var(--wf-ink);background:none;font:inherit;font-size:20px;font-weight:700;text-align:center;width:150px;padding:2px 0;outline:none}\u000a.editicon{border:none;background:none;cursor:pointer;color:var(--wf-muted);font-size:14px;padding:2px 4px}\u000a/* 통계 */\u000a.stat-grid{display:flex;gap:8px}\u000a.stat{flex:1;border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:12px 4px;text-align:center}\u000a.stat b{display:block;font-size:18px}\u000a.stat span{font-size:11px;color:var(--wf-muted)}\u000a.frow{display:flex;justify-content:space-between;align-items:center}\u000a.linkbtn{border:none;background:none;color:var(--wf-ink);font:inherit;font-size:12px;font-weight:600;cursor:pointer}\u000a.row{display:flex;align-items:center;justify-content:space-between;gap:10px;height:52px;border-bottom:1px solid var(--wf-line)}\u000a.row:last-child{border-bottom:none}\u000a.row .lead{display:flex;align-items:center;gap:10px;min-width:0}\u000a.row .rmeta{font-size:12px;color:var(--wf-muted)}\u000a.switch{width:42px;height:24px;border-radius:999px;background:var(--wf-fill);border:1px solid var(--wf-line);position:relative;cursor:pointer;flex:0 0 auto}\u000a.switch.on{background:var(--wf-ink);border-color:var(--wf-ink)}\u000a.switch i{position:absolute;top:2px;left:2px;width:18px;height:18px;border-radius:50%;background:#fff;transition:left .15s}\u000a.switch.on i{left:20px}\u000a/* 모달 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:center;justify-content:center;padding:24px}\u000a.modal.show{display:flex}\u000a.modal.bottom{align-items:flex-end;justify-content:center;padding:0}\u000a.dialog{background:var(--wf-surface);width:100%;max-width:310px;border-radius:var(--wf-radius);padding:18px 16px;display:flex;flex-direction:column;gap:12px}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:16px;display:flex;flex-direction:column;gap:6px}\u000a.sheet-handle{width:40px;height:4px;border-radius:999px;background:var(--wf-line);margin:2px auto 6px}\u000a.menu-item{display:flex;align-items:center;gap:10px;padding:12px 6px;border:none;background:none;text-align:left;font:inherit;font-size:15px;cursor:pointer;border-radius:8px;color:var(--wf-ink)}\u000a.menu-item:hover{background:var(--wf-fill)}\u000a</style></head>\u000a<body data-screen="profile">\u000a<div class="wf">\u000a <header class="wf-topbar"><span style="flex:1">프로필</span><button class="wf-btn" id="settingsMini" style="padding:4px 10px;font-size:12px">⚙</button></header>\u000a <main class="wf-body">\u000a   <!-- 헤더 -->\u000a   <div class="phead">\u000a     <div class="avatar-xl" id="avatarBox">\u000a       <span class="ava-face" id="avaFace" style="display:none">👤</span>\u000a       <div class="cam" id="cam">📷</div>\u000a     </div>\u000a     <div class="namerow" id="nameView">\u000a       <span class="pname" id="nick">러너</span>\u000a       <button class="editicon" id="editBtn" title="닉네임 수정">✎</button>\u000a     </div>\u000a     <div class="nameedit" id="nameEdit" style="display:none">\u000a       <input class="nick-inline" id="nickInput" value="러너">\u000a       <button class="editicon" id="saveBtn" title="저장" style="color:var(--wf-ink)">✓</button>\u000a     </div>\u000a     <div class="wf-sub">카카오 로그인 · 2026년 6월 가입</div>\u000a   </div>\u000a\u000a   <!-- 러닝 통계 -->\u000a   <div class="stat-grid">\u000a     <div class="stat"><b>12</b><span>경쟁</span></div>\u000a     <div class="stat"><b>5</b><span>우승</span></div>\u000a     <div class="stat"><b>48.2</b><span>총 km</span></div>\u000a     <div class="stat"><b>83%</b><span>완주율</span></div>\u000a   </div>\u000a\u000a   <!-- 최근 경주 -->\u000a   <div>\u000a     <div class="frow" style="margin-bottom:6px"><span class="wf-title" style="font-size:15px">최근 경주</span><button class="linkbtn" id="seeAll">전체 보기</button></div>\u000a     <div class="wf-card">\u000a       <div class="row"><div class="lead"><div class="wf-avatar"></div><div style="min-width:0"><b>아침 3km 대결</b><div class="rmeta">07-08 · 목표 3km</div></div></div><span class="wf-badge">1위</span></div>\u000a       <div class="row"><div class="lead"><div class="wf-avatar"></div><div style="min-width:0"><b>퇴근런 5km</b><div class="rmeta">07-05 · 목표 5km</div></div></div><span class="wf-badge">3위</span></div>\u000a       <div class="row"><div class="lead"><div class="wf-avatar"></div><div style="min-width:0"><b>주말 10km 롱런</b><div class="rmeta">07-01 · 목표 10km</div></div></div><span class="wf-badge">미완주</span></div>\u000a     </div>\u000a   </div>\u000a\u000a   <!-- 설정 -->\u000a   <div>\u000a     <div class="wf-title" style="font-size:15px;margin-bottom:6px">설정</div>\u000a     <div class="wf-card">\u000a       <div class="row"><span>경주 알림</span><div class="switch on" id="notifSwitch"><i></i></div></div>\u000a       <div class="row"><span>위치 권한</span><span class="wf-badge">허용됨</span></div>\u000a       <div class="row"><span>연결 계정</span><span class="wf-sub">카카오</span></div>\u000a       <div class="row" id="termsRow" style="cursor:pointer"><span>약관 · 개인정보 처리방침</span><span style="display:flex;align-items:center;gap:6px"><span class="wf-badge" id="termsBadge">재동의 필요</span><span class="wf-sub">›</span></span></div>\u000a     </div>\u000a   </div>\u000a\u000a   <button class="wf-btn" id="logout" style="width:100%;color:var(--wf-muted)">로그아웃</button>\u000a </main>\u000a\u000a <!-- 프로필 사진 시트 -->\u000a <div class="modal bottom" id="photoSheet">\u000a   <div class="sheet">\u000a     <div class="sheet-handle"></div>\u000a     <div class="wf-sub" style="padding:0 6px">프로필 사진</div>\u000a     <button class="menu-item" id="pAlbum">🖼&nbsp;&nbsp;앨범에서 선택</button>\u000a     <button class="menu-item" id="pCam">📷&nbsp;&nbsp;카메라로 촬영</button>\u000a     <button class="menu-item" id="pDefault" style="display:none">👤&nbsp;&nbsp;기본 이미지로</button>\u000a     <button class="wf-btn" id="pCancel" style="margin-top:4px">닫기</button>\u000a   </div>\u000a </div>\u000a\u000a <!-- 재동의/약관 모달 -->\u000a <div class="modal" id="termsModal">\u000a   <div class="dialog">\u000a     <b style="font-size:15px">위치기반서비스 이용약관 (v2)</b>\u000a     <div class="wf-card" style="max-height:150px;overflow:auto;padding:12px;background:var(--wf-fill);border:none;font-size:13px;color:var(--wf-muted)">개정 요지: 위치정보 보관 기간 및 제3자 제공 범위 조항이 변경되었습니다. (본문 목업)</div>\u000a     <label style="display:flex;align-items:center;gap:8px;font-size:13px"><input type="checkbox" id="agree"> 위 변경 약관에 동의합니다 (필수)</label>\u000a     <div style="display:flex;gap:8px"><button class="wf-btn" id="reCancel" style="flex:1">나중에</button><button class="wf-btn wf-btn-primary" id="reOk" style="flex:1">재동의</button></div>\u000a   </div>\u000a </div>\u000a\u000a <!-- 로그아웃 확인 -->\u000a <div class="modal" id="outModal">\u000a   <div class="dialog">\u000a     <b style="font-size:15px">로그아웃 할까요?</b>\u000a     <div style="display:flex;gap:8px"><button class="wf-btn" id="outCancel" style="flex:1">취소</button><button class="wf-btn wf-btn-primary" id="outOk" style="flex:1">로그아웃</button></div>\u000a   </div>\u000a </div>\u000a\u000a <div id="note" class="wf-sub" style="position:absolute;left:0;right:0;bottom:60px;text-align:center;pointer-events:none"></div>\u000a <nav class="wf-tabbar"><button>홈</button><button>이력</button><button class="active">내 정보</button></nav>\u000a</div>\u000a<script>\u000afunction note(m){var n=document.getElementById(''note'');n.textContent=m;setTimeout(function(){n.textContent='''';},1500);}\u000a\u000a// 닉네임 인라인 편집 (레이아웃 이동 없음)\u000adocument.getElementById(''editBtn'').addEventListener(''click'',function(){\u000a  document.getElementById(''nameView'').style.display=''none'';\u000a  document.getElementById(''nameEdit'').style.display=''flex'';\u000a  document.getElementById(''nickInput'').focus();\u000a});\u000adocument.getElementById(''saveBtn'').addEventListener(''click'',function(){\u000a  var v=document.getElementById(''nickInput'').value||''러너'';\u000a  document.getElementById(''nick'').textContent=v;\u000a  document.getElementById(''nameEdit'').style.display=''none'';\u000a  document.getElementById(''nameView'').style.display=''flex'';\u000a  note(''닉네임 저장됨'');\u000a});\u000a\u000a// 프로필 사진\u000avar photoSheet=document.getElementById(''photoSheet''), hasPhoto=false;\u000afunction openPhoto(){ document.getElementById(''pDefault'').style.display=hasPhoto?''flex'':''none''; photoSheet.classList.add(''show''); }\u000adocument.getElementById(''cam'').addEventListener(''click'',function(e){ e.stopPropagation(); openPhoto(); });\u000adocument.getElementById(''avatarBox'').addEventListener(''click'',openPhoto);\u000afunction setPhoto(has){ hasPhoto=has; document.getElementById(''avaFace'').style.display=has?''flex'':''none''; photoSheet.classList.remove(''show''); note(has?''사진이 변경되었습니다 (목업)'':''기본 이미지로 변경''); }\u000adocument.getElementById(''pAlbum'').addEventListener(''click'',function(){ setPhoto(true); });\u000adocument.getElementById(''pCam'').addEventListener(''click'',function(){ setPhoto(true); });\u000adocument.getElementById(''pDefault'').addEventListener(''click'',function(){ setPhoto(false); });\u000adocument.getElementById(''pCancel'').addEventListener(''click'',function(){ photoSheet.classList.remove(''show''); });\u000a\u000a// 알림 토글\u000adocument.getElementById(''notifSwitch'').addEventListener(''click'',function(){ this.classList.toggle(''on''); });\u000adocument.getElementById(''settingsMini'').addEventListener(''click'',function(){ note(''설정 (목업)''); });\u000a\u000a// 약관 · 재동의\u000avar termsModal=document.getElementById(''termsModal'');\u000adocument.getElementById(''termsRow'').addEventListener(''click'',function(){ termsModal.classList.add(''show''); });\u000adocument.getElementById(''reCancel'').addEventListener(''click'',function(){ termsModal.classList.remove(''show''); });\u000adocument.getElementById(''reOk'').addEventListener(''click'',function(){\u000a  if(!document.getElementById(''agree'').checked){ note(''필수 약관 동의가 필요합니다''); return; }\u000a  termsModal.classList.remove(''show'');\u000a  document.getElementById(''termsBadge'').style.display=''none'';\u000a  note(''재동의 완료'');\u000a});\u000a\u000a// 로그아웃\u000avar outModal=document.getElementById(''outModal'');\u000adocument.getElementById(''logout'').addEventListener(''click'',function(){ outModal.classList.add(''show''); });\u000adocument.getElementById(''outCancel'').addEventListener(''click'',function(){ outModal.classList.remove(''show''); });\u000adocument.getElementById(''outOk'').addEventListener(''click'',function(){ outModal.classList.remove(''show''); });\u000a\u000adocument.getElementById(''seeAll'').addEventListener(''click'',function(){ note(''경주 이력 (별도 화면)''); });\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){ b.addEventListener(''click'',function(){ document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')}); b.classList.add(''active''); }); });\u000a</script>\u000a</body></html>'),8,4,'cmrmtwkk30001rwgnoiejp8hz',1783580813400);
INSERT INTO Wireframe VALUES('cmrksdaki000z1zbp3vj4nmaf','cmrby3y0000001znnofoo0a53','대기실','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-btn-danger{color:#b91c1c;border-color:#e7b7b7}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.stats{display:flex;gap:8px}\u000a.stat{flex:1;border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:10px;text-align:center}\u000a.stat b{display:block;font-size:16px}\u000a.efield{display:flex;align-items:center;justify-content:space-between;gap:8px}\u000a.efield input{width:110px;text-align:right}\u000a/* 상단 우측 컨트롤 */\u000a.rolebtn{font-size:11px;padding:3px 10px;border:1px solid var(--wf-line);border-radius:999px;background:var(--wf-surface);cursor:pointer;color:var(--wf-muted)}\u000a.iconbtn{width:34px;height:34px;border:none;background:none;cursor:pointer;display:flex;align-items:center;justify-content:center;color:var(--wf-ink);border-radius:8px}\u000a.iconbtn:hover{background:var(--wf-fill)}\u000a/* 참가자 그리드 */\u000a.pgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(88px,1fr));gap:12px 8px}\u000a.ptile{padding:6px 4px;display:flex;flex-direction:column;align-items:center;justify-content:flex-start;gap:6px;text-align:center}\u000a.ptile .wf-avatar{width:48px;height:48px}\u000a.pname{font-size:13px;font-weight:600}\u000a.ptile .kick{padding:3px 10px;font-size:11px}\u000a.host-tag{font-size:10px;font-weight:700;padding:2px 8px;border-radius:999px;background:var(--wf-ink);color:#fff}\u000a.ptile.empty{color:var(--wf-muted)}\u000a.empty-av{width:48px;height:48px;border-radius:50%;border:1.5px dashed var(--wf-line)}\u000a/* 모달 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:center;justify-content:center;padding:24px}\u000a.modal.show{display:flex}\u000a.modal.bottom{align-items:flex-end;justify-content:center;padding:0}\u000a.dialog{background:var(--wf-surface);width:100%;max-width:300px;border-radius:var(--wf-radius);padding:18px 16px;display:flex;flex-direction:column;gap:12px}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:16px 16px 24px;display:flex;flex-direction:column;gap:12px}\u000a.sheet-handle{width:40px;height:4px;border-radius:999px;background:var(--wf-line);margin:2px auto 6px}\u000a.menu-item{display:flex;align-items:center;gap:10px;padding:14px 6px;border:none;background:none;width:100%;text-align:left;font:inherit;font-size:15px;cursor:pointer;border-radius:8px;color:var(--wf-ink)}\u000a.menu-item:hover{background:var(--wf-fill)}\u000a</style></head>\u000a<body data-screen="waiting-room">\u000a<div class="wf">\u000a <header class="wf-topbar">\u000a   <span>← 대기실</span>\u000a   <div style="margin-left:auto;display:flex;align-items:center;gap:8px">\u000a     <button class="rolebtn" id="roleToggle" title="미리보기 역할 전환">역할: 방장</button>\u000a     <button class="iconbtn" id="menuBtn" aria-label="방 메뉴" title="방 메뉴">\u000a       <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg>\u000a     </button>\u000a   </div>\u000a </header>\u000a <main class="wf-body">\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <div class="wf-title">아침 3km 대결</div><span class="wf-badge">모집 중</span>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">시작까지</div>\u000a     <div style="font-size:28px;font-weight:700" id="cd">09:58</div>\u000a   </div>\u000a   <div class="stats">\u000a     <div class="stat"><span class="wf-sub">목표 거리</span><b id="sGoal">3.0km</b></div>\u000a     <div class="stat"><span class="wf-sub">제한 시간</span><b id="sLimit">30분</b></div>\u000a     <div class="stat"><span class="wf-sub">완주 기준 페이스</span><b id="sPace">10''00"</b><span class="wf-sub">/km</span></div>\u000a   </div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-label">참가자</span><span class="wf-sub" id="count">3 / 6</span>\u000a   </div>\u000a   <div class="pgrid" id="pgrid">\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">나</span><span class="host-tag">방장</span></div>\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">러너_김</span><button type="button" class="wf-btn kick">강퇴</button></div>\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">러너_이</span><button type="button" class="wf-btn kick">강퇴</button></div>\u000a     <div class="ptile empty"><div class="empty-av"></div><span class="wf-sub">빈 자리</span></div>\u000a     <div class="ptile empty"><div class="empty-av"></div><span class="wf-sub">빈 자리</span></div>\u000a     <div class="ptile empty"><div class="empty-av"></div><span class="wf-sub">빈 자리</span></div>\u000a   </div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" disabled style="opacity:.6">시작 시간에 자동 시작</button>\u000a   <button class="wf-btn wf-btn-danger" id="leaveBtn" style="display:none">방 나가기</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a\u000a <!-- 강퇴 확인 -->\u000a <div class="modal" id="kickModal">\u000a   <div class="dialog">\u000a     <b style="font-size:15px">강퇴하시겠습니까?</b>\u000a     <div class="wf-sub" id="kickWho">해당 참가자를 방에서 제거합니다.</div>\u000a     <div style="display:flex;gap:8px">\u000a       <button class="wf-btn" id="kickCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="kickOk" style="flex:1">강퇴</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a\u000a <!-- 방 메뉴 (방장 전용) -->\u000a <div class="modal bottom" id="menuSheet">\u000a   <div class="sheet">\u000a     <div class="sheet-handle"></div>\u000a     <button class="menu-item" id="menuEdit">✎&nbsp;&nbsp;방 조건 변경</button>\u000a     <button class="menu-item" id="menuDelete">🗑&nbsp;&nbsp;방 삭제</button>\u000a     <button class="wf-btn" id="menuClose">닫기</button>\u000a   </div>\u000a </div>\u000a\u000a <!-- 조건 변경 시트 -->\u000a <div class="modal bottom" id="editModal">\u000a   <div class="sheet">\u000a     <div class="sheet-handle"></div>\u000a     <div style="display:flex;justify-content:space-between;align-items:center">\u000a       <b style="font-size:15px">방 조건 변경</b><span class="wf-sub">모집 중에만 가능</span>\u000a     </div>\u000a     <div class="efield"><span>목표 거리 (km)</span><input class="wf-input" id="eGoal" type="number" step="0.5" value="3"></div>\u000a     <div class="efield"><span>제한 시간 (분)</span><input class="wf-input" id="eLimit" type="number" value="30"></div>\u000a     <div class="efield"><span>최대 인원</span><input class="wf-input" id="eCap" type="number" value="6"></div>\u000a     <div class="wf-sub">→ 완주 기준 페이스 <b id="ePace">10''00"</b>/km</div>\u000a     <div style="display:flex;gap:8px">\u000a       <button class="wf-btn" id="editCancel" style="flex:1">닫기</button>\u000a       <button class="wf-btn wf-btn-primary" id="editApply" style="flex:1">적용</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a\u000a <!-- 방 삭제 확인 -->\u000a <div class="modal" id="deleteModal">\u000a   <div class="dialog">\u000a     <b style="font-size:15px">방을 삭제하시겠습니까?</b>\u000a     <div class="wf-sub">삭제하면 참가자에게 취소가 안내되고 방이 사라집니다.</div>\u000a     <div style="display:flex;gap:8px">\u000a       <button class="wf-btn" id="delCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="delOk" style="flex:1">삭제</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a\u000a <!-- 방 나가기 확인 (참가자 전용) -->\u000a <div class="modal" id="leaveModal">\u000a   <div class="dialog">\u000a     <b style="font-size:15px">방에서 나가시겠습니까?</b>\u000a     <div class="wf-sub">나가면 참가자 목록에서 제외됩니다. 다시 참가하려면 방 목록에서 재입장해야 합니다.</div>\u000a     <div style="display:flex;gap:8px">\u000a       <button class="wf-btn" id="leaveCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-danger" id="leaveOk" style="flex:1">나가기</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a</div>\u000a<script>\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000afunction pace(goalKm,limitMin){\u000a  if(!goalKm||goalKm<=0) return "--''--\\"";\u000a  var sec=Math.round(limitMin*60/goalKm);\u000a  return Math.floor(sec/60)+"''"+pad(sec%60)+''"'';\u000a}\u000afunction applyTop(goalKm,limitMin){\u000a  document.getElementById(''sGoal'').textContent=goalKm.toFixed(1)+''km'';\u000a  document.getElementById(''sLimit'').textContent=limitMin+''분'';\u000a  document.getElementById(''sPace'').textContent=pace(goalKm,limitMin);\u000a}\u000aapplyTop(3,30);\u000a\u000avar t=598,cd=document.getElementById(''cd'');\u000asetInterval(function(){ if(t>0){t--; cd.textContent=pad(Math.floor(t/60))+'':''+pad(t%60);} },1000);\u000a\u000afunction refresh(){ document.getElementById(''count'').textContent=document.querySelectorAll(''#pgrid .ptile.filled'').length+'' / ''+(document.getElementById(''eCap'').value||6); }\u000a\u000a// 역할(방장/참가자) 미리보기 — 참가자면 ⋮ 메뉴·강퇴 숨김, 방 나가기 노출\u000avar isHost=true;\u000afunction applyRole(){\u000a  document.getElementById(''roleToggle'').textContent=''역할: ''+(isHost?''방장'':''참가자'');\u000a  document.getElementById(''menuBtn'').style.display=isHost?''flex'':''none'';\u000a  document.getElementById(''leaveBtn'').style.display=isHost?''none'':''block'';\u000a  document.querySelectorAll(''.kick'').forEach(function(b){ b.style.display=isHost?'''':''none''; });\u000a}\u000adocument.getElementById(''roleToggle'').addEventListener(''click'',function(){ isHost=!isHost; applyRole(); });\u000aapplyRole();\u000a\u000a// 강퇴 → 확인\u000avar kickModal=document.getElementById(''kickModal''), kickTarget=null;\u000afunction bindKick(b){ b.addEventListener(''click'',function(){\u000a  kickTarget=b.closest(''.ptile'');\u000a  var name=kickTarget.querySelector(''.pname'');\u000a  document.getElementById(''kickWho'').textContent=(name?name.textContent:''해당 참가자'')+'' 님을 방에서 제거합니다.'';\u000a  kickModal.classList.add(''show'');\u000a}); }\u000adocument.querySelectorAll(''.kick'').forEach(bindKick);\u000adocument.getElementById(''kickCancel'').addEventListener(''click'',function(){ kickModal.classList.remove(''show''); kickTarget=null; });\u000adocument.getElementById(''kickOk'').addEventListener(''click'',function(){\u000a  if(kickTarget){ kickTarget.className=''ptile empty''; kickTarget.innerHTML=''<div class="empty-av"></div><span class="wf-sub">빈 자리</span>''; refresh(); }\u000a  kickModal.classList.remove(''show''); kickTarget=null;\u000a});\u000a\u000a// ⋮ 방 메뉴\u000avar menuSheet=document.getElementById(''menuSheet''), editModal=document.getElementById(''editModal''), deleteModal=document.getElementById(''deleteModal'');\u000adocument.getElementById(''menuBtn'').addEventListener(''click'',function(){ menuSheet.classList.add(''show''); });\u000adocument.getElementById(''menuClose'').addEventListener(''click'',function(){ menuSheet.classList.remove(''show''); });\u000adocument.getElementById(''menuEdit'').addEventListener(''click'',function(){ menuSheet.classList.remove(''show''); editModal.classList.add(''show''); });\u000adocument.getElementById(''menuDelete'').addEventListener(''click'',function(){ menuSheet.classList.remove(''show''); deleteModal.classList.add(''show''); });\u000a\u000a// 조건 변경 시트\u000adocument.getElementById(''editCancel'').addEventListener(''click'',function(){ editModal.classList.remove(''show''); });\u000adocument.getElementById(''editApply'').addEventListener(''click'',function(){ editModal.classList.remove(''show''); });\u000afunction recalc(){\u000a  var g=parseFloat(document.getElementById(''eGoal'').value),l=parseFloat(document.getElementById(''eLimit'').value);\u000a  document.getElementById(''ePace'').textContent=pace(g,l);\u000a  if(g>0&&l>0) applyTop(g,l);\u000a  refresh();\u000a}\u000a[''eGoal'',''eLimit'',''eCap''].forEach(function(id){ document.getElementById(id).addEventListener(''input'',recalc); });\u000a\u000a// 방 삭제 확인\u000adocument.getElementById(''delCancel'').addEventListener(''click'',function(){ deleteModal.classList.remove(''show''); });\u000adocument.getElementById(''delOk'').addEventListener(''click'',function(){ deleteModal.classList.remove(''show''); document.getElementById(''note'').textContent=''방이 삭제되었습니다 (별도 화면)''; });\u000a\u000a// 방 나가기 (참가자 전용)\u000avar leaveModal=document.getElementById(''leaveModal'');\u000adocument.getElementById(''leaveBtn'').addEventListener(''click'',function(){ leaveModal.classList.add(''show''); });\u000adocument.getElementById(''leaveCancel'').addEventListener(''click'',function(){ leaveModal.classList.remove(''show''); });\u000adocument.getElementById(''leaveOk'').addEventListener(''click'',function(){ leaveModal.classList.remove(''show''); document.getElementById(''note'').textContent=''방에서 나갔습니다 (방 목록으로 이동)''; });\u000a</script>\u000a</body></html>'),4,9,'cmrmtwkk30001rwgnoiejp8hz',1784041706178);
INSERT INTO Wireframe VALUES('cmrlsan3x000hrwz8kx8xnvk9','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:16px;overflow:auto}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.chips{display:flex;gap:8px;flex-wrap:wrap}\u000a.chip{border:1px solid var(--wf-line);border-radius:8px;padding:9px 12px;background:var(--wf-surface);cursor:pointer;font:inherit;font-size:13px;color:var(--wf-muted)}\u000a.chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.frow{display:flex;align-items:center;gap:10px}\u000a.picker{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit;cursor:pointer;display:flex;align-items:center;justify-content:space-between;color:var(--wf-muted);text-align:left}\u000a.picker.set{color:var(--wf-ink);font-weight:600}\u000a/* 슬라이더 */\u000ainput[type=range]{-webkit-appearance:none;appearance:none;height:6px;background:var(--wf-fill);border-radius:999px;outline:none}\u000ainput[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000ainput[type=range]::-moz-range-thumb{width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a/* 스텝퍼 */\u000a.step{width:44px;height:44px;border:1px solid var(--wf-line);border-radius:8px;background:var(--wf-surface);cursor:pointer;font-size:18px}\u000a/* 모달 + 캘린더 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:flex-end;justify-content:center}\u000a.modal.show{display:flex}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:18px 16px 24px;display:flex;flex-direction:column;gap:12px}\u000a.cal-head{display:flex;align-items:center;justify-content:space-between}\u000a.cal-head button{border:none;background:none;font-size:20px;cursor:pointer;padding:4px 12px;color:var(--wf-ink)}\u000a.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px}\u000a.cal-dow{text-align:center;font-size:11px;color:var(--wf-muted);padding:4px 0}\u000a.cal-day{border:none;background:none;padding:9px 0;border-radius:8px;cursor:pointer;font:inherit;color:var(--wf-ink)}\u000a.cal-day:hover{background:var(--wf-fill)}\u000a.cal-day.sel{background:var(--wf-ink);color:#fff}\u000a.time-row{display:flex;align-items:center;gap:8px}\u000a.time-row select{border:1px solid var(--wf-line);border-radius:8px;padding:8px 10px;background:var(--wf-surface);font:inherit}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <main class="wf-body">\u000a   <div class="wf-field">\u000a     <span class="wf-label">방 제목</span>\u000a     <input class="wf-input" placeholder="예: 아침 3km 대결">\u000a   </div>\u000a\u000a   <!-- 목표 거리 (프리셋 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">목표 거리</span>\u000a     <div class="chips" id="distChips">\u000a       <button type="button" class="chip" data-v="2">2km</button>\u000a       <button type="button" class="chip on" data-v="3">3km</button>\u000a       <button type="button" class="chip" data-v="5">5km</button>\u000a       <button type="button" class="chip" data-v="10">10km</button>\u000a       <button type="button" class="chip" id="distCustomChip">직접 입력</button>\u000a     </div>\u000a     <div id="distCustomWrap" style="display:none">\u000a       <div class="frow"><input class="wf-input" id="distCustom" type="number" min="0.1" max="100" step="0.1" placeholder="예: 7.5" style="flex:1"><span class="wf-label">km</span></div>\u000a     </div>\u000a     <span class="wf-sub" id="distSummary">목표 거리: 3km</span>\u000a   </div>\u000a\u000a   <!-- 제한 시간 (슬라이더 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">제한 시간 (분)</span>\u000a     <div class="frow">\u000a       <input type="range" id="limitRange" min="5" max="1440" step="5" value="30" style="flex:1">\u000a       <input class="wf-input" id="limitNum" type="number" min="5" max="1440" value="30" style="width:78px;text-align:center">\u000a     </div>\u000a     <span class="wf-sub">5 ~ 1,440분(24시간) · 슬라이더 또는 직접 입력</span>\u000a   </div>\u000a\u000a   <!-- 시작 시간 (캘린더 피커) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">시작 시간</span>\u000a     <button type="button" class="picker" id="startPicker">\u000a       <span id="startText">날짜·시간을 선택하세요</span>\u000a       <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><rect x="3" y="4" width="18" height="17" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="16" y1="2" x2="16" y2="6"/></svg>\u000a     </button>\u000a   </div>\u000a\u000a   <!-- 최대 인원 -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">최대 인원</span>\u000a     <div class="frow">\u000a       <button type="button" class="step" id="capMinus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:28px;text-align:center">6</b>\u000a       <button type="button" class="step" id="capPlus">+</button>\u000a       <span class="wf-sub">명</span>\u000a     </div>\u000a   </div>\u000a\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" id="submit">방 개설</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a\u000a <!-- 날짜·시간 선택 모달 -->\u000a <div class="modal" id="dtModal">\u000a   <div class="sheet">\u000a     <b style="font-size:15px">시작 시간 선택</b>\u000a     <div class="cal-head"><button type="button" id="prevM">‹</button><span id="calTitle" style="font-weight:600"></span><button type="button" id="nextM">›</button></div>\u000a     <div class="cal-grid" id="calGrid"></div>\u000a     <div class="time-row" style="margin-top:6px">\u000a       <span class="wf-label">시간</span>\u000a       <select id="hh"></select><b>:</b><select id="mm"></select>\u000a     </div>\u000a     <div class="frow" style="margin-top:6px">\u000a       <button class="wf-btn" id="dtCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="dtOk" style="flex:1">확인</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a</div>\u000a<script>\u000a// ---- 목표 거리 ----\u000avar distVal=3;\u000afunction setDistSummary(){document.getElementById(''distSummary'').textContent=''목표 거리: ''+distVal+''km'';}\u000adocument.querySelectorAll(''#distChips .chip[data-v]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    this.classList.add(''on''); document.getElementById(''distCustomWrap'').style.display=''none'';\u000a    distVal=+this.getAttribute(''data-v''); setDistSummary();\u000a  });\u000a});\u000adocument.getElementById(''distCustomChip'').addEventListener(''click'',function(){\u000a  document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a  this.classList.add(''on'');\u000a  document.getElementById(''distCustomWrap'').style.display=''block'';\u000a  document.getElementById(''distCustom'').focus();\u000a});\u000adocument.getElementById(''distCustom'').addEventListener(''input'',function(){\u000a  var v=parseFloat(this.value); if(!isNaN(v)&&v>0){distVal=v; setDistSummary();}\u000a});\u000a\u000a// ---- 제한 시간 (슬라이더 <-> 입력 동기화) ----\u000avar range=document.getElementById(''limitRange''), num=document.getElementById(''limitNum'');\u000arange.addEventListener(''input'',function(){num.value=this.value;});\u000anum.addEventListener(''input'',function(){var v=Math.max(5,Math.min(1440,+this.value||5)); range.value=v;});\u000a\u000a// ---- 최대 인원 ----\u000avar cap=6;\u000adocument.getElementById(''capMinus'').addEventListener(''click'',function(){if(cap>2){cap--;document.getElementById(''cap'').textContent=cap;}});\u000adocument.getElementById(''capPlus'').addEventListener(''click'',function(){if(cap<20){cap++;document.getElementById(''cap'').textContent=cap;}});\u000a\u000a// ---- 캘린더 피커 ----\u000avar modal=document.getElementById(''dtModal'');\u000avar viewDate=new Date(); viewDate.setDate(1);\u000avar selDate=null;\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000afunction renderCal(){\u000a  var y=viewDate.getFullYear(), m=viewDate.getMonth();\u000a  document.getElementById(''calTitle'').textContent=y+''년 ''+(m+1)+''월'';\u000a  var startDow=new Date(y,m,1).getDay(), days=new Date(y,m+1,0).getDate();\u000a  var grid=document.getElementById(''calGrid''); grid.innerHTML='''';\u000a  [''일'',''월'',''화'',''수'',''목'',''금'',''토''].forEach(function(d){var e=document.createElement(''div'');e.className=''cal-dow'';e.textContent=d;grid.appendChild(e);});\u000a  for(var i=0;i<startDow;i++){grid.appendChild(document.createElement(''div''));}\u000a  for(var d=1;d<=days;d++){\u000a    var cell=document.createElement(''button'');cell.type=''button'';cell.className=''cal-day'';cell.textContent=d;\u000a    if(selDate && selDate.getFullYear()===y && selDate.getMonth()===m && selDate.getDate()===d) cell.classList.add(''sel'');\u000a    (function(dd){cell.addEventListener(''click'',function(){\u000a      selDate=new Date(y,m,dd);\u000a      [].forEach.call(grid.querySelectorAll(''.cal-day''),function(x){x.classList.remove(''sel'')});\u000a      this.classList.add(''sel'');\u000a    });})(d);\u000a    grid.appendChild(cell);\u000a  }\u000a}\u000avar hh=document.getElementById(''hh''), mm=document.getElementById(''mm'');\u000afor(var h=0;h<24;h++){var o=document.createElement(''option'');o.value=h;o.textContent=pad(h);hh.appendChild(o);}\u000afor(var mi=0;mi<60;mi+=5){var o2=document.createElement(''option'');o2.value=mi;o2.textContent=pad(mi);mm.appendChild(o2);}\u000ahh.value=7; mm.value=0;\u000a\u000adocument.getElementById(''startPicker'').addEventListener(''click'',function(){renderCal();modal.classList.add(''show'');});\u000adocument.getElementById(''prevM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()-1);renderCal();});\u000adocument.getElementById(''nextM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()+1);renderCal();});\u000adocument.getElementById(''dtCancel'').addEventListener(''click'',function(){modal.classList.remove(''show'');});\u000adocument.getElementById(''dtOk'').addEventListener(''click'',function(){\u000a  if(!selDate){document.getElementById(''note'').textContent=''날짜를 선택하세요'';modal.classList.remove(''show'');return;}\u000a  var dows=[''일'',''월'',''화'',''수'',''목'',''금'',''토''];\u000a  var txt=selDate.getFullYear()+''-''+pad(selDate.getMonth()+1)+''-''+pad(selDate.getDate())+'' (''+dows[selDate.getDay()]+'') ''+pad(+hh.value)+'':''+pad(+mm.value);\u000a  var el=document.getElementById(''startText''); el.textContent=txt; el.parentElement.classList.add(''set'');\u000a  modal.classList.remove(''show'');\u000a});\u000a\u000adocument.getElementById(''submit'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 개설 (대기실로 이동 · 별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),3,4,'cmrmtwkk30001rwgnoiejp8hz',1784102048638);
INSERT INTO Wireframe VALUES('cmrmsc6vj001lrwz89row0vy6','cmrby3y0000001znnofoo0a53','관리자 로그인','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--bg:#f4f4f5;--surface:#fff;--line:#d4d4d8;--ink:#3f3f46;--muted:#a1a1aa;--fill:#e4e4e7;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--bg);color:var(--ink);font:13px/1.5 -apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh}\u000a.card{background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:28px;width:320px;display:flex;flex-direction:column;gap:10px}\u000a.brand{font-weight:700;font-size:18px;text-align:center;margin-bottom:6px}\u000a.sub{color:var(--muted);font-size:12px}\u000alabel{font-size:12px;font-weight:600;margin-top:6px}\u000a.inp{border:1px solid var(--line);border-radius:8px;padding:9px 11px;background:var(--surface);font:inherit}\u000a.btn{border:1px solid var(--ink);border-radius:8px;padding:10px;background:var(--ink);color:#fff;cursor:pointer;font:inherit;margin-top:8px}\u000a.err{color:#b91c1c;font-size:12px;min-height:14px}\u000a</style></head>\u000a<body data-screen="admin-login">\u000a  <form class="card" onsubmit="event.preventDefault();document.getElementById(''e'').textContent=this.email.value?'''':''이메일·비밀번호를 확인하세요'';">\u000a    <div class="brand">추노 백오피스</div>\u000a    <div class="sub" style="text-align:center">사내 관리자 전용</div>\u000a    <label>이메일</label>\u000a    <input class="inp" name="email" placeholder="admin@chuno.run">\u000a    <label>비밀번호</label>\u000a    <input class="inp" type="password" placeholder="••••••••">\u000a    <div class="err" id="e"></div>\u000a    <button class="btn" type="submit">로그인</button>\u000a    <div class="sub" style="text-align:center">자체 이메일 로그인 · 구글 로그인은 2차</div>\u000a  </form>\u000a</body></html>'),11,1,'cmrmtwkk80003rwgnkid249iz',1784162587087);
INSERT INTO Wireframe VALUES('cmrmsd6kh001prwz86c7yfvwc','cmrby3y0000001znnofoo0a53','대시보드','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--bg:#f4f4f5;--surface:#fff;--line:#d4d4d8;--ink:#3f3f46;--muted:#a1a1aa;--fill:#e4e4e7;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--bg);color:var(--ink);font:13px/1.5 -apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;min-height:100vh}\u000a.side{width:180px;background:var(--surface);border-right:1px solid var(--line);padding:14px 0;flex-shrink:0}\u000a.brand{font-weight:700;padding:0 16px 12px;border-bottom:1px solid var(--line);margin-bottom:8px}\u000a.nav{display:flex;flex-direction:column}\u000a.nav a{padding:9px 16px;color:var(--ink);text-decoration:none;border-left:3px solid transparent;cursor:pointer}\u000a.nav a.on{background:var(--fill);font-weight:600;border-left-color:var(--ink)}\u000a.main{flex:1;display:flex;flex-direction:column;min-width:0}\u000a.top{display:flex;align-items:center;justify-content:space-between;padding:13px 20px;border-bottom:1px solid var(--line);background:var(--surface)}\u000a.top h1{font-size:16px}.who{color:var(--muted);font-size:12px}\u000a.body{padding:20px;overflow:auto}\u000a.card{background:var(--surface);border:1px solid var(--line);border-radius:10px;padding:16px}\u000a.kpi{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px}\u000a.kpi .card b{font-size:22px;display:block}.kpi .card span{color:var(--muted);font-size:12px}\u000atable{width:100%;border-collapse:collapse}\u000ath,td{text-align:left;padding:9px 11px;border-bottom:1px solid var(--line)}\u000ath{color:var(--muted);font-weight:600;font-size:12px}tr:last-child td{border-bottom:none}\u000a.badge{display:inline-block;padding:2px 8px;border:1px solid var(--line);border-radius:999px;font-size:11px;color:var(--muted)}\u000ah2{font-size:14px;margin-bottom:10px}\u000a</style></head>\u000a<body data-screen="dashboard">\u000a  <aside class="side">\u000a    <div class="brand">추노 백오피스</div>\u000a    <nav class="nav">\u000a      <a class="on">대시보드</a><a>사용자</a><a>방</a><a>약관</a><a>경주 결과</a><a>관리자</a>\u000a    </nav>\u000a  </aside>\u000a  <div class="main">\u000a    <div class="top"><h1>대시보드</h1><span class="who">admin@chuno.run ▾</span></div>\u000a    <div class="body">\u000a      <div class="kpi">\u000a        <div class="card"><b>1,284</b><span>누적 가입자</span></div>\u000a        <div class="card"><b>37</b><span>활성 방 (모집·진행)</span></div>\u000a        <div class="card"><b>12</b><span>오늘 경주</span></div>\u000a        <div class="card"><b>92%</b><span>완주율 (7일)</span></div>\u000a      </div>\u000a      <div class="card" style="margin-bottom:16px">\u000a        <h2>최근 경주</h2>\u000a        <table>\u000a          <tr><th>방</th><th>상태</th><th>참가</th><th>시작</th></tr>\u000a          <tr><td>아침 3km 대결</td><td><span class="badge">live</span></td><td>4</td><td>07-16 07:00</td></tr>\u000a          <tr><td>퇴근런 5km</td><td><span class="badge">finished</span></td><td>6</td><td>07-15 19:00</td></tr>\u000a          <tr><td>주말 10km</td><td><span class="badge">recruiting</span></td><td>2</td><td>07-17 08:00</td></tr>\u000a        </table>\u000a      </div>\u000a      <div class="card">\u000a        <h2>상태별 방</h2>\u000a        <div style="display:flex;gap:20px;color:var(--muted)">recruiting 20 · ready 5 · live 12 · finished 143 · cancelled 8</div>\u000a      </div>\u000a    </div>\u000a  </div>\u000a</body></html>'),12,1,'cmrmtwkk80003rwgnkid249iz',1784162633346);
