;gap:10px">\u000a      <b>새 약관 버전 등록</b>\u000a      <select class="btn"><option>유형: service</option><option>privacy</option><option>location</option><option>marketing</option></select>\u000a      <input class="btn" placeholder="버전 (예: 1.2)"><input class="btn" placeholder="시행 예정일 (YYYY-MM-DD)">\u000a      <textarea class="btn" rows="4" placeholder="약관 본문"></textarea>\u000a      <div style="display:flex;gap:8px;justify-content:flex-end"><button class="btn" onclick="document.getElementById(''m'').style.display=''none''">취소</button><button class="btn btn-p" onclick="document.getElementById(''m'').style.display=''none''">등록(pending)</button></div>\u000a    </div>\u000a  </div>\u000a</body></html>'),17,2,'cmrmtwkk80003rwgnkid249iz',1784189106088);
